const Map<String, (String nameVi, String descVi)> kLandmarkVi = {
  'chengdu/panda': ('Trung tâm Nghiên cứu Gấu trúc Thành Đô', 'Trung tâm Nghiên cứu Nhân giống Gấu trúc Thành Đô là cơ sở bảo tồn và nhân giống gấu trúc lớn nhất thế giới. Mỗi năm, hàng triệu du khách đến đây để ngắm biểu tượng đáng yêu của thành phố lăn lộn giữa những rừng tre xanh mướt.'),
  'chengdu/hotpot': ('Lẩu Tứ Xuyên', 'Sôi sục với hạt tiêu Tứ Xuyên gây tê đầu lưỡi và lớp dầu ớt đỏ rực, lẩu là trái tim của văn hóa ẩm thực Thành Đô. Mỗi người tự nhúng miếng ăn của mình vào nồi lẩu chung giữa bàn — ăn uống ở đây giống như một trò chơi tập thể đầy niềm vui.'),
  'chengdu/bianlian': ('Biến diện', 'Trong Biến Kiểm — nghệ thuật kỳ ảo của kinh kịch Tứ Xuyên — các nghệ nhân thay đổi những chiếc mặt nạ rực rỡ chỉ trong chớp mắt bằng một cái phẩy tay. Bí quyết của nghệ thuật này chỉ được truyền từ thầy sang trò, đời này qua đời khác.'),
  'chengdu/jinli': ('Phố cổ Cẩm Lý', 'Rực sáng dưới ánh đèn lồng đỏ, Cẩm Lý là con phố chợ có lịch sử từ thời Tam Quốc. Với những quán trà, nghệ thuật rối bóng và các nghệ nhân vẽ tranh bằng đường, đây là nơi bạn cảm nhận rõ nhất nhịp sống chậm rãi nổi tiếng của Thành Đô.'),
  'nanjing/citywall': ('Tường thành Nam Kinh', 'Được vị hoàng đế sáng lập nhà Minh cho xây để bảo vệ kinh đô, bức tường thành khổng lồ này là tường thành cổ dài nhất còn tồn tại trên thế giới. Mỗi viên gạch đều khắc tên người thợ làm ra nó như một cam kết chất lượng; ngày nay, đi dạo trên mặt thành, bạn có thể ngắm cả Nam Kinh xưa và nay cùng một lúc.'),
  'nanjing/plum': ('Hoa mai', 'Nở rộ giữa tuyết trắng trong tiết đông giá lạnh, hoa mai (mơ) tượng trưng cho nghị lực và hy vọng trong văn hóa Trung Hoa — và Nam Kinh đã chọn nó làm loài hoa của thành phố. Cuối đông, sườn đồi Mai Hoa biến thành biển hoa hồng-trắng, và người dân nô nức dạo chơi dưới những tán cây.'),
  'nanjing/duck': ('Vịt muối Nam Kinh', 'Vịt muối — món đặc sản trứ danh của Nam Kinh — được ướp trong nước muối gia vị, ninh nhẹ rồi dùng nguội. Với thịt mềm, vị thanh và độ mặn hài hòa, vịt là niềm đam mê của cả thành phố; người dân địa phương còn đùa rằng chẳng con vịt nào rời Nam Kinh mà còn sống.'),
  'nanjing/bridge': ('Cầu Nam Kinh Trường Giang', 'Hoàn thành năm 1968 hoàn toàn bởi các kỹ sư Trung Quốc, cầu Trường Giang Nam Kinh là công trình hai tầng đồ sộ vừa cho đường bộ vừa cho đường sắt vượt sông. Được xây dựng không cần trợ giúp nước ngoài, cây cầu trở thành biểu tượng tự lực tự cường của Trung Quốc hiện đại và đến nay vẫn được nhắc đến đầy tự hào trong sách giáo khoa.'),
  'qingdao/beer': ('Bia Thanh Đảo', 'Ra đời từ nhà máy bia được thành lập trong thời kỳ Đức quản lý thành phố, Tsingtao (Thanh Đảo) trở thành loại bia Trung Quốc nổi tiếng nhất thế giới. Mỗi mùa hè, lễ hội bia quốc tế lại làm cả thành phố tưng bừng; và bia tươi bán trong túi ni lông, uống bằng ống hút ở các quầy hàng vỉa hè vẫn là nét truyền thống đáng yêu nhất của Thanh Đảo.'),
  'qingdao/sailing': ('Thành phố Thuyền buồm', 'Các cuộc đua thuyền buồm của Thế vận hội 2008 được tổ chức tại bến du thuyền Thanh Đảo, và từ đó thành phố mang danh hiệu \'Thành phố Thuyền buồm\'. Với vịnh biển lộng gió, những cánh buồm trắng điểm khắp chân trời và các con đường dạo biển dài, đây chính là thủ phủ thể thao dưới nước của Trung Quốc.'),
  'qingdao/beach': ('Bãi biển Thanh Đảo', 'Những bãi biển của Thanh Đảo trải dài dưới các sườn đồi với kiến trúc mái đỏ thời Đức, mang lại cho thành phố không khí của một thị trấn ven biển châu Âu hiếm thấy ở Trung Quốc. Mùa hè, bãi cát chật kín người bơi lội, và con đường ven biển nối các vịnh với nhau là điểm ngắm hoàng hôn kinh điển.'),
  'qingdao/crab': ('Hải sản Thanh Đảo', 'Hướng ra Hoàng Hải, Thanh Đảo thưởng thức hải sản tươi mỗi ngày: các quầy nghêu, hàu, nhím biển và cua chen chúc trên bến cảng. Cách ăn của người địa phương là hấp đơn giản mẻ hải sản trong ngày rồi nhâm nhi cùng một cốc bia Tsingtao mát lạnh.'),
  'changsha/pepper': ('Ớt Hồ Nam', 'Khác với vị cay tê của Tứ Xuyên, ẩm thực Hồ Nam nổi tiếng với vị cay khô và sắc — ớt tươi và ớt muối chua xuất hiện trong hầu như mọi món ăn. Ở Trường Sa, vị cay là câu trả lời lâu đời cho khí hậu ẩm ướt; người dân địa phương hay đùa rằng họ không sợ cay, chỉ sợ không có cay.'),
  'changsha/tofu': ('Đậu phụ thối', 'Được ngâm trong nước muối lên men rồi chiên giòn, đậu phụ thối Trường Sa có lớp vỏ đen bóng giòn tan bên ngoài, còn bên trong trắng như tuyết và mềm mượt. Đừng để mùi hăng đánh lừa bạn — khi rưới thêm tương ớt, món ăn nhỏ bé này thu hút những hàng người xếp dài nhất ở các chợ đêm.'),
  'changsha/fireworks': ('Pháo hoa', 'Lưu Dương, vùng đất láng giềng của Trường Sa, hàng thế kỷ nay được xem là kinh đô pháo hoa của thế giới — trên quê hương của thuốc súng, nghề này được truyền từ đời này sang đời khác. Trong những màn trình diễn thường kỳ bên bờ sông Tương, bầu trời và mặt nước cùng lúc bừng lên muôn sắc màu.'),
  'changsha/orange': ('Đảo Cam', 'Đảo Quýt (Quất Tử Châu), dải đất dài nằm giữa sông Tương, mang tên từ những vườn quýt phủ kín hai bờ. Thời trẻ, Mao Trạch Đông từng bơi trên dòng sông này và viết một bài thơ nổi tiếng về hòn đảo; ngày nay, bức tượng bán thân bằng đá hoa cương khổng lồ của Mao thời trẻ hướng nhìn ra sông từ mũi đảo.'),
  'zhengzhou/kungfu': ('Thiếu Lâm Kung Fu', 'Dưới chân núi Tung Sơn gần Trịnh Châu là Thiếu Lâm Tự, nơi khai sinh Thiền tông và võ thuật Thiếu Lâm. Quanh ngôi chùa cổ khoảng 1.500 năm tuổi, hàng nghìn học viên tại các trường võ vẫn gìn giữ di sản này với những buổi luyện tập bắt đầu từ lúc rạng đông.'),
  'zhengzhou/train': ('Trung tâm đường sắt', 'Trịnh Châu vươn lên thành đô thị lớn tại giao điểm của các tuyến đường sắt Bắc-Nam và Đông-Tây chính của Trung Quốc. Được mệnh danh là \'thành phố do những đoàn tàu dựng nên\', đến nay đây vẫn là một trong những đầu mối trung chuyển nhộn nhịp nhất của mạng lưới đường sắt cao tốc cả nước.'),
  'zhengzhou/wheat': ('Cánh đồng lúa mì', 'Đồng bằng Hà Nam, được sông Hoàng Hà tưới tắm, là một trong những vựa lúa mì lớn nhất Trung Quốc. Đất đai màu mỡ nơi đây nuôi dưỡng linh hồn của ẩm thực phương Bắc — mì kéo tay, bánh bao hấp và bánh nướng đều bắt đầu từ hạt lúa mì của cánh đồng này.'),
  'zhengzhou/ding': ('Đỉnh đồng', 'Trịnh Châu và vùng phụ cận từng là kinh đô của nhà Thương, một trong những triều đại sớm nhất của Trung Quốc; các cuộc khai quật tại đây đã đưa ra ánh sáng những chiếc vạc đồng nghi lễ gọi là đỉnh. Những chiếc vạc này tượng trưng cho quyền lực và lễ vật dâng tổ tiên — vì thế thành phố được xem là một trong những cái nôi của văn minh Trung Hoa.'),
  'wuxi/lake': ('Hồ Thái Hồ', 'Vô Tích nằm bên bờ Thái Hồ, một trong những hồ nước ngọt lớn nhất Trung Quốc; cá, tôm và rau thủy sinh của hồ là nền tảng của ẩm thực địa phương. Ngắm từ mũi Nguyên Đầu Chử lúc hoàng hôn, mặt hồ trở nên đẹp huyền ảo, nhất là vào mùa hoa anh đào.'),
  'wuxi/peach': ('Đào Dương Sơn', 'Thị trấn Dương Sơn của Vô Tích nổi tiếng khắp Trung Quốc với những quả đào ngọt như mật và mọng nước đến mức có thể ăn bằng thìa. Đào chín vào giữa hè, khi mùa thu hoạch mang không khí lễ hội đến thị trấn và các vườn đào mở cửa đón du khách.'),
  'wuxi/figurine': ('Tượng đất sét Huệ Sơn', 'Tượng đất Huệ Sơn là nghề thủ công dân gian hàng trăm năm tuổi, được nặn từ loại đất sét đen mềm dưới chân núi Huệ Sơn của Vô Tích. Được yêu thích nhất là tượng A Phúc, em bé má phúng phính tượng trưng cho sung túc và niềm vui; với màu sắc tươi sáng vẽ tay, những bức tượng này là món quà lưu niệm kinh điển của thành phố.'),
  'wuxi/boat': ('Thuyền trên kênh đào', 'Đại Vận Hà, tuyến đường thủy nhân tạo dài nhất thế giới, chảy xuyên qua trái tim Vô Tích. Lên thuyền ở khu phố cầu Thanh Minh lung linh ánh đèn lồng buổi tối, lướt qua những ngôi nhà cổ tường trắng ngói đen — đó là cách đẹp nhất để làm quen với thành phố này.'),
  'nanning/tree': ('Thành phố Xanh', 'Nằm trong vành đai nhiệt đới của miền Nam Trung Quốc, Nam Ninh được gọi là \'Thành phố Xanh\' nhờ những con phố rợp bóng cây cổ thụ và các công viên xanh tươi quanh năm. Gần biên giới Việt Nam, thành phố là cửa ngõ giao thương và giao lưu văn hóa giữa Trung Quốc và Đông Nam Á.'),
  'nanning/noodle': ('Mì Lão Hữu', 'Lão hữu phấn — \'mì bạn cũ\' — là món kinh điển chua cay của Nam Ninh, nấu với măng chua, đậu xị và ớt. Tương truyền, một chủ quán trà đã nấu bát mì này để chữa bệnh cho người bạn già của mình — và từ đó nó trở thành phương thuốc cho những ngày trời ẩm ướt.'),
  'nanning/song': ('Dân ca', 'Người Tráng ở Quảng Tây đã gửi gắm tâm tình qua những làn điệu dân ca đối đáp ứng khẩu suốt hàng thế kỷ. Mỗi độ xuân về, hội hát \'tháng Ba\' lại rộn ràng khắp Nam Ninh với những màn đối ca sôi nổi của các chàng trai cô gái; nàng ca sĩ huyền thoại Lưu Tam Tỷ vẫn là nhân vật được yêu mến nhất của truyền thống này.'),
  'nanning/mango': ('Trái cây nhiệt đới', 'Khí hậu nhiệt đới biến Nam Ninh thành miền đất trù phú của xoài, nhãn, vải và đu đủ — các quầy hàng ven đường ngập tràn trái cây tươi quanh năm. Vào những buổi tối oi ả, các món chè trái cây đá và nước ép tươi là cách giải nhiệt được yêu thích nhất của cả thành phố.'),
  'nanchang/pavilion': ('Đằng Vương Các', 'Đằng Vương Các bên sông Cám, bị phá hủy và xây lại nhiều lần kể từ thời nhà Đường, là một trong ba tòa lầu các nổi tiếng nhất miền Nam Trung Quốc. Bài tựa mà nhà thơ trẻ Vương Bột viết tại đây đã trở thành kiệt tác của văn học Trung Hoa và khiến tòa lầu trở nên bất tử.'),
  'nanchang/star': ('Ngày 1 tháng 8', 'Cuộc khởi nghĩa Nam Xương ngày 1 tháng 8 năm 1927 được xem là ngày ra đời của Quân Giải phóng Nhân dân Trung Quốc, mang lại cho Nam Xương danh hiệu \'Thành phố Anh hùng\'. Hai chữ \'Bát Nhất\' (8-1) trên quân kỳ chỉ về ngày lịch sử ấy — và cũng là tên của quảng trường trung tâm thành phố.'),
  'nanchang/porcelain': ('Thủ phủ gốm sứ', 'Giang Tây, tỉnh nhà của Nam Xương, là quê hương của Cảnh Đức Trấn — kinh đô gốm sứ của thế giới. Suốt một nghìn năm, các lò ngự nơi đây nung \'vàng trắng\' cho cung đình, rồi những đoàn thương buôn và tàu thuyền đưa nó đi khắp thế giới — nghề gốm ấy ngày nay vẫn sống động trong bàn tay của các nghệ nhân trẻ.'),
  'nanchang/sunset': ('Cảnh sông Cám', 'Khi màn đêm buông xuống, hai bờ sông Cám khoác lên diện mạo hoàn toàn khác: mặt tiền của hàng trăm tòa nhà hòa thành một màn trình diễn ánh sáng khổng lồ và đồng bộ. Các công viên ven sông cùng bóng dáng rực sáng của Đằng Vương Các là cung đường dạo bộ buổi tối được yêu thích nhất ở Nam Xương.'),
  'yinchuan/camel': ('Con đường Tơ lụa', 'Là ốc đảo được sông Hoàng Hà nuôi dưỡng, Ngân Xuyên từng là một trong những cửa ngõ phía Tây nơi các đoàn lữ hành trên Con đường Tơ lụa dừng chân trước khi băng qua sa mạc. Ngoài rìa thành phố, những lăng mộ hoàng gia hình kim tự tháp của vương triều Tây Hạ vẫn lặng lẽ vươn lên dưới nắng sa mạc.'),
  'yinchuan/grapes': ('Vườn nho Hạ Lan', 'Chân núi phía đông dãy Hạ Lan, với nắng dồi dào, không khí khô ráo và đất sỏi đá, được xem là vùng rượu vang tốt nhất Trung Quốc. Rượu vang từ những vườn nho nơi đây liên tục giành giải thưởng quốc tế, và giới sành rượu đã quen gọi vùng này là \'Bordeaux của Trung Quốc\'.'),
  'yinchuan/desert': ('Sa mạc Sa Pha Đầu', 'Tại Sa Pha Đầu (Shapotou) gần Ngân Xuyên, những đụn cát vàng của sa mạc Tengger gặp sông Hoàng Hà — một trong những nơi hiếm hoi mà sa mạc và dòng sông đứng cạnh nhau. Trượt cát từ đỉnh đụn, cưỡi lạc đà vào sa mạc và vượt sông trên bè da cừu là những cuộc phiêu lưu kinh điển của vùng đất này.'),
  'yinchuan/sheep': ('Thịt cừu Hồi tộc', 'Thịt cừu là ngôi sao của ẩm thực người Hồi theo đạo Hồi ở Ninh Hạ: xiên nướng rắc thìa là, cừu luộc mềm và các món canh mì kéo tay phủ kín bàn ăn thành phố. Được chăn thả trên đồng cỏ thảo nguyên, cừu địa phương nổi tiếng khắp Trung Quốc nhờ thịt mềm và hương vị thanh khiết.'),
  'lhasa/mountain': ('Cung điện Potala', 'Sừng sững trên đỉnh Hồng Sơn, cung điện Potala là kiệt tác của kiến trúc Tây Tạng với hàng trăm căn phòng, những lăng mộ thiêng và các điện thờ. Từng là cung điện mùa đông của các đời Đạt Lai Lạt Ma, tòa kiến trúc đỏ-trắng này là Di sản Thế giới UNESCO và có thể nhìn thấy từ hầu như mọi nơi ở Lhasa.'),
  'lhasa/prayer': ('Chùa Đại Chiêu', 'Những người hành hương tìm đến chùa Jokhang (Đại Chiêu), ngôi đền thiêng liêng nhất của Phật giáo Tây Tạng, đôi khi bằng cách quỳ lạy suốt cả chặng đường dài. Trên tuyến đường Barkhor bao quanh ngôi chùa, dòng người vừa đi vừa quay bánh xe cầu nguyện không bao giờ ngơi nghỉ, và hương trầm phảng phất khắp các con phố.'),
  'lhasa/yak': ('Văn hóa bò Yak', 'Sinh ra để chịu đựng cái lạnh của cao nguyên, bò yak là trụ cột của đời sống Tây Tạng: sữa cho bơ và phô mai, lông dệt thành lều và áo, phân khô làm chất đốt. Ngay cả những ngọn đèn cháy suốt ngày đêm trong các ngôi chùa cũng được thắp bằng bơ làm từ sữa yak.'),
  'lhasa/tea': ('Trà bơ', 'Trà bơ, được đánh từ bơ yak, muối và nước trà đen đậm, là thức uống hằng ngày của người Tây Tạng. Trong cái lạnh khô của vùng cao, nó vừa sưởi ấm vừa bổ dưỡng — và việc liên tục rót đầy chén cho khách là quy tắc ngọt ngào nhất của lòng hiếu khách Tây Tạng.'),
  'zhuhai/shell': ('Tượng Nàng tiên cá', 'Đứng trên tảng đá giữa biển và nâng viên ngọc trai lên trời cao, bức tượng Cô gái Ngư dân là biểu tượng của Chu Hải. Tượng bắt nguồn từ truyền thuyết địa phương về nàng tiên hóa thân thành người vì tình yêu với một chàng ngư dân; với dáng đứng thanh thoát, nàng chào đón mọi người dạo bước trên con đường ven biển.'),
  'zhuhai/bridge': ('Cầu Hồng Kông - Chu Hải - Ma Cao', 'Cầu Hồng Kông - Chu Hải - Ma Cao là tuyến vượt biển dài nhất thế giới với 55 km, gồm chuỗi cầu, đảo nhân tạo và một đường hầm dưới biển. Nối liền ba thành phố của châu thổ Châu Giang trên một trục duy nhất, công trình khổng lồ này là một trong những kỳ tích tiêu biểu của kỹ thuật hiện đại.'),
  'zhuhai/island': ('Trăm đảo', 'Tên gọi Chu Hải có nghĩa là \'biển ngọc trai\', và hơn một trăm hòn đảo rải rác dọc bờ biển của thành phố. Những hòn đảo như Đông Áo và Ngoại Linh Đinh, đến được bằng phà, chào đón du khách với làng chài, vịnh biển yên tĩnh và các nhà hàng hải sản — mỗi đảo sống theo nhịp điệu riêng của mình.'),
  'zhuhai/lobster': ('Tiệc hải sản', 'Nơi Châu Giang gặp biển, Chu Hải dọn bàn ăn bằng mẻ hải sản trong ngày: tôm hùm, tôm tít, sò điệp và hàu được chọn sống từ bể và chế biến ngay tại chỗ. Cách hấp nhẹ nhàng kiểu Quảng Đông làm nổi bật độ tươi và vị ngọt tự nhiên của hải sản.'),
  'yantai/apple': ('Táo Yên Đài', 'Khí hậu biển mát mẻ và nắng dồi dào của Yên Đài nuôi lớn giống táo nổi tiếng nhất Trung Quốc — đỏ mọng, giòn tan và thơm mùi mật, được chuyển đi khắp mọi miền đất nước. Mùa thu, các vườn táo dọc bờ biển rộn ràng vào vụ, và cả thành phố ngập trong hương táo.'),
  'yantai/wine': ('Rượu vang Trường Dụ', 'Trương Dụ (Changyu), nhà máy rượu vang hiện đại đầu tiên của Trung Quốc, được thành lập tại Yên Đài năm 1892 và đến nay vẫn là thương hiệu vang lâu đời nhất nước. Với bảo tàng văn hóa rượu vang, những hầm rượu lịch sử và các tuyến tham quan vườn nho lân cận, Yên Đài được xếp vào số ít \'thành phố rượu vang\' đích thực của châu Á.'),
  'yantai/wave': ('Bờ biển Bồng Lai', 'Bờ biển Bồng Lai của Yên Đài được thần thoại Trung Hoa kể là nơi Bát Tiên vượt biển ra khơi. Những ảo ảnh thi thoảng lung linh trên mặt nước đã mang lại cho bờ biển này danh tiếng \'chốn bồng lai tiên cảnh\', và lầu Bồng Lai cổ kính trên vách đá vẫn ngày ngày dõi nhìn ra biển.'),
  'yantai/cherry': ('Vườn anh đào', 'Yên Đài là một trong những vùng trồng anh đào (cherry) quan trọng nhất Trung Quốc; khí hậu ven biển mát mẻ nơi đây lý tưởng cho những trái cherry to, mọng nước và ngọt lịm. Đầu hè, các vườn cây mở cửa đón khách — tự tay hái cherry từ cành và thưởng thức tại chỗ là thú vui ngọt ngào nhất của mùa.'),
  'datong/buddha': ('Hang đá Vân Cương', 'Được tạc vào vách đá phía tây Đại Đồng, hang đá Vân Cương lưu giữ hàng nghìn tượng Phật từ thời Bắc Ngụy — một đỉnh cao của nghệ thuật Phật giáo Trung Hoa. Có bức tượng nhỏ gọn trong lòng bàn tay, có bức cao sừng sững như tòa nhà; quần thể hang động này là Di sản Thế giới UNESCO.'),
  'datong/citywall': ('Tường thành nhà Minh', 'Từng là thị trấn đồn trú nơi biên ải, Đại Đồng đã dựng lại tường thành thời Minh của mình với những cổng thành uy nghi và tháp canh ở các góc. Đi dạo trên mặt thành lung linh ánh đèn lồng lúc chiều tà là cách tuyệt nhất để thu vào tầm mắt cả mái ngói phố cổ lẫn ánh đèn của Đại Đồng mới trong cùng một khung cảnh.'),
  'datong/noodle': ('Mì cắt tay', 'Với đao tiêu miến (mì cắt bằng dao) — niềm tự hào của Sơn Tây — người đầu bếp tì khối bột lên cánh tay và dùng lưỡi dao gọt từng dải mì bay thẳng vào nồi nước sôi. Sợi mì dày ở viền, mỏng ở giữa nên thấm nước sốt tuyệt hảo — món kinh điển không thể thiếu trên bàn ăn Đại Đồng.'),
  'datong/lantern': ('Chùa Treo', 'Bám vào vách đá của núi Hằng Sơn gần Đại Đồng, Huyền Không Tự (chùa Treo) như lơ lửng giữa không trung trên những cây cột gỗ mảnh mai. Ngôi chùa khoảng 1.500 năm tuổi này còn độc đáo ở một điểm khác: nó là nơi Phật giáo, Đạo giáo và Nho giáo cùng hội tụ dưới một mái nhà.'),
  'baotou/horse': ('Ngựa thảo nguyên', 'Tên gọi Bao Đầu trong tiếng Mông Cổ có nghĩa là \'nơi có hươu\', và thành phố nằm bên rìa thảo nguyên Nội Mông. Trên những đồng cỏ bao quanh, ngựa vẫn là một phần của đời sống thường nhật: các mục dân Mông Cổ tổ chức đua ngựa, và giai điệu đàn mã đầu cầm ngân vang trong những căn lều du mục.'),
  'baotou/deer': ('Công viên Hươu', 'Bao Đầu được mệnh danh là \'Thành phố Hươu\', và những chú hươu thong dong dạo bước trong các công viên khiến cái tên ấy luôn sống động. Du khách có thể tự tay cho hươu ăn — một khung cảnh dịu dàng giữa thảo nguyên, hé lộ nét mềm mại đến bất ngờ của một thành phố công nghiệp.'),
  'baotou/factory': ('Thành phố Thép', 'Bao Đầu là nơi đặt một trong những nhà máy thép lớn nhất Trung Quốc và giữ vị trí đặc biệt trên bản đồ công nghiệp nặng của đất nước. Nhờ các mỏ khoáng sản lân cận, thành phố còn được biết đến như một trong những trung tâm đất hiếm quan trọng nhất thế giới.'),
  'baotou/grass': ('Du lịch thảo nguyên', 'Chỉ một chuyến đi ngắn từ thành phố là bạn đã đến với thảo nguyên trải dài tận chân trời. Khách được nghỉ trong lều Mông Cổ, được đón tiếp bằng trà sữa và thịt cừu nướng; buổi tối, những bài ca Mông Cổ vang lên quanh bếp lửa. Lòng hiếu khách trên thảo nguyên nơi đây là truyền thống đã có từ hàng thế kỷ.'),
  'weifang/kite': ('Thủ phủ diều', 'Duy Phường, nơi được xem là quê hương của cánh diều, đã gìn giữ nghề này suốt hàng thế kỷ với khung tre và lụa vẽ tay. Mỗi tháng Tư, Lễ hội Diều Quốc tế Duy Phường lại biến bầu trời thành ngày hội sắc màu với những cánh diều đến từ khắp nơi trên thế giới.'),
  'weifang/woodprint': ('Tranh khắc gỗ Dương Gia Phụ', 'Làng Dương Gia Phụ ở Duy Phường là một trong những cái nôi nổi tiếng nhất của tranh khắc gỗ nhiều màu treo trên cửa vào dịp Tết Nguyên đán. Thần giữ cửa, em bé bụ bẫm và các biểu tượng sung túc được in từng lớp màu từ những bản khắc gỗ thủ công — nghề này được truyền qua bao thế hệ.'),
  'weifang/dragon': ('Diều rồng', 'Ngôi sao trên bầu trời Duy Phường là những con diều rết khổng lồ đầu rồng: hàng chục vòng tre nối với thân lụa uốn lượn dài hàng chục mét trong gió. Đưa được một \'gã khổng lồ\' như thế lên trời đòi hỏi kỹ năng và sức lực của cả một đội thả diều.'),
  'weifang/radish': ('Củ cải Duy Phường', 'Củ cải xanh Duy Phường ngọt và mọng nước đến mức người dân địa phương gọt vỏ, thái lát và ăn như trái cây. Câu nói địa phương \'củ cải Duy Phường ngon hơn cả lê\' thể hiện niềm tự hào dành cho loại rau củ khiêm nhường này — mời khách củ cải bên chén trà là nét thanh lịch trong lòng hiếu khách của thành phố.'),
  'dezhou/chicken': ('Gà om Đức Châu', 'Gà om ngũ vị của Đức Châu được nấu đến khi thịt tự róc khỏi xương; danh tiếng của món ăn lan rộng khắp cả nước nhờ vị trí sầm uất của thành phố trên Đại Vận Hà và sau này là tuyến đường sắt. Được phết mật, chiên vàng rồi om liu riu trong nước dùng gia vị, món gà này từng được dâng lên bàn tiệc hoàng cung.'),
  'dezhou/sun': ('Thung lũng Năng lượng Mặt trời', 'Đầu tư sớm vào ngành công nghiệp năng lượng mặt trời, Đức Châu mang danh hiệu \'Thành phố Mặt trời\'; trong khu Thung lũng Mặt trời rộng lớn của thành phố, khách sạn, đèn đường và nhà cửa đều vận hành bằng năng lượng mặt trời. Thành phố là một trong những mô hình trưng bày năng lượng tái tạo dễ thấy nhất của Trung Quốc.'),
  'dezhou/grapes': ('Vùng đất dưa và nho', 'Đất đai màu mỡ của đồng bằng Hoàng Hà biến Đức Châu thành xứ sở trái cây mùa hè: những cánh đồng đầy dưa hấu và giàn nho trĩu quả. Một miếng dưa hấu mát lạnh từ quầy hàng ven đường là điểm dừng chân kinh điển trong ngày hè oi ả.'),
  'dezhou/train': ('Cảng kênh đào', 'Trong những thế kỷ Đại Vận Hà còn nhộn nhịp, Đức Châu là bến đỗ tấp nập của những đoàn thuyền chở lương thực lên phương Bắc. Ngày nay, đường sắt đã tiếp quản vai trò của kênh đào: nằm trên tuyến Bắc Kinh - Thượng Hải, thành phố vẫn là một trong những cửa ngõ giao thông trọng yếu của miền Bắc Trung Quốc.'),
  'xuzhou/stone': ('Phù điêu đá thời Hán', 'Từ Châu, quê hương của Lưu Bang — người sáng lập nhà Hán, là một kho lưu trữ lịch sử được khắc trên đá. Những bức phù điêu đá thời Hán từng trang trí các hầm mộ khắc họa yến tiệc, xe ngựa chiến và những linh thú huyền thoại, mở ra trước mắt ta đời sống thường nhật của hai nghìn năm trước như một cuốn truyện tranh cổ đại.'),
  'xuzhou/terracotta': ('Đội quân đất nung', 'Nhỏ hơn đội quân nổi tiếng ở Tây An, những binh sĩ đất nung thời Hán này được tìm thấy khi đang canh giữ lăng mộ một vị vua nước Sở. Các bức tượng chỉ cao đến đầu gối xếp thành hàng ngũ chỉnh tề; dù kích thước tí hon, vẻ trang nghiêm của chúng kể về một đội quân được tạo ra để tiếp tục phụng sự cả sau cái chết.'),
  'xuzhou/lake': ('Hồ Vân Long', 'Mang tên "Vân Long" — Rồng Mây, hồ Vân Long là tấm gương nước rộng lớn được bao quanh bởi đồi núi, được xem là lá phổi xanh của thành phố. Với những lối đi dạo ven hồ, quán trà và các sườn đồi có đền chùa trên đỉnh, người dân Từ Châu đổ về đây mọi giờ trong ngày, từ tập thể dục buổi sáng đến tản bộ buổi tối.'),
  'xuzhou/skewer': ('Văn hóa đồ nướng', 'Từ Châu tự hào tự xưng là thủ đô thịt nướng của Trung Quốc; khói từ những xiên thịt cừu xoay trên than hồng lan tỏa khắp phố phường đến tận đêm khuya. Những chiếc lò than nhỏ được mang thẳng ra bàn và mỗi người tự nướng xiên của mình — một nét văn hóa ẩm thực ồn ào, vui vẻ bên bạn bè kéo dài đến khuya.'),
  'zhenjiang/vinegar': ('Giấm Trấn Giang', 'Giấm gạo đen Trấn Giang ra đời từ quá trình lên men lâu dài và kiên nhẫn của gạo nếp; với vị chua dịu và chút ngọt thanh, đây là loại giấm nổi tiếng nhất trong ẩm thực Trung Hoa. Không bàn sủi cảo nào trọn vẹn nếu thiếu nó — như người dân địa phương nói, hương giấm thoang thoảng khắp các con phố Trấn Giang.'),
  'zhenjiang/temple': ('Chùa Kim Sơn', 'Chùa Kim Sơn bên bờ Trường Giang là nơi diễn ra cảnh kịch tính nhất của Truyền thuyết Bạch Xà, câu chuyện dân gian được yêu thích nhất Trung Quốc: chính tại đây, nàng xà tinh Bạch Tố Trinh đã dâng nước nhấn chìm ngôi chùa vì tình yêu của mình. Ngọn bảo tháp trên đỉnh đồi bao quát cả dòng sông lẫn thành phố.'),
  'zhenjiang/pot': ('Mì nắp nồi', 'Với món quả cái miến (mì nắp nồi) của Trấn Giang, một chiếc nắp gỗ nhỏ được thả nổi trong nồi nước sôi lớn; chiếc nắp giữ nước không trào và giúp sợi mì chín vừa tới. Sợi mì mảnh hòa quyện với giấm địa phương và nước dùng xì dầu — đó là cách khởi đầu ngày mới kinh điển ở thành phố này.'),
  'zhenjiang/bridge': ('Bờ sông Dương Tử', 'Trấn Giang là thành phố cảng cổ được dựng lên tại điểm chiến lược nơi Trường Giang giao với Đại Vận Hà. Ba ngọn đồi ven sông — Kim Sơn, Bắc Cố Sơn và Tiêu Sơn — với những ngọn tháp, ngôi chùa và công viên dạo bộ, biến bờ sông thành một dải văn hóa xanh mướt.'),
  'jiaxing/zongzi': ('Bánh chưng Gia Hưng', 'Gia Hưng là thủ phủ của bánh ú (zongzi) — những gói gạo nếp bọc lá tre đem hấp chín. Món ăn biểu tượng của Tết Đoan Ngọ được bán ở đây quanh năm với nhân thịt heo, đậu ngọt hay lòng đỏ trứng muối; bóc một chiếc bánh nóng hổi là một nghi thức nhỏ bắt đầu bằng hương thơm của lá.'),
  'jiaxing/boat': ('Thuyền trên hồ Nam Hồ', 'Năm 1921, khi buộc phải rời Thượng Hải, đại hội đầu tiên của Đảng Cộng sản Trung Quốc đã hoàn tất phiên họp trên một con thuyền ở Nam Hồ của Gia Hưng. Bản sao của "Con thuyền Đỏ" ngày nay vẫn neo trên hồ; mặt nước mờ sương, hàng liễu và những đình tạ trên đảo mang đến cho chuyến thăm một cảm giác lịch sử trầm lắng.'),
  'jiaxing/silk': ('Xứ sở tơ lụa', 'Suốt nhiều thế kỷ, những vườn dâu và nghề nuôi tằm của vùng Giang Nam đã nuôi sống các thị trấn kênh đào của Gia Hưng. Sợi tơ kéo từ kén tằm nơi đây biến thành chăn, vải và đồ thêu; sự mềm mại của lụa là món quà từ khí hậu ôn hòa, nhiều sông nước của vùng, trải dài từ ruộng đồng đến tủ áo.'),
  'jiaxing/canal': ('Ô Trấn', 'Ô Trấn, thuộc địa phận Gia Hưng, là một trong những thủy trấn thanh nhã nhất Giang Nam với những cây cầu đá, mái ngói đen và bậc thang dẫn xuống kênh. Khi đèn lồng thắp lên lúc hoàng hôn, mặt nước nhuộm đỏ rực; những nghề thủ công xưa như nhuộm chàm và múa rối bóng vẫn sống trong các ngõ nhỏ.'),
  'lishui/mountains': ('Đỉnh Xanh', 'Lệ Thủy là góc núi non hùng vĩ nhất của tỉnh Chiết Giang, thung lũng ngập sương mù còn các dãy núi phủ kín rừng tre và thông. Những ngôi làng đá cheo leo trên sườn núi cùng ruộng bậc thang chạm tới mây trời ẩn giấu một Trung Hoa chậm rãi, xanh mướt, cách xa sự náo nhiệt của tỉnh ven biển.'),
  'lishui/camera': ('Thiên đường nhiếp ảnh', 'Những thung lũng ngập sương mai, bóng nông dân hiện ra trên ruộng bậc thang và biển mây biến ảo theo ánh sáng đã biến Lệ Thủy thành chốn hành hương của giới nhiếp ảnh. Thành phố nổi tiếng với các sự kiện nhiếp ảnh quốc tế; những bức ảnh đẹp nhất chớp lấy khoảnh khắc ruộng bậc thang đầy nước ánh lên sắc vàng lúc bình minh.'),
  'lishui/mushroom': ('Xứ sở nấm', 'Huyện Khánh Nguyên thuộc Lệ Thủy được xem là cái nôi của nghề trồng nấm; phương pháp trồng nấm hương trên thân gỗ đã ra đời từ nhiều thế kỷ trước ngay trên những ngọn núi này. Ngày nay chợ làng vẫn thơm mùi nấm khô, và ẩm thực địa phương tự hào với những món canh, món om nấu từ nấm tươi vừa hái.'),
  'lishui/raft': ('Chèo bè trên sông', 'Sông Âu uốn lượn giữa những hẻm núi xanh của Lệ Thủy, và thả trôi trên làn nước trong vắt bằng bè tre là thú vui kinh điển của vùng này. Khi người lái bè điều khiển bằng cây sào dài, những làng chài, đồi núi mờ sương và khung cảnh như bước ra từ tranh thủy mặc lần lượt lướt qua hai bên bờ.'),
  'anqing/opera': ('Kịch Hoàng Mai', 'Hoàng Mai hí sinh ra từ những điệu hát hái chè của vùng quê An Khánh rồi trở thành một trong những loại hình hí kịch địa phương được yêu thích nhất Trung Quốc. Giai điệu mộc mạc, mượt mà cùng những chuyện tình kể bằng lời ăn tiếng nói hằng ngày đã được bao thế hệ thuộc lòng — và An Khánh đến nay vẫn được xem là thủ phủ của nghệ thuật này.'),
  'anqing/pagoda': ('Chấn Phong Tháp', 'Vươn cao bên bờ Trường Giang, tháp Chấn Phong từng làm ngọn hải đăng cho thuyền bè trên sông suốt hàng thế kỷ và được mệnh danh là \'ngọn tháp đầu tiên của Trường Giang\'. Tòa tháp bát giác thời Minh này ban tặng cho những ai leo lên các tầng tháp khung cảnh khúc sông uốn lượn hùng vĩ.'),
  'anqing/tea': ('Trà Nhạc Tây', 'Những sườn núi mát mẻ, mờ sương của dãy Đại Biệt Sơn phía sau An Khánh là khu vườn lý tưởng cho trà xanh thơm ngát. Ở huyện Nhạc Tây, những búp trà non hái tay vào mùa xuân cho nước trà nhẹ nhàng, thoảng hương hoa — và ở các bản làng trên núi, vụ hái trà vẫn là sự kiện lớn nhất trong mùa.'),
  'anqing/sail': ('Cửa sông', 'An Khánh, tên gọi mang nghĩa \'mừng vui an lành\', là cửa ngõ cảng lịch sử của tỉnh An Huy mở ra Trường Giang — chữ \'An\' trong tên tỉnh chính là lấy từ thành phố này. Những bến sông và khu phố cổ nơi đây vẫn lưu giữ dấu tích của thời hải cảng sầm uất.'),
  'ganzhou/orange': ('Cam rốn Cám Nam', 'Đất đỏ và khí hậu phương nam ôn hòa của Cám Châu nuôi lớn giống cam rốn Cám Nam, được xếp vào hàng ngọt nhất Trung Quốc. Vào mùa thu hoạch, những ngọn đồi nhuộm màu cam rực rỡ; mọng nước và không hạt, thứ quả này mang tên thành phố đi khắp cả nước như một niềm tự hào.'),
  'ganzhou/house': ('Nhà thổ lâu Khách Gia', 'Người Khách Gia, những di dân từ phương bắc, đã dựng nên các tòa nhà pháo đài ở những làng núi của Cám Châu; sau lớp tường phòng thủ dày, hàng chục gia đình cùng sinh sống dưới một mái nhà. Bên trong là sân chung, từ đường thờ tổ tiên và một văn hóa đoàn kết gắn bó được gìn giữ qua nhiều thế kỷ.'),
  'ganzhou/pavilion': ('Đình Úc Cô', 'Lầu Úc Cô nhìn xuống nơi hai dòng sông Chương và sông Cống hợp lưu để sinh ra sông Cám. Được ngợi ca trong thơ của các thi nhân đời Tống, tòa lầu gỗ này đan quyện cảnh sông nước với nghìn năm truyền thống thi ca; lúc chiều tà, đây là góc trầm mặc, hoài niệm nhất của thành phố.'),
  'ganzhou/star': ('Vạn lý Trường chinh', 'Năm 1934, Hồng quân bắt đầu cuộc rút lui hào hùng đi vào lịch sử với tên gọi Vạn lý Trường chinh từ huyện Vu Đô thuộc Cám Châu. Câu chuyện những người lính vượt sông suốt đêm được tưởng nhớ nơi đây bằng tượng đài và bảo tàng; thành phố chính là vạch xuất phát của một bước ngoặt trong lịch sử Trung Quốc hiện đại.'),
  'putian/shrine': ('Đền thờ Mẹ Mẫu', 'Nữ thần Ma Tổ, vị thần hộ mệnh của người đi biển, sinh ra ở Bồ Điền; ngôi đền tổ của bà tọa lạc trên đảo Mi Châu và được xem là cội nguồn của hàng nghìn đền Ma Tổ trên khắp thế giới. Tín ngưỡng và phong tục thờ Ma Tổ đã được UNESCO ghi vào danh sách di sản văn hóa phi vật thể; vào ngày lễ hội, hòn đảo ngập trong khói hương và dòng người hành hương.'),
  'putian/lychee': ('Vườn vải', 'Bồ Điền còn được gọi là "Thành phố Vải"; những cây vải hàng trăm năm tuổi vẫn cho quả và tỏa bóng mát xuống phố phường. Ửng đỏ vào mùa thu hoạch hè, thứ quả ngọt này từng là món xa xỉ phương nam được ca tụng trong thơ ca cổ điển, và thưởng thức vải tươi hái từ cành là một trong những niềm vui đẹp nhất của mùa hè Bồ Điền.'),
  'putian/shoe': ('Thủ phủ giày dép', 'Bồ Điền là một trong những người khổng lồ thầm lặng của ngành sản xuất giày thể thao thế giới; các xưởng và nhà máy nơi đây làm ra hàng triệu đôi giày cho những thương hiệu lớn. Ở thành phố này, nghề đóng giày như một nghề gia truyền — từ thợ làm khuôn đến thợ may, cả một chuỗi tay nghề tạo nên gian bếp vô hình của thời trang thể thao toàn cầu.'),
  'putian/wave': ('Đảo Mi Châu', 'Đảo Mi Châu, nơi chỉ đến được bằng phà, nổi tiếng với những bãi cát vàng, vịnh đá và các lễ hội đền Ma Tổ. Vào dịp sinh nhật nữ thần, hòn đảo bừng sống dậy với tiếng trống và những đoàn rước; những ngày còn lại, đây là chốn hành hương và nghỉ dưỡng yên bình lộng gió biển.'),
  'mudanjiang/snow': ('Làng Tuyết', '\'Làng Tuyết Trung Quốc\' gần Mẫu Đơn Giang là một trong những ngôi làng nhiều tuyết nhất cả nước, nơi những lớp tuyết dày phồng lên trên mái nhà, biến các căn nhà thành những túp lều cổ tích. Khi đèn lồng đỏ thắp lên lúc chiều buông, những con ngõ phủ tuyết bừng sáng trong ánh đèn ấm áp.'),
  'mudanjiang/lake': ('Hồ Kính Bạc', 'Hồ Kính Bạc, hình thành khi những đợt phun trào núi lửa cổ xưa chặn dòng sông, là một trong những hồ chắn núi lửa lớn nhất Trung Quốc. Nước hồ đổ xuống qua thác Điếu Thủy Lâu — nổi tiếng với những màn nhảy thác ngoạn mục của các thợ lặn gan dạ vào mùa hè và khung cảnh băng giá tuyệt đẹp vào mùa đông.'),
  'mudanjiang/tiger': ('Công viên Hổ Siberia', 'Hoành Đạo Hà Tử ở vùng Mẫu Đơn Giang là một trong những trung tâm hàng đầu thế giới về bảo tồn và nhân giống hổ Siberia, loài mèo lớn nhất hành tinh. Du khách quan sát những chú hổ dạo bước trong khu rừng rộng lớn từ các tuyến đường được bảo vệ, và trung tâm chính là trái tim của nỗ lực bảo vệ tương lai loài thú quý hiếm này.'),
  'mudanjiang/ski': ('Mùa trượt tuyết', 'Ở Mẫu Đơn Giang, nằm sâu trong vành đai tuyết của Trung Quốc, mùa đông kéo dài và tuyết rơi dày, khô mịn; những ngọn đồi rừng quanh thành phố chật kín người trượt tuyết mỗi mùa. Các cung trượt tuyết kết hợp với chuyến thăm Làng Tuyết biến vùng đất này thành một trong những trung tâm du lịch mùa đông của Đông Bắc Trung Quốc.'),
  'changzhou/dino': ('Công viên Khủng long', 'Công viên Khủng long Thường Châu, công viên chủ đề khủng long nổi tiếng nhất Trung Quốc, kết hợp bảo tàng hóa thạch với khu vui chơi giải trí và được trìu mến gọi là \'Công viên kỷ Jura của Trung Quốc\'. Với những mô hình khủng long khổng lồ, trò chơi dưới nước và tàu lượn siêu tốc, đây là điểm đến số một của thành phố dành cho các gia đình.'),
  'changzhou/pagoda': ('Chùa Thiên Ninh', 'Ngọn tháp cao 153 mét của chùa Thiên Ninh giữa trung tâm thành phố được xem là bảo tháp cao nhất thế giới. Vươn lên từ sân một ngôi chùa hơn nghìn năm lịch sử, tầng cao nhất của tháp trải cả Thường Châu và những khúc uốn của Đại Vận Hà dưới chân bạn.'),
  'changzhou/comb': ('Nghề làm lược', 'Lược Thường Châu là nghề thủ công hàng trăm năm tuổi, được chế tác từ các loại gỗ quý như hoàng dương và mun qua hàng chục công đoạn thủ công. Từng là vật phẩm tiến cung, những chiếc lược với hoa văn chạm khắc tinh xảo và hình vẽ tay này đến nay vẫn là món quà lưu niệm thanh lịch nhất của thành phố.'),
  'changzhou/canal': ('Đại Vận Hà', 'Đại Vận Hà đã chảy qua Thường Châu suốt hàng thế kỷ, và thành phố trở nên giàu có nhờ thương mại cùng nghề dệt mà tuyến đường thủy này mang lại. Buổi tối, những khu phố cổ ven kênh lung linh ánh đèn lồng, và tản bộ dọc các bến đá là thú vui kinh điển nhất của thành phố.'),
  'shaoxing/wine': ('Rượu Thiệu Hưng', 'Rượu nếp vàng màu hổ phách của Thiệu Hưng được lên men bằng nước hồ Giám Hồ địa phương, quý giá vừa như một thức uống vừa như gia vị không thể thiếu trong ẩm thực Trung Hoa. Theo phong tục thanh nhã nhất của thành phố, những vò rượu được chôn xuống đất khi con gái chào đời và khai mở trong ngày cưới của nàng.'),
  'shaoxing/bridge': ('Cầu đá cổ', 'Ở Thiệu Hưng chằng chịt kênh rạch, đường thủy nhộn nhịp chẳng kém gì đường phố, và với hàng trăm cây cầu đá cong cong, thành phố được gọi là \'bảo tàng những cây cầu\'. Nhiều nhịp cầu đã đứng vững hàng thế kỷ; những vòm đá phủ rêu của chúng đến nay vẫn tỏa bóng lên những con thuyền lướt bên dưới.'),
  'shaoxing/pen': ('Cái nôi thư pháp', 'Vương Hi Chi, người được tôn là bậc thầy vĩ đại nhất của thư pháp, đã viết kiệt tác Lan Đình Tự trong một buổi hội ngộ giữa những rừng trúc Thiệu Hưng. Tục thả chén rượu trôi theo dòng suối và ngâm thơ ra đời từ ngày ấy, và Lan Đình đến nay vẫn là điểm dừng chân thiêng liêng của những người yêu nghệ thuật bút lông.'),
  'shaoxing/boat': ('Thuyền Ô Bồng', 'Trên những chiếc thuyền ô bồng mui đen của Thiệu Hưng, người lái thuyền chèo bằng chân trong khi tay giữ lái — một kỹ thuật độc nhất vô nhị được truyền qua bao thế hệ. Lướt dưới những cây cầu đá dọc các con kênh hẹp, những chiếc thuyền này còn trôi qua cả ký ức tuổi thơ của Lỗ Tấn, nhà văn lừng danh mà thành phố đã sinh thành.'),
  'bengbu/shell': ('Cảng Ngọc Trai', 'Tên gọi Bạng Phụ có nghĩa là \'bến trai ngọc\', và khúc sông Hoài này từng nổi tiếng với những người mò ngọc trai nước ngọt. Ngọc trai đến nay vẫn là biểu tượng của thành phố — bạn sẽ bắt gặp nó ở khắp nơi, từ các bức tượng quảng trường đến huy hiệu của thành phố.'),
  'bengbu/train': ('Cửa ngõ đường sắt', 'Bạng Phụ vươn mình từ một thị trấn nhỏ thành đô thị lớn tại điểm tuyến đường sắt Thiên Tân - Phố Khẩu vượt sông Hoài. Cửa ngõ trên trục Bắc-Nam này đến nay vẫn nối miền bắc An Huy vào mạng lưới giao thông chính của cả nước.'),
  'bengbu/river': ('Sông Hoài', 'Sông Hoài được xem là ranh giới tự nhiên chia Trung Quốc thành hai miền Nam-Bắc: phía bắc trồng lúa mì, phía nam trồng lúa nước, và hệ thống sưởi trung tâm mùa đông cũng dừng lại ở bờ sông này. Bạng Phụ nằm ngay trên lằn ranh chuyển giao ấy, giữa hai vùng khí hậu và hai nền ẩm thực.'),
  'bengbu/blossom': ('Lễ hội hoa xuân', 'Mùa xuân, các công viên dọc sông Hoài bung nở muôn hoa, và người dân Bạng Phụ dành những ngày cuối tuần bên sông với các buổi dã ngoại và hội hoa. Công viên Trương Công Sơn bên hồ trở thành điểm hẹn đông vui nhất thành phố khi anh đào và hoa đào đua nở.'),
  'jiujiang/mountain': ('Lư Sơn', 'Vươn lên giữa Trường Giang và hồ Bà Dương, Lư Sơn là ngọn núi nên thơ nhất Trung Quốc — với những đỉnh núi quyện mây mù, thác nước và cao nguyên mát lành, đã được ghi danh Di sản Thế giới UNESCO. Từ những vần thơ của Lý Bạch về thác nước đến các biệt thự đá của thị trấn Guling trên sườn núi, mỗi góc nơi đây đều kể một câu chuyện.'),
  'jiujiang/tea': ('Trà Vân Vụ', 'Trà Vân Vụ (\'mây mù\'), mọc trên những sườn núi phủ mây của Lư Sơn, thuộc hàng những danh trà xanh của Trung Quốc. Hơi ẩm của núi và ánh nắng lọc qua màn sương cho lá trà hương thơm tươi mát, ngọt dịu; những búp non đầu xuân được hái bằng tay và được quý trọng như vụ thu hoạch tinh túy nhất.'),
  'jiujiang/lake': ('Hồ Bà Dương', 'Bà Dương, hồ nước ngọt lớn nhất Trung Quốc, hòa vào Trường Giang ngay cạnh Cửu Giang. Mực nước hồ dâng lên hạ xuống theo mùa, và những đồng cỏ ngập nước lộ ra vào mùa đông đón hàng chục nghìn cánh chim di trú — trong đó có loài sếu Siberia quý hiếm.'),
  'jiujiang/scroll': ('Thành phố thi ca', 'Bến cảng cổ bên Trường Giang này từng đón những tên tuổi lớn của thi ca Trung Hoa: Bạch Cư Dị đã viết áng thơ nổi tiếng \'Tỳ bà hành\' tại đây, lấy cảm hứng từ một khúc đàn nghe được trên sông. Nép mình dưới bóng Lư Sơn, Cửu Giang là một trong những cửa sông được nhắc tên nhiều nhất trong thơ ca.'),
  'quanzhou/ship': ('Con đường tơ lụa trên biển', 'Được thế giới trung cổ biết đến với tên gọi \'Zayton\', Tuyền Châu từng là hải cảng lớn nhất của Con đường Tơ lụa trên biển — Marco Polo mô tả đây là một trong những bến cảng nhộn nhịp nhất thế gian. Với nhà thờ Hồi giáo, đền chùa và nhà thờ đứng kề bên nhau, di sản đa văn hóa của thành phố đã mang về cho nó một vị trí trong danh sách Di sản Thế giới UNESCO.'),
  'quanzhou/mosque': ('Thánh đường Thanh Tịnh', 'Được các thương nhân Ả Rập xây dựng năm 1009, thánh đường Thanh Tịnh là một trong những nhà thờ Hồi giáo cổ nhất còn tồn tại ở Trung Quốc. Cổng đá hoa cương và những bức tường đá mang cảm hứng kiến trúc Trung Đông là minh chứng cho việc hải cảng Tuyền Châu từng đa tín ngưỡng và quốc tế đến nhường nào trong thời đại Con đường Tơ lụa trên biển.'),
  'quanzhou/puppet': ('Múa rối dây', 'Trong nghệ thuật rối dây Tuyền Châu, các nghệ nhân thổi hồn vào những hình nhân gỗ bằng cách điều khiển hàng chục sợi dây mảnh cùng lúc — con rối có thể viết thư pháp hay rút kiếm giao đấu. Truyền thống nghìn năm này vẫn là khách mời danh dự của các hội đền và sân khấu lễ hội.'),
  'quanzhou/tea': ('Trà Thiết Quan Âm', 'Huyện miền núi An Khê thuộc Tuyền Châu là quê hương của Thiết Quan Âm — loại trà ô long nổi tiếng nhất thế giới. Những lá trà bán lên men bung nở với hương thơm tựa hoa lan, và nghi thức trà công phu pha trong những chén nhỏ xíu chính là nhịp sống thường ngày nơi đây.'),
  'shanghai/pearl': ('Tháp truyền hình Minh Châu Phương Đông', 'Vươn cao giữa khu Lục Gia Chủy của Phố Đông, tòa tháp với những quả cầu hồng là hình bóng dễ nhận ra nhất của Thượng Hải hiện đại. Từ đài quan sát có sàn kính, sông Hoàng Phố và Bến Thượng Hải bên kia bờ trải ra dưới chân bạn; về đêm, sắc màu của tháp lung linh phản chiếu trên mặt nước.'),
  'shanghai/bund': ('Bến Thượng Hải', 'Những mặt tiền ngân hàng và khách sạn cổ kính dọc sông Hoàng Phố lưu giữ vẻ tráng lệ của thời Thượng Hải còn là một thương cảng quốc tế. Trong buổi dạo chơi chiều tối, một bên là các tòa nhà thương mại với hàng cột đá, bên kia là những tòa cao ốc rực sáng của Phố Đông — hai thế kỷ gặp nhau trong một ánh nhìn.'),
  'shanghai/garden': ('Dự Viên', 'Khu vườn cổ điển từ thời nhà Minh này, với non bộ, ao nước và cây cầu chữ chi, là một ốc đảo giữa lòng thành phố. Khu chợ bao quanh vườn nhộn nhịp quán trà và hàng quà vặt, còn sau những bức tường chạm hình rồng ẩn giấu nghệ thuật vườn cảnh Giang Nam đầy tinh tế.'),
  'shanghai/xlb': ('Tiểu long bao', 'Tiểu long bao — những chiếc bánh vỏ mỏng giữ trọn nước dùng nóng hổi bên trong — là kiệt tác của ẩm thực Thượng Hải. Bạn cắn nhẹ mép bánh để nhấp phần súp trước, rồi chấm bánh vào giấm đen với gừng. Mỗi buổi sáng, những lồng hấp bằng tre lại phủ làn hơi nước mờ ảo lên các con phố.'),
  'hangzhou/lake': ('Tây Hồ', 'Với hàng liễu, những hòn đảo nhỏ và các cây cầu vòm, Tây Hồ là thắng cảnh được thi ca Trung Hoa ca ngợi nhiều nhất và là di sản thế giới UNESCO. Dạo bước trên đê Tô và đê Bạch đã là thú vui suốt bao thế kỷ, còn cầu Đoạn được truyền tụng là nơi hò hẹn của đôi tình nhân trong truyền thuyết Bạch Xà.'),
  'hangzhou/tea': ('Trà Long Tỉnh', 'Trồng trên những sườn đồi quanh hồ, trà xanh Long Tỉnh — \'Giếng Rồng\' — là loại trà nổi tiếng nhất Trung Quốc. Những lá trà dẹt vẫn được tạo hình bằng tay trong chảo nóng, và vụ hái đầu xuân được quý trọng hơn cả. Một chén Long Tỉnh trong quán trà thôn quê chính là tinh thần đích thực của Hàng Châu.'),
  'hangzhou/temple': ('Chùa Linh Ẩn', 'Linh Ẩn, ngôi chùa mang nghĩa \'nơi ẩn cư của tâm linh\', là một trong những ngôi chùa Phật giáo cổ nhất Trung Quốc. Đối diện chùa, hàng trăm tượng Phật đã được tạc vào vách đá của đỉnh Phi Lai qua nhiều thế kỷ. Dạo bước giữa khói hương và bóng tùng, bạn sẽ quên hẳn tiếng ồn phố thị.'),
  'hangzhou/silk': ('Phố lụa Hàng Châu', 'Lụa Hàng Châu đã được dệt suốt hơn một nghìn năm, và thành phố từng là biểu tượng của sự giàu có nơi đầu phía đông Con đường Tơ lụa. Ngày nay vải vóc, khăn choàng và đồ thêu vẫn tấp nập đổi chủ trong chợ tơ lụa, còn bảo tàng tơ lụa kể lại hành trình từ kén tằm đến khung cửi. Mềm mại trong từng thớ vải, lụa Hàng Châu vẫn là món quà thanh lịch bậc nhất.'),
  'chongqing/hongya': ('Hồng Nhai Động', 'Là quần thể nhà sàn gỗ truyền thống bám vào vách núi, Hồng Nhai Động lưu giữ kiến trúc xưa của thành phố miền sơn cước. Khi những tầng nhà chồng lớp lên đèn về đêm, cả công trình rực sáng như chuyện cổ tích bên sông Gia Lăng; những lối đi hẹp bên trong đầy ắp món ăn vặt địa phương và cửa hàng thủ công.'),
  'chongqing/hotpot': ('Lẩu Trùng Khánh', 'Sôi sục với lớp dầu đỏ rực và vị tê cay của hạt tiêu Tứ Xuyên, lẩu chính là linh hồn nóng bỏng của Trùng Khánh. Tương truyền món ăn ra đời từ những nồi lẩu của phu khuân vác nơi bến sông. Mỗi miếng ngon nhúng vào chiếc nồi chín ngăn giữa bàn lại mở ra một cuộc chuyện trò dài bên bạn bè.'),
  'chongqing/monorail': ('Đường sắt trên cao Trùng Khánh', 'Ở Trùng Khánh đồi núi trập trùng, các tuyến tàu điện vượt qua thung lũng, và tại một nhà ga, đoàn tàu nổi tiếng chạy xuyên thẳng qua một tòa chung cư. Cảnh tượng ấy đã trở thành hình ảnh đặc trưng của thành phố. Với những con dốc, thang máy và cây cầu, \'thành phố núi\' này thách thức mọi logic phẳng phiu của bản đồ.'),
  'chongqing/river': ('Tam Hiệp Trường Giang', 'Thành phố vươn lên nơi Trường Giang gặp sông Gia Lăng, và các chuyến du thuyền Tam Hiệp khởi hành từ bến Triều Thiên Môn. Khi con tàu lướt giữa những vách đá dựng đứng, hàng nghìn năm thương mại và thi ca của dòng sông vĩ đại nhất Trung Hoa như trôi qua trước mắt bạn.'),
  'dalian/square': ('Quảng trường Tinh Hải', 'Mở ra hướng biển, Tinh Hải là một trong những quảng trường thành phố lớn nhất thế giới, mang tên \'biển sao\'. Diều bay lượn trên thảm cỏ rộng, còn buổi chiều tối những người đạp xe lướt dọc con đường ven biển; vào mùa lễ hội, quảng trường tràn ngập hòa nhạc và trình diễn.'),
  'dalian/beach': ('Bãi biển Đại Liên', 'Với những vũng đá, bãi biển sạch và mùa hè mát mẻ, Đại Liên là điểm nghỉ biển được yêu thích nhất miền bắc Trung Quốc. Con đường Tân Hải uốn lượn ven bờ mở ra những khung cảnh ngoạn mục giữa vách đá và vịnh biển. Khi cái nóng đổ xuống, người phương bắc lại tìm về đây để hít thở gió biển.'),
  'dalian/football': ('Thành phố bóng đá', 'Đại Liên được gọi là \'cái nôi bóng đá\' của Trung Quốc; những câu lạc bộ từng thống trị giải quốc gia và vô số tuyển thủ đều xuất thân từ thành phố này. Lũ trẻ đuổi theo trái bóng trong các công viên ven biển tiếp nối truyền thống ấy, và vào ngày có trận đấu, cả thành phố hóa thành một khán đài chung nhịp đập.'),
  'dalian/seafood': ('Hải sản Đại Liên', 'Vùng Hoàng Hải lạnh và trong xanh mang đến cho bàn ăn Đại Liên sò điệp, tôm, nhím biển và hải sâm. Trong các nhà hàng ven bờ, bạn tự chọn hải sản từ bể và món ăn được hấp chín chỉ trong vài phút. Còn mùi mực nướng thơm lừng chính là linh hồn của những khu chợ đêm.'),
  'shenyang/palace': ('Thẩm Dương Cố Cung', 'Được những người sáng lập nhà Thanh xây dựng, Cố cung Thịnh Kinh là cung điện đầu tiên của vương triều trước khi triều đình dời về Bắc Kinh. Thường được xem là \'người em nhỏ\' của Tử Cấm Thành, nơi đây vẫn mang cá tính riêng với những điện bát giác đậm phong cách Mãn Châu — ngày nay là bảo tàng được UNESCO công nhận.'),
  'shenyang/tomb': ('Lăng mộ nhà Thanh', 'Đông Lăng và Bắc Lăng bao quanh thành phố là những lăng mộ đồ sộ của các vị vua khai quốc nhà Thanh và đã được UNESCO ghi danh. Những con đường thiêng với hai hàng tượng thú bằng đá chạy xuyên qua rừng thông cổ thụ, và vào mùa thu, các công viên lăng tẩm nhuộm một màu vàng óng.'),
  'shenyang/factory': ('Cái nôi công nghiệp', 'Phần lớn nền công nghiệp nặng Trung Quốc khởi sinh từ Thẩm Dương, và những nhà máy cơ khí khổng lồ đã mang lại cho thành phố danh xưng \'Ruhr của phương Đông\'. Các xưởng cũ ở khu Thiết Tây nay đang trở thành bảo tàng và không gian nghệ thuật, nhưng niềm tự hào của bao thế hệ đứng máy vẫn còn vương vấn trong không khí.'),
  'shenyang/dumpling': ('Sủi cảo Lão Biên', 'Được làm từ thời nhà Thanh, bánh chẻo hấp Lão Biên là món đặc trưng của bàn ăn phương bắc. Nhân bánh được xào chín trước để ngấm trọn nước ngọt, đem lại độ mềm mại không gì sánh được. Một lồng bánh trong những nhà hàng lâu đời của thành phố gần như là lời chào đón chính thức khi bạn đến Thẩm Dương.'),
  'hefei/judge': ('Bao Công Từ', 'Bao Chửng, vị quan tòa huyền thoại của nhà Tống, sinh ra ở Hợp Phì; dân gian gọi ông là \'Bao Thanh Thiên\' — bầu trời không gợn vết. Tinh thần công lý không khuất phục trước hối lộ của ông đã đi vào cả tuồng kịch lẫn phim truyền hình. Công viên tưởng niệm bên hồ của ông tựa như một ngôi đền dâng cho sự thanh liêm.'),
  'hefei/science': ('Thành phố Khoa học', 'Hợp Phì là thành phố khoa học, nơi quy tụ nhiều trường đại học và phòng thí nghiệm hàng đầu Trung Quốc. Từ thí nghiệm nhiệt hạch đến nghiên cứu lượng tử, các dự án lớn đều được triển khai tại đây; những khuôn viên đại học và khu công nghệ mang lại cho thành phố một tinh thần trẻ trung, ham khám phá.'),
  'hefei/lake': ('Hồ Sào', 'Sào Hồ là một trong năm hồ nước ngọt lớn của Trung Quốc, trải rộng ngay phía nam Hợp Phì. Cá bạc, tôm trắng và cua của hồ được xưng tụng là \'tam bảo\'. Ở các thị trấn ven bờ, thuyền cá và quán trà nhìn ra hồ tạo nên nhịp sống chậm rãi, thư thái.'),
  'hefei/cake': ('Bánh mè Lư Châu', 'Tên cũ của Hợp Phì là Lư Châu, và chiếc bánh vừng nhân ngọt mang tên gọi ấy là món quà quê đã có tự bao đời. Hương vừng rang quyện với phần nhân mềm ẩn dưới lớp vỏ giòn tan. Mỗi dịp lễ tết, chiếc bánh này luôn chiếm vị trí trang trọng nhất trong những hộp quà biếu.'),
  'foshan/wingchun': ('Vịnh Xuân Quyền', 'Môn võ Vịnh Xuân Quyền đã trưởng thành ở Phật Sơn; tôn sư huyền thoại Diệp Vấn rèn luyện tại đây, và qua người học trò Lý Tiểu Long, di sản ấy lan tỏa khắp thế giới. Các nhà tưởng niệm và võ đường trong thành phố gìn giữ truyền thống — bắt gặp các võ sư luyện quyền trong công viên buổi sáng là chuyện thường ngày.'),
  'foshan/lion': ('Múa lân', 'Phật Sơn là thủ phủ của múa lân phương nam, và người anh hùng dân gian lừng danh Hoàng Phi Hồng cũng xuất thân từ vùng đất này. Trong các lễ hội, những chú lân rực rỡ nhảy qua các cột cao theo nhịp trống dồn dập. Nghề làm đầu lân là một nghệ thuật tinh xảo được truyền từ đời này sang đời khác.'),
  'foshan/ceramic': ('Gốm Thạch Loan', 'Những lò gốm Thạch Loan đã đỏ lửa suốt hàng thế kỷ; lò Nam Phong là một trong những lò nung củi cổ nhất Trung Quốc vẫn còn hoạt động. Với những bức tượng nhỏ giàu biểu cảm và các phù điêu tráng men trang trí mái nhà, gốm Thạch Loan còn tô điểm cả nóc những ngôi đền khắp Quảng Đông.'),
  'foshan/opera': ('Kịch Quảng Đông', 'Việt kịch — nghệ thuật sân khấu được yêu thích nhất miền nam Trung Quốc — đã trưởng thành trên vùng đất này. Xưa kia các gánh hát rong ruổi khắp châu thổ Châu Giang trên những \'chiếc thuyền đỏ\', diễn từ làng này sang làng khác. Trang phục lộng lẫy, màn nhào lộn và làn điệu tiếng Quảng vẫn làm rộn ràng các nhà hát hôm nay.'),
  'guiyang/pavilion': ('Giáp Tú Các', 'Tọa lạc trên một tảng đá giữa sông Nam Minh, lầu Giáp Tú ba tầng đã là biểu tượng của thành phố từ thời nhà Minh. Tên lầu có nghĩa \'người đỗ đầu\', được dựng với mong ước thành phố sản sinh những sĩ tử xuất sắc trong các kỳ khoa cử. Khi ánh đèn lầu soi xuống dòng sông về đêm, khung cảnh duyên dáng nhất của Quý Dương hiện ra.'),
  'guiyang/sourfish': ('Cá nấu canh chua', 'Cá nấu canh chua là món đặc trưng của Quý Châu, bắt nguồn từ truyền thống lên men của người Miêu. Cá nước ngọt được ninh trong nồi nước dùng đỏ au, chua thanh nhờ cà chua và cơm rượu lên men. Vũ điệu của vị chua, cay và thơm nồng hòa hợp tuyệt vời với khí hậu vùng núi phương nam.'),
  'guiyang/waterfall': ('Thác Hoàng Quả Thụ', 'Từ Quý Dương có thể đến Hoàng Quả Thụ, một trong những thác nước lớn nhất châu Á. Bạn có thể đi xuyên qua động Thủy Liêm nằm sau bức màn nước gầm vang, nơi bụi nước tung lên tạo thành cầu vồng trong nắng. Vào mùa mưa, tiếng thác dội xa hàng cây số dọc thung lũng.'),
  'guiyang/miao': ('Văn hóa người Miêu', 'Những bản làng vùng núi Quý Châu là quê hương của người Miêu, nổi tiếng với mũ đội đầu bằng bạc. Trong các lễ hội, thiếu nữ đội vương miện bạc chế tác thủ công, khoác trang phục thêu, và mọi người nắm tay nhảy vòng theo tiếng khèn lusheng. Nghệ thuật batik và thêu thùa là thứ ngôn ngữ truyền từ mẹ sang con gái.'),
  'changchun/film': ('Thành phố Điện ảnh', 'Xưởng phim Trường Xuân là nơi khai sinh nền điện ảnh Trung Quốc mới; suốt nhiều thế hệ, những bộ phim kinh điển của đất nước được quay tại đây. Vì thế thành phố được gọi là \'Hollywood của phương Đông\'. Các phim trường cũ nay trở thành công viên chủ đề điện ảnh, còn truyền thống liên hoan phim vẫn tiếp diễn.'),
  'changchun/car': ('Thành phố Ô tô', 'Chiếc xe tải nội địa đầu tiên và chiếc ô tô nội địa đầu tiên của Trung Quốc đều lăn bánh từ các nhà máy Trường Xuân, và những chiếc limousine Hồng Kỳ chở nguyên thủ quốc gia cũng được sản xuất tại đây. Danh hiệu \'thành phố ô tô\' hoàn toàn xứng đáng: với nhà máy, bảo tàng và triển lãm, văn hóa xe hơi chính là bản sắc của thành phố.'),
  'changchun/palace': ('Ngụy Mãn Hoàng cung', 'Phổ Nghi, vị hoàng đế cuối cùng của Trung Quốc, đã sống trong cung điện này với vai trò vua bù nhìn thời Mãn Châu Quốc. Nay là bảo tàng, nơi đây kể về sự giám sát và nỗi cô đơn ẩn sau những gian điện bề thế. Cung điện là ô cửa sổ lặng lẽ nhìn vào những biến động của thế kỷ hai mươi.'),
  'changchun/snow': ('Tuyết mùa đông', 'Mùa đông dài phủ trắng của Trường Xuân biến thành phố thành một lễ hội tuyết. Những tác phẩm điêu khắc băng rực sáng dưới ánh đèn màu về đêm, còn hồ Tịnh Nguyệt Đàm giữa rừng đón chào người trượt tuyết và trượt xe. Dẫu giá lạnh, mùa đông nơi đây lại là mùa vui nhất trong năm.'),
  'xining/lake': ('Hồ Thanh Hải', 'Hồ Thanh Hải là hồ lớn nhất Trung Quốc, trải dài như một vùng biển ngọc lam giữa cao nguyên. Mùa hè, bờ hồ được bao phủ bởi những cánh đồng hoa cải vàng rực, và chim di cư đậu kín các hòn đảo. Đạp xe một vòng quanh hồ là cuộc phiêu lưu vùng cao được du khách yêu thích nhất.'),
  'xining/monastery': ('Tu viện Kumbum', 'Tháp Nhĩ Tự (Kumbum) là một trong những tu viện lớn nhất của Phật giáo Tây Tạng, vươn lên nơi Tông Khách Ba — người sáng lập phái Cách Lỗ — chào đời. Những bức tượng nhiều màu nặn từ bơ bò yak, các bích họa và tranh vải đắp nổi của tu viện được tôn vinh là \'tam tuyệt\'. Trong các sân viện, bánh xe cầu nguyện của khách hành hương không bao giờ ngừng quay.'),
  'xining/flower': ('Hoa cải dầu', 'Khi tháng Bảy đến, cao nguyên Thanh Hải được phủ kín đến tận chân trời bởi hoa cải vàng óng. Bờ hồ và chân núi dập dờn trong muôn nghìn sắc vàng. Giữa không khí mát lành vùng cao, cảnh tượng ấy năm nào cũng cuốn hút các nhiếp ảnh gia và những đôi uyên ương hưởng tuần trăng mật.'),
  'xining/lamb': ('Thịt bò yak và thịt cừu', 'Bàn ăn Tây Ninh là nơi ẩm thực của người Hồi và người Tạng gặp gỡ. Mì kéo tay được dọn trong những bát nghi ngút khói, xiên thịt cừu xèo xèo trên than hồng, còn sữa chua bò yak và trà bơ là hương vị thường nhật của cao nguyên. Về đêm, các khu chợ ngập tràn mùi thơm của gia vị.'),
  'guilin/karst': ('Núi đá vôi sông Ly', 'Sông Ly uốn lượn giữa những ngọn núi đá vôi nhô lên từ màn sương — chính là khung cảnh được in trên tờ tiền 20 nhân dân tệ. Những con thuyền trôi từ Quế Lâm về Dương Sóc, những chiếc bè tre và người đánh cá bằng chim cốc tạo nên một bức tranh thủy mặc Trung Hoa sống động.'),
  'guilin/elephant': ('Núi Vòi Voi', 'Trông như chú voi đang nhúng vòi xuống sông Ly, ngọn núi đá này là biểu tượng được yêu mến nhất của Quế Lâm. Vòm đá giữa vòi và thân voi in bóng xuống nước tựa vầng trăng tròn, nên được gọi là động \'Thủy Nguyệt\'. Bao thế kỷ qua, các thi nhân đã đưa cảnh sắc này vào thơ.'),
  'guilin/terrace': ('Ruộng bậc thang Long Tích', 'Ôm lấy các sườn núi từng bậc từng bậc, ruộng bậc thang Long Tích — \'Sống lưng Rồng\' — là thành quả lao động hàng thế kỷ của người Choang và người Dao. Mùa xuân, những thửa ruộng ngập nước lấp lánh như gương; mùa thu, chúng chuyển sang sắc vàng óng ả. Những ngôi làng gỗ trên cao vẫn giữ nếp sống truyền thống.'),
  'guilin/osmanthus': ('Hoa mộc tê', 'Tên gọi Quế Lâm có nghĩa là \'rừng hoa quế\', và mùa thu cả thành phố đắm chìm trong hương thơm ngọt ngào của loài hoa bé nhỏ này. Trà hoa quế, rượu hoa quế và mứt kẹo hoa quế đứng đầu danh sách đặc sản địa phương. Dạo bước dưới hàng cây thơm ngát ven sông là nghi thức đẹp nhất của mùa.'),
  'wenzhou/merchant': ('Tinh thần thương nhân', 'Người Ôn Châu nổi tiếng là một trong những cộng đồng giàu tinh thần kinh doanh nhất Trung Quốc, dựng nên những nhịp cầu thương mại từ châu Âu đến châu Mỹ nhờ mạng lưới gia đình và đồng hương. Là nơi tiên phong của kinh tế tư nhân trong thời kỳ cải cách, thành phố đầy ắp những câu chuyện đi từ xưởng nhỏ ra thị trường thế giới.'),
  'wenzhou/shoe': ('Giày dép và đồ da', 'Ôn Châu được xem là thủ phủ giày dép và đồ da của Trung Quốc; phần lớn giày da trên thế giới xuất xưởng từ thành phố công nghiệp này. Cũng thành thạo trong các mặt hàng nhỏ từ bật lửa đến kính mắt, thành phố vẫn giữ tinh thần thợ thủ công của thời mà \'mỗi mái nhà là một xưởng sản xuất\'.'),
  'wenzhou/mountain': ('Núi Nhạn Đãng', 'Nổi tiếng với thác nước và những đỉnh núi lởm chởm, dãy Nhạn Đãng được ngợi ca là \'ngọn núi đầu tiên bên bờ biển\'. Thác Đại Long Tưu gầm vang đổ xuống vách đá, và lúc hoàng hôn, bóng dáng của vài ngọn núi dường như biến đổi hình hài. Dãy núi là công viên địa chất được bảo tồn nhờ cấu tạo địa chất độc đáo.'),
  'wenzhou/seafood': ('Hải sản', 'Mở ra biển Hoa Đông, ẩm thực Ôn Châu thanh nhẹ và tươi mới, với mực, sò điệp và cá là trung tâm của bữa ăn hằng ngày. Trường phái ẩm thực Âu địa phương để hương vị tự nhiên của hải sản lên tiếng. Canh chả cá giã tay là món ăn đường phố được yêu thích nhất của thành phố.'),
  'tangshan/memorial': ('Đài tưởng niệm động đất', 'Trận đại địa chấn năm 1976 đã san phẳng Đường Sơn; trong công viên tưởng niệm ngày nay, tên các nạn nhân được khắc lên những bức tường đá hoa cương dài. Lễ tưởng niệm được tổ chức hằng năm bên các hồ nước tĩnh lặng. Thành phố được tái thiết đã trở thành biểu tượng của sức bền bỉ và sự hồi sinh.'),
  'tangshan/coal': ('Than đá và thép', 'Mỏ than hiện đại đầu tiên và một trong những tuyến đường sắt đầu tiên của Trung Quốc được mở tại Đường Sơn, và đầu máy hơi nước đầu tiên của đất nước cũng ra đời nơi đây. Vì thế thành phố được xem là cái nôi của công nghiệp Trung Quốc. Văn hóa mỏ than và luyện thép vẫn thấm sâu trong bản sắc đô thị đến tận hôm nay.'),
  'tangshan/ceramic': ('Gốm sứ Đường Sơn', 'Đường Sơn được mệnh danh là \'thành phố gốm sứ phương bắc\', nổi tiếng trên hết với dòng sứ xương. Những bộ đồ ăn trắng muốt, mỏng đến mức xuyên sáng của thành phố tô điểm bàn ăn khắp Trung Quốc. Các hội chợ gốm sứ và xưởng của những nghệ nhân bậc thầy giữ cho truyền thống luôn sống động.'),
  'tangshan/lake': ('Công viên Nam Hồ', 'Nam Hồ ra đời khi một vùng sụt lún mỏ cũ được cải tạo thành hồ nước và công viên xanh mướt; ngày nay đó là lá phổi xanh của thành phố. Đường đạp xe và vườn hoa trải dọc bờ hồ, và công viên từng đăng cai một triển lãm làm vườn quy mô lớn. Nơi đây là biểu tượng của một thành phố công nghiệp làm hòa với thiên nhiên.'),
  'anshan/steel': ('Thành phố Thép', 'An Sơn là nơi đặt một trong những khu liên hợp gang thép lớn nhất Trung Quốc và được mệnh danh là \'thủ đô thép\' của cả nước. Suốt bao thế hệ, ánh lửa lò cao đã thắp sáng những đêm dài của thành phố. Ở đây, nghề luyện thép không chỉ là một công việc mà chính là bản sắc của đô thị.'),
  'anshan/jade': ('Ngọc Tú Nham', 'Tụ Nham, thuộc vùng An Sơn, là một trong những miền ngọc bích trứ danh của Trung Quốc. Cung Ngọc Phật trong thành phố trưng bày bức tượng Phật nổi tiếng thế giới, được tạc từ một khối ngọc khổng lồ nguyên vẹn. Các xưởng và chợ ngọc tràn đầy tài nghệ thổi hồn vào đá của những người thợ.'),
  'anshan/mountain': ('Núi Thiên Sơn', 'Thiên Sơn — \'Nghìn đỉnh sen\' — là ngọn núi thiêng của vùng đông bắc, với những đỉnh đá hoa cương xếp lớp như cánh sen. Chùa chiền Phật giáo và đạo quán Đạo giáo rải rác khắp sườn núi, và một tảng đá khổng lồ nổi tiếng vì giống hệt dáng Phật ngồi. Mùa xuân, cả ngọn núi khoác lên mình sắc hoa.'),
  'anshan/spring': ('Suối nước nóng Thang Cương Tử', 'Suốt nghìn năm qua, người ta tìm đến suối nước nóng Thang Cương Tử để chữa bệnh; bao thế hệ đã ngâm mình trong dòng nước khoáng và bùn nóng được tin là làm dịu đau nhức xương khớp. Từng đón tiếp các bậc quân vương và tân khách danh tiếng trong lịch sử, suối nước nóng vẫn là chốn nghỉ dưỡng cho những ai tìm kiếm sự thư thái.'),
  'linyi/market': ('Chợ bán buôn Lâm Nghi', 'Lâm Nghi là trung tâm bán buôn lớn nhất miền bắc Trung Quốc; những khu chợ mênh mông của thành phố có đủ mọi thứ, từ cây kim đến bộ bàn ghế. Đoàn xe tải xuất phát từ đây chở hàng đến mọi miền đất nước. Nhịp sống sôi động ấy đã mang về cho thành phố danh hiệu \'thủ đô logistics\'.'),
  'linyi/brush': ('Quê hương thư pháp', 'Vương Hi Chi, \'Thư thánh\' của Trung Hoa, sinh ra ở Lâm Nghi; nét bút phóng khoáng của ông đã được noi theo suốt hơn một nghìn năm. Đền tưởng niệm và các lễ hội thư pháp trong thành phố tiếp nối di sản ấy. Ở Lâm Nghi, hương mực tàu là khúc đối âm thanh nhã giữa nhịp thương mại rộn ràng.'),
  'linyi/mountain': ('Núi Mông Sơn', 'Mông Sơn, viên ngọc của dãy Nghi Mông, là một trong những ngọn núi cao nhất Sơn Đông. Rừng rậm, thác nước và bầu không khí trong lành tinh khiết đã mang lại cho núi danh xưng \'quầy oxy thiên nhiên\'. Với các lối mòn leo núi, bản làng sườn đồi và mật ong rừng, nơi đây trao cho lữ khách một chốn lánh mình yên ả.'),
  'linyi/pancake': ('Bánh xèo Nghi Mông', 'Chiếc bánh tráng mỏng tang làm từ ngô và ngũ cốc là lương thực chính bao đời của cư dân vùng núi Nghi Mông. Nướng trên phiến đá nóng, bánh theo truyền thống được cuốn quanh cọng hành lá tươi mà ăn. Dẻo dai và chắc bụng, thứ bánh này là người bạn đồng hành trung thành qua cuộc sống gian khó của những bản làng miền núi.'),
  'cangzhou/lion': ('Sư tử sắt Thương Châu', 'Đứng vững hơn một nghìn năm, con sư tử gang khổng lồ là niềm kiêu hãnh của Thương Châu và là một trong những hiện vật sắt cổ lớn nhất Trung Quốc. Người dân gọi nó là \'tiếng gầm trấn biển\', tương truyền được đúc để chế ngự nước lũ. Thành phố ôm ấp biểu tượng của mình như một vị thần hộ mệnh.'),
  'cangzhou/martial': ('Võ thuật Thương Châu', 'Thương Châu lừng danh là \'quê hương võ thuật\' của Trung Quốc; những môn phái cương mãnh như Bát Cực Quyền đã phát triển tại đây. Thuở trước, phần lớn các tiêu sư hộ tống đoàn thương buôn đều xuất thân từ thành phố này. Ngày nay các võ đường và giải đấu vẫn giữ cho truyền thống ấy hiên ngang.'),
  'cangzhou/canal': ('Đại Vận Hà', 'Đại Vận Hà nối Bắc Kinh với Hàng Châu chảy xuyên qua lòng Thương Châu, và suốt nhiều thế kỷ thành phố giàu lên nhờ thương mại trên kênh đào. Những bến tàu cổ và các khu phố ven bến vẫn in dấu thời vàng son ấy. Công viên dọc kênh nay là điểm dạo chơi yêu thích mỗi buổi chiều tối.'),
  'cangzhou/jujube': ('Táo tàu vàng', 'Táo tàu \'tơ vàng\' vỏ mỏng, ngọt như mật của Thương Châu được tôn là vua của các loại quả khô. Tên gọi bắt nguồn từ những sợi tơ vàng óng kéo dài từ phần thịt quả khi bẻ đôi. Mùa thu hoạch, các vườn cây nhuộm đỏ rực, và trà táo tàu cùng các món ngọt từ táo là hương vị không thể thiếu của bàn ăn địa phương.'),
  'nantong/textile': ('Thành phố Dệt may', 'Câu chuyện dệt may hiện đại của Nam Thông bắt đầu với những nhà máy bông do nhà công nghiệp Trương Kiển sáng lập. Ngày nay thành phố là thủ phủ dệt may gia dụng của Trung Quốc, với chăn ga và rèm cửa vươn tới thị trường toàn cầu. Văn hóa dệt còn sống mãi trong nghệ thuật vải in hoa xanh-trắng của địa phương.'),
  'nantong/mountain': ('Núi Lang', 'Vươn lên nơi Trường Giang đổ ra biển, ngọn Lang Sơn năm đỉnh là núi thiêng của cả vùng. Khách hành hương và du khách leo những bậc thang dẫn lên ngôi chùa Phật giáo hàng trăm năm tuổi trên đỉnh. Từ nơi cao ấy, khoảnh khắc dòng sông vĩ đại hòa vào biển cả trải rộng dưới chân bạn.'),
  'nantong/kite': ('Diều sáo', 'Những cánh diều \'bản diêu\' của Nam Thông vi vu khắp bầu trời nhờ hàng chục chiếc còi nhỏ gắn trên khung; gió càng mạnh, âm thanh càng dâng lên như một dàn nhạc. Nghề làm diều sáo này là tinh hoa thủ công lâu đời, được truyền qua nhiều thế hệ và được các nghệ nhân địa phương nâng niu gìn giữ.'),
  'nantong/school': ('Cái nôi giáo dục', 'Nhà công nghiệp và nhà cải cách Trương Kiển đã dâng trọn gia sản cho quê hương: ông mở trường học hiện đại, thư viện và bảo tàng đầu tiên ở Trung Quốc do chính một người Trung Quốc sáng lập. Nhờ đó thành phố trở thành nơi tiên phong về giáo dục. Lý tưởng \'thực nghiệp cứu quốc\' của ông vẫn sống trong ký ức người dân nơi đây.'),
  'taizhou/opera': ('Mai Lan Phương', 'Gốc gác của Mai Lan Phương, bậc thầy huyền thoại của kinh kịch, bắt nguồn từ Thái Châu; nét thanh nhã ông mang đến cho các vai nữ đã giới thiệu môn nghệ thuật này với thế giới. Công viên tưởng niệm và bảo tàng kể chuyện đời ông qua những bộ trang phục và ảnh sân khấu. Làn điệu kinh kịch vẫn còn vang vọng trong các công viên của thành phố.'),
  'taizhou/tea': ('Trà sáng', 'Thái Châu bắt đầu ngày mới với \'tảo trà\': bánh bao hấp, đậu khô thái sợi mảnh và canh chả cá được dọn ra cùng ấm trà đậm. Trà sáng ở đây không bao giờ vội vã — hàng xóm gặp nhau trong quán trà và thong thả bước vào ngày mới bằng những câu chuyện trò.'),
  'taizhou/boat': ('Lễ hội đua thuyền Cần Đồng', 'Mỗi độ xuân về, hàng trăm con thuyền tụ hội trên vùng đầm nước của trấn Tần Đồng; các tay chèo đua theo nhịp trống, bọt nước trắng xóa tung lên mỗi khi mái sào chạm mặt nước. Lễ hội đua thuyền hàng trăm năm tuổi này là ngày hội tưng bừng nhất của văn hóa thủy trấn và đã được ghi vào danh mục di sản quốc gia.'),
  'taizhou/meatball': ('Thịt viên đầu sư tử', 'Viên thịt heo to tròn, mềm mượt mang tên \'đầu sư tử\' là món kinh điển của ẩm thực Hoài Dương, gọi vậy vì kết cấu bông xốp gợi nhớ bờm sư tử. Được om lửa liu riu suốt nhiều giờ, viên thịt tan ngay trong miệng. Phiên bản thêm gạch cua là món đãi khách sang trọng nhất của bàn tiệc mùa thu.'),
  'jinhua/ham': ('Giăm bông Kim Hoa', 'Giăm bông Kim Hoa được ủ chín theo phương pháp muối và phơi gió đã có hàng thế kỷ; thớ thịt đỏ sậm và hương vị đậm đà khiến nó trở thành loại giăm bông nổi tiếng nhất Trung Quốc. Món này thường được dùng để tăng chiều sâu hương vị cho các món canh và món om. Một tảng giăm bông Kim Hoa hảo hạng là kết tinh của nhiều năm kiên nhẫn.'),
  'jinhua/film': ('Phim trường Hoành Điếm', 'Hoành Điếm, thuộc vùng Kim Hoa, là phim trường ngoài trời lớn nhất thế giới, nơi dựng lên những bản sao khổng lồ của Tử Cấm Thành và các cung điện cổ. Vô số phim và phim truyền hình cổ trang được quay tại đây. Dạo quanh trường quay, du khách rất có thể chạm mặt các diễn viên trong trang phục cổ trang đầy đủ.'),
  'jinhua/cave': ('Động Song Long', 'Bước vào động Song Long — \'Đôi Rồng\' — là trải nghiệm khó quên: du khách nằm ngửa trên thuyền, lướt qua cửa đá thấp để vào trong. Bên trong mở ra một thế giới ngầm mát lạnh, điểm tô bằng thạch nhũ và măng đá. Hang động từng được ngợi ca trong ghi chép của các lữ khách thời xưa.'),
  'jinhua/bridge': ('Cầu cổ', 'Vùng quê quanh Kim Hoa, xưa gọi là Vụ Châu, điểm xuyết những cây cầu đá vòm và các thủy trấn chằng chịt kênh rạch. Những ngôi nhà tường trắng mái ngói đen soi bóng xuống mặt nước, và quán trà quây quần nơi đầu cầu. Khung cảnh ấy mang phong vị sống thanh nhã của miền Giang Nam vào hiện tại.'),
  'wuhu/park': ('Công viên giải trí Phương Đặc', 'Vu Hồ sở hữu một cụm công viên chủ đề thuộc hàng lớn nhất Trung Quốc, mang đến cho các gia đình những ngày tràn đầy phấn khích, từ tàu lượn siêu tốc đến thế giới hoạt hình. Nhờ vậy thành phố đã vươn lên thành thủ phủ giải trí của cả vùng, cuối tuần nào cũng đón từng dòng du khách từ các tỉnh lân cận.'),
  'wuhu/ironart': ('Tranh sắt', 'Trong nghệ thuật \'tranh sắt\' của Vu Hồ, sắt rèn được tôi luyện thành những bức tranh thanh thoát gợi nét bút lông; nghề thủ công khoảng ba thế kỷ tuổi này đưa hồn tranh thủy mặc vào kim loại. Bằng búa và đe, các nghệ nhân tạo hình núi non, tùng bách và chim muông. Những tác phẩm ấy là món quà độc đáo nhất của thành phố.'),
  'wuhu/rice': ('Cảng gạo', 'Trong lịch sử, Vu Hồ từng là một trong những chợ gạo lớn nhất Trung Quốc; nhờ vị trí bên Trường Giang, mùa màng của phương nam được giao thương tại đây. Những nhà kho hiện đại đã thay chỗ các phu khuân vác vác bao gạo trên bến xưa, nhưng thành phố vẫn tự hào về di sản buôn bán lúa gạo của mình.'),
  'wuhu/river': ('Cảng Dương Tử', 'Bến cảng sầm uất bên Trường Giang khiến Vu Hồ trở thành cửa ngõ mở ra thế giới của tỉnh An Huy. Dọc dòng sông, tàu hàng và cần cẩu container không lúc nào ngơi nghỉ, và từ các công viên ven bờ, ngắm nhịp sống tấp nập ấy là một thú vui. Dòng sông mang đến cho thành phố cả thương mại lẫn làn gió mát mỗi buổi chiều.'),
  'huangshan/peak': ('Hoàng Sơn', 'Với những đỉnh đá hoa cương, biển mây, tùng cổ thụ dáng kỳ và suối nước nóng, Hoàng Sơn là ngọn núi nổi tiếng nhất Trung Quốc và là di sản UNESCO. \'Tứ tuyệt\' ấy đã truyền cảm hứng cho các họa sĩ và thi nhân suốt nhiều thế kỷ. Đứng trên biển mây lúc bình minh là ký ức theo bạn suốt cuộc đời.'),
  'huangshan/village': ('Thôn Hoành', 'Hoành Thôn — ngôi làng của người Huy với tường trắng mái ngói đen, đan xen kênh nước và hồ bán nguyệt — đẹp như bước ra từ tranh vẽ và đã được UNESCO ghi danh. Bố cục làng được thiết kế mô phỏng hình dáng một con trâu. Khi sương sớm buông xuống mặt hồ, các họa sĩ lại dựng giá vẽ dọc bờ nước.'),
  'huangshan/tea': ('Trà Mao Phong', 'Được hái trên những sườn núi mờ sương, Hoàng Sơn Mao Phong là một trong những loại trà xanh nổi tiếng nhất Trung Quốc, mang tên từ những búp lá phủ lông tơ, dáng tựa đỉnh núi. Vụ hái đầu xuân được quý chuộng nhất. Chén trà để lại hương lan thoang thoảng, như thể mây núi đã dệt vào từng búp lá.'),
  'huangshan/ink': ('Mực và nghệ thuật Huy Châu', 'Vùng Huy Châu xưa từng sản xuất những thỏi mực và nghiên đá danh giá nhất Trung Hoa, được giới thư pháp săn tìm suốt nhiều thế kỷ. Những dinh thự trang hoàng bằng gỗ, gạch và đá chạm khắc cũng nảy sinh từ chính tinh thần thủ công ấy. Văn hóa Huy Châu hòa quyện mực tàu và kiến trúc trong một mỹ cảm duy nhất.'),
  'yichun/moon': ('Núi Minh Nguyệt', 'Núi Minh Nguyệt, tên có nghĩa \'Trăng Sáng\', là biểu tượng của Nghi Xuân — thành phố còn nổi tiếng với các lễ hội chủ đề trăng. Cáp treo đưa du khách lên những lối mòn ven vách đá và các đồng cỏ trên núi cao. Khi sương tan trên đỉnh, các thung lũng phía dưới ánh lên một thứ ánh sáng bàng bạc.'),
  'yichun/spring': ('Suối nước nóng', 'Suối nước nóng ở trấn Ôn Thang của Nghi Xuân giàu selen quý hiếm và từ lâu được tin là có công dụng chữa lành. Các khách sạn nghỉ dưỡng và hồ tắm ngoài trời đón khách quanh năm. Sự hòa quyện giữa không khí núi rừng và làn nước ấm nghi ngút đã đưa thành phố vào hàng những điểm nghỉ dưỡng suối khoáng được yêu thích nhất Trung Quốc.'),
  'yichun/zen': ('Thiền tông', 'Núi non Nghi Xuân thuộc những vùng đất nơi các tông phái quan trọng của Thiền tông Trung Hoa bén rễ; những ngôi chùa hàng trăm năm tuổi rải rác trong các thung lũng tĩnh lặng. Vườn trà của các nhà sư và thiền đường mời gọi du khách sống chậm lại. Tiếng chuông chùa ngân vang qua cánh rừng mờ sương.'),
  'yichun/rice': ('Đồng bằng Viên Hà', 'Đồng bằng màu mỡ của sông Viên từ lâu đã là vựa lúa của Giang Tây, những cánh đồng đủ nước năm nào cũng cho mùa gặt bội thu. Mùa thu hoạch trôi qua như ngày hội trong các làng quê. Sợi mì làm từ gạo mới và rượu gạo địa phương mang sự hào phóng của đồng bằng lên bàn ăn.'),
  'zhangzhou/narcissus': ('Hoa thủy tiên', 'Những củ thủy tiên nổi tiếng nhất Trung Quốc được trồng ở Chương Châu, và loài hoa này là vật trang trí không thể thiếu của Tết Nguyên đán. Các nghệ nhân gọt tỉa củ hoa bằng những đường cắt đặc biệt để hoa nở thành các dáng thanh nhã. Một chậu thủy tiên nở trong nhà dịp năm mới được xem là điềm lành cho cả năm sắp tới.'),
  'zhangzhou/tulou': ('Thổ lâu Khách Gia', 'Những pháo đài tròn khổng lồ bằng đất nện gọi là \'thổ lâu\' quy tụ cả một ngôi làng dưới một mái nhà và đã được UNESCO ghi danh. Tường dày vừa để phòng thủ vừa giữ mát, và nếp sống cộng đồng đã tiếp diễn trong các khoảng sân ấy suốt hàng thế kỷ. Quần thể thổ lâu nép mình giữa đồi xanh vẽ nên khung cảnh như trong truyện cổ.'),
  'zhangzhou/banana': ('Trái cây nhiệt đới', 'Vùng châu thổ ấm áp, ẩm ướt của Chương Châu cho trái ngọt quanh năm: những đồn điền chuối, rừng nhãn và vườn quýt trải dài đến tận chân trời. Trái bưởi to mọng nước của vùng cũng là món được ưa chuộng trên bàn ăn. Dù mùa nào, các chợ trái cây nơi đây cũng là bữa tiệc của sắc màu và hương thơm.'),
  'zhangzhou/coast': ('Đảo Đông Sơn', 'Với những bãi cát vàng và làng chài, đảo Đông Sơn là viên ngọc của vùng biển phương nam. Cảnh quan nổi tiếng nhất của đảo là tảng \'đá lay theo gió\' khổng lồ, chênh vênh bên mép vách đá và được kể rằng khẽ đung đưa trong làn gió. Buổi chiều tối, những con thuyền trở về bến mang theo mẻ cá tươi trong ngày.'),
  'guangzhou/tower': ('Tháp Quảng Châu', 'Vươn cao bên bờ sông Châu Giang, ngọn tháp với dáng xoắn thon thả được người dân trìu mến gọi là \'Tiểu Man Yêu\' — chiếc eo thon nhỏ. Là một trong những ngọn tháp cao nhất thế giới, công trình rực rỡ đổi màu với hàng nghìn đèn LED khi đêm xuống, trở thành vương miện hiện đại của đường chân trời Quảng Châu.'),
  'guangzhou/dimsum': ('Điểm sấm', 'Buổi sáng ở Quảng Châu bắt đầu bằng \'yum cha\': những ấm trà đậm đà được dọn cùng các xửng tre nghi ngút hơi đựng dim sum. Há cảo tôm, siu mai và bánh nướng giòn tan đồng hành cùng những cuộc trò chuyện kéo dài hàng giờ — nghi thức này được xem là linh hồn của ẩm thực Quảng Đông.'),
  'guangzhou/academy': ('Từ đường dòng họ Trần', 'Được xây vào cuối thời nhà Thanh nhờ đóng góp của các gia đình mang họ Trần, từ đường nguy nga này nổi tiếng với những mảng chạm gỗ, phù điêu đá và vô số tượng gốm sứ rực rỡ phủ kín mái nhà. Ngày nay nơi đây là bảo tàng nghệ thuật dân gian, trưng bày đỉnh cao của nghề thủ công phương Nam.'),
  'guangzhou/flower': ('Thành phố Hoa', 'Nhờ khí hậu ôn hòa, hoa ở Quảng Châu nở suốt bốn mùa, nên từ xa xưa thành phố đã được gọi là \'Hoa Thành\' — thành phố của hoa. Trước Tết Nguyên đán, những chợ hoa khổng lồ mọc lên khắp phố phường, nơi các gia đình mua cây quất và cành đào để mang may mắn về nhà đón năm mới.'),
  'wuhan/crane': ('Hoàng Hạc Lâu', 'Soi bóng xuống Trường Giang, Hoàng Hạc Lâu có lịch sử bắt nguồn từ thời Tam Quốc và là một trong những ngọn lầu nổi tiếng nhất Trung Quốc. Từng khơi nguồn cảm hứng cho những vần thơ của Thôi Hiệu và Lý Bạch, công trình đã nhiều lần bị phá hủy rồi dựng lại, nhưng hồn thơ của nó vẫn luôn vẹn nguyên.'),
  'wuhan/noodle': ('Mì khô nóng', 'Reganmian, tức \'mì nóng khô\', được làm từ sợi mì luộc dai trộn cùng sốt vừng béo ngậy, dưa muối và hành lá. Người Vũ Hán bắt đầu ngày mới với một bát mì mua từ quầy hàng ven đường; văn hóa ăn sáng ở đây quan trọng đến mức có hẳn tên riêng — \'guozao\', một lối sống thực thụ.'),
  'wuhan/duckneck': ('Cổ vịt cay', 'Cổ vịt om hàng giờ trong nước dùng thơm lừng ớt và gia vị là món ăn vặt được yêu thích nhất Vũ Hán. Vị cay tê nhè nhẹ của món ăn được gặm trực tiếp từ xương này là người bạn không thể thiếu của những buổi chuyện trò bên bờ sông và những cốc bia mát lạnh trong các buổi tối mùa hè.'),
  'wuhan/university': ('Hoa anh đào Đại học Vũ Hán', 'Mỗi độ xuân về, khuôn viên cổ kính của Đại học Vũ Hán lại chìm trong sắc hoa anh đào hồng trắng, thu hút du khách từ khắp Trung Quốc. Hoa nở bên những tòa nhà xưa trên sườn đồi Lạc Già tạo nên khung cảnh mùa xuân lãng mạn nhất của thành phố.'),
  'tianjin/eye': ('Mắt Thiên Tân', 'Dựng ngay chính giữa một cây cầu bắc qua sông Hải Hà, vòng quay khổng lồ \'Con mắt Thiên Tân\' là một trong số ít vòng đu quay trên thế giới xây trực tiếp trên dòng nước chảy. Khi cabin lên tới đỉnh, cả hai bờ sông trải ra dưới chân bạn: một bên là những mặt tiền kiểu châu Âu xưa, bên kia là các tòa tháp kính lấp lánh.'),
  'tianjin/baozi': ('Bánh bao Cẩu Bất Lý', 'Được làm từ thời nhà Thanh, bánh bao Cẩu Bất Lý là hương vị đặc trưng của Thiên Tân với lớp vỏ mỏng, nhân thịt mọng nước và những nếp gấp xếp khéo léo. Cái tên kỳ lạ nghĩa là \'chó cũng chẳng thèm để ý\' — tương truyền người sáng lập mải mê gói bánh đến mức chẳng còn thời gian trò chuyện với khách.'),
  'tianjin/crosstalk': ('Tướng thanh', 'Tướng thanh (xiangsheng) là loại hình sân khấu truyền thống trong đó hai nghệ sĩ đối đáp bằng những màn đấu khẩu chớp nhoáng, chơi chữ và nhại giọng khiến khán giả cười nghiêng ngả. Bén rễ trong các quán trà Thiên Tân, nghệ thuật này mang lại cho thành phố danh tiếng \'cái nôi của hài kịch Trung Hoa\' — và đến nay khán giả vẫn thưởng thức nó bên tách trà nóng.'),
  'tianjin/architecture': ('Khu phố kiến trúc châu Âu', 'Ngũ Đại Đạo, tức \'Năm đại lộ lớn\', lưu giữ hàng trăm biệt thự kiểu châu Âu còn lại từ thời tô giới nước ngoài. Với các phong cách Anh, Pháp, Ý đứng cạnh nhau, khu phố mang lại cho Thiên Tân biệt danh \'bảo tàng kiến trúc thế giới\' — nơi đẹp nhất khi dạo bằng xe ngựa hoặc xe đạp.'),
  'xiamen/island': ('Đảo Cổ Lãng Tự', 'Trên đảo Cổ Lãng Tự (Gulangyu) ngoài khơi Hạ Môn, xe cơ giới bị cấm hoàn toàn; những con hẻm nhỏ chỉ vang tiếng bước chân và giai điệu dương cầm. Với các tòa lãnh sự cũ và những biệt thự phủ đầy hoa giấy, hòn đảo được UNESCO công nhận là Di sản Thế giới này tựa một bảo tàng ngoài trời, chỉ cách bờ một chuyến phà ngắn.'),
  'xiamen/piano': ('Đảo Dương cầm', 'Âm nhạc phương Tây bén rễ trên đảo Cổ Lãng Tự từ thế kỷ mười chín, theo chân các nhà truyền giáo và thương nhân đến định cư. Nổi tiếng với số lượng đàn dương cầm trên mỗi hộ gia đình cao hiếm thấy, \'Đảo Dương Cầm\' gìn giữ truyền thống ấy bằng một bảo tàng piano và nhiều thế hệ nhạc sĩ tài hoa.'),
  'xiamen/egret': ('Cò trắng', 'Tên cũ của Hạ Môn là \'Lộ Đảo\', nghĩa là \'đảo cò trắng\', và đến nay những chú cò trắng thanh nhã vẫn lượn trên các bãi bờ và đầm phá của thành phố. Được chọn làm biểu tượng, loài chim này hiện diện khắp nơi, từ tượng đài đến tên đường, nhắc nhở về mối gắn bó của Hạ Môn với biển cả và thiên nhiên.'),
  'xiamen/oyster': ('Trứng chiên hàu', 'Hàu tươi trộn với trứng và bột khoai lang rồi chiên đến khi ngoài giòn trong mềm — món trứng chiên hàu này là món ăn đường phố kinh điển của vùng ven biển Mân Nam. Được dọn kèm sốt chua cay ngọt tại các chợ đêm Hạ Môn, món ăn cũng được yêu thích không kém ở Đài Loan bên kia eo biển.'),
  'harbin/ice': ('Lễ hội Băng đăng', 'Mỗi mùa đông, những khối băng khổng lồ cắt từ sông Tùng Hoa đóng băng được xếp thành cung điện, tòa tháp và cầu trượt, rực sáng muôn màu khi đêm xuống. Lễ hội Băng Tuyết Cáp Nhĩ Tân — lễ hội điêu khắc băng lớn nhất thế giới — biến thành phố giá lạnh thành xứ sở cổ tích đón hàng triệu du khách.'),
  'harbin/cathedral': ('Nhà thờ Thánh Sophia', 'Với mái vòm củ hành xanh và những bức tường gạch đỏ, Nhà thờ Thánh Sophia là công trình tráng lệ nhất còn lại từ thời đường sắt Nga ở Cáp Nhĩ Tân. Ngày nay là bảo tàng kiến trúc, nhà thờ nhìn ra một quảng trường sôi động với đàn bồ câu và các nghệ sĩ đường phố — điểm hẹn quen thuộc nhất của thành phố.'),
  'harbin/sausage': ('Xúc xích đỏ', 'Xúc xích đỏ hun khói, được sản xuất theo công thức của người Nga di cư từ hơn một thế kỷ trước, là hương vị biểu tượng của Cáp Nhĩ Tân. Mùi khói gỗ đặc trưng và vị tỏi dịu nhẹ của nó kết hợp hoàn hảo với bánh mì tươi và bia lạnh, mang cội nguồn châu Âu của thành phố lên bàn ăn.'),
  'harbin/accordion': ('Thành phố âm nhạc', 'Vĩ cầm, phong cầm và opera theo chân những người Nga di cư đến đây, biến Cáp Nhĩ Tân thành một trong những trung tâm âm nhạc phương Tây sớm nhất của Trung Quốc. Là quê hương của dàn nhạc giao hưởng tiên phong của đất nước, thành phố gìn giữ danh hiệu \'thành phố âm nhạc\' bằng liên hoan âm nhạc mùa hè lâu đời tổ chức hằng năm.'),
  'fuzhou/alley': ('Tam Phường Thất Ngõ', 'Khu \'Tam Phường Thất Hạng\' — ba phố ba, bảy ngõ — lưu giữ những ngôi nhà tường trắng, mái ngói đen từ thời Minh và Thanh. Xưa kia các bậc học giả và quan lại từng sống dọc những con hẻm đá hẹp này; ngày nay các dinh thự có sân trong trở thành quán trà và cửa hàng thủ công, giữ cho khu phố cổ luôn sống động như một bảo tàng.'),
  'fuzhou/banyan': ('Thành phố cây đa', 'Nhờ phong trào trồng cây khởi xướng từ thời nhà Tống, đường phố Phúc Châu phủ đầy những cây đa cổ thụ đứng vững qua nhiều thế kỷ. Rễ phụ của chúng buông dài như những chòm râu, tỏa bóng mát sâu giữa mùa hè oi ả — vì thế thành phố được trìu mến gọi là \'Dung Thành\', thành phố cây đa.'),
  'fuzhou/hotspring': ('Suối nước nóng', 'Những dòng suối nước nóng tự nhiên phun trào ngay giữa lòng Phúc Châu, nuôi dưỡng văn hóa tắm khoáng đã kéo dài hơn nghìn năm. Người dân ngày nay vẫn ngâm mình xua tan mệt mỏi tại các nhà tắm khu phố; tọa lạc ngay trên một kho báu địa nhiệt, Phúc Châu là một trong những \'thủ đô suối nóng\' hiếm hoi của Trung Quốc.'),
  'fuzhou/soup': ('Phật nhảy tường', 'Phật Khiêu Tường là món súp huyền thoại được hầm hàng giờ trong hũ đất từ hàng chục nguyên liệu quý như sò điệp, nấm và bào ngư. Tên gọi \'Phật nhảy tường\' bắt nguồn từ câu thơ kể rằng hương thơm của món ăn quyến rũ đến mức cả nhà sư cũng phải nhảy qua tường để nếm thử — đây được xem là vương miện của ẩm thực Phúc Kiến.'),
  'dongguan/robot': ('Công xưởng thế giới', 'Nằm giữa lòng châu thổ Châu Giang, Đông Quản là gã khổng lồ công nghiệp với các nhà máy sản xuất một phần đáng kể đồ điện tử và đồ chơi của thế giới. Những dây chuyền lắp ráp thâm dụng lao động đang dần nhường chỗ cho nhà máy thông minh và cánh tay robot — \'công xưởng của thế giới\' đang tự làm mới mình.'),
  'dongguan/basketball': ('Thành phố bóng rổ', 'Bóng rổ là niềm đam mê ở Đông Quản: hầu như khu phố nào cũng có sân chơi, cùng hệ thống đào tạo bài bản từ sân phường lên giải chuyên nghiệp. Guangdong Southern Tigers, một trong những câu lạc bộ giàu thành tích nhất giải bóng rổ Trung Quốc, đóng quân tại đây — thành phố được chính thức phong danh hiệu \'thành phố bóng rổ\'.'),
  'dongguan/keyuan': ('Khả Viên', 'Do một vị quan thời nhà Thanh xây dựng, Khả Viên nổi tiếng vì khéo léo sắp đặt đình tạ, ao nước và hành lang uốn lượn trong một không gian nhỏ gọn đến kinh ngạc. Được xếp vào bốn khu vườn cổ điển lớn của Quảng Đông, Khả Viên chưng cất trọn vẹn sự tinh tế của nghệ thuật vườn cảnh miền Nam Trung Hoa.'),
  'dongguan/cannon': ('Pháo đài Hổ Môn', 'Các pháo đài Hổ Môn từng canh giữ cửa sông Châu Giang với những dãy đại pháo. Chính trên bờ biển này năm 1839, khâm sai Lâm Tắc Từ đã tiêu hủy số thuốc phiện tịch thu, châm ngòi cho Chiến tranh Nha phiến; ngày nay các pháo đài và bảo tàng kể lại bước ngoặt ấy trong lịch sử cận đại Trung Quốc.'),
  'lanzhou/beefnoodle': ('Mì bò Lan Châu', 'Mì kéo tay Lan Châu nổi tiếng với công thức trứ danh: nước dùng bò trong veo, củ cải trắng, dầu ớt đỏ và rau mùi xanh mướt. Các nghệ nhân kéo khối bột thành từng sợi mảnh chỉ trong vài giây ngay trước mắt thực khách — bát mì nóng buổi sáng vừa là nghi thức thường nhật của thành phố, vừa là một trong những món mì lừng danh nhất Trung Quốc.'),
  'lanzhou/waterwheel': ('Guồng nước', 'Những guồng nước gỗ khổng lồ, được dựng từ thời nhà Minh để đưa nước Hoàng Hà lên ruộng đồng, đã trở thành biểu tượng của Lan Châu. Trong công viên guồng nước bên bờ sông, các bản phục dựng của kỳ quan kỹ thuật hàng thế kỷ này vẫn quay đều; tiếng kẽo kẹt chậm rãi của chúng vọng về âm thanh của những thời xa xưa.'),
  'lanzhou/statue': ('Tượng Mẹ Hoàng Hà', 'Bức tượng \'Hoàng Hà Mẫu Thân\' bên bờ sông khắc họa người mẹ tóc bồng bềnh cùng đứa bé nằm trên ngực. Người mẹ tượng trưng cho Hoàng Hà — dòng sông nuôi dưỡng nền văn minh Trung Hoa, còn đứa trẻ là nhân dân sinh ra từ dòng nước ấy. Bức tượng là lời tri ân sâu sắc nhất của Lan Châu dành cho con sông.'),
  'lanzhou/raft': ('Bè da cừu', 'Những chiếc bè làm từ da cừu thổi phồng buộc vào khung gỗ đã chở hàng hóa và hành khách xuôi ngược Hoàng Hà suốt nhiều thế kỷ. Ngày nay các bè truyền thống này đưa du khách dạo chơi dọc bờ sông Lan Châu; lướt trên dòng nước đục phù sa vẫn là trải nghiệm đậm chất bản địa nhất của thành phố.'),
  'urumqi/bazaar': ('Đại Ba-za', 'Đại Bazaar của Urumqi, với ngọn tháp lấy cảm hứng từ kiến trúc Hồi giáo và những gian chợ mái vòm, gìn giữ tinh thần giao thương của Con đường Tơ lụa. Các sạp hàng ngập tràn hoa quả sấy, gia vị, tơ lụa và dao thủ công; khi chiều buông, quảng trường lại sôi động với các màn ca múa.'),
  'urumqi/tianshan': ('Thiên Trì', 'Thiên Trì, \'Hồ Trời\', nằm dưới bóng đỉnh Bogda tuyết phủ trong dãy Thiên Sơn, nổi tiếng với làn nước xanh thẳm được rừng vân sam bao quanh. Truyền thuyết kể rằng đây là nơi Tây Vương Mẫu mở yến tiệc, và hồ là một phần của dãy Thiên Sơn được UNESCO công nhận là Di sản Thế giới.'),
  'urumqi/kebab': ('Thịt cừu xiên nướng', 'Những xiên thịt cừu xèo xèo trên than hồng được rắc thìa là và ớt bột, mùi thơm khói lan tỏa khắp các con phố Urumqi. Là biểu tượng của ẩm thực Duy Ngô Nhĩ, món thịt nướng ngon nhất khi thưởng thức ở chợ đêm cùng bánh nan nóng hổi vừa ra lò tandoor và ấm trà đậm đà.'),
  'urumqi/dance': ('Điệu múa Duy Ngô Nhĩ', 'Những điệu múa Duy Ngô Nhĩ xoay tròn theo nhịp trống và tiếng đàn rawap, dutar là tâm điểm của mọi đám cưới và lễ hội. Với cử chỉ tay uyển chuyển và những vòng xoay ngày càng nhanh, đây là nghệ thuật của niềm vui cộng đồng — khách mời luôn được kéo vào vòng tròn để cùng nhảy múa.'),
  'haikou/coconut': ('Thành phố Dừa', 'Ở Hải Khẩu, thủ phủ đảo Hải Nam, các đại lộ rợp bóng hàng dừa, nên thành phố mang biệt danh \'Da Thành\' — thành phố dừa. Những người bán hàng rong vung dao phay bổ trái dừa ướp lạnh, mời khách thứ nước giải khát tự nhiên nhất giữa cái nóng nhiệt đới.'),
  'haikou/arcade': ('Phố cổ Kỵ Lâu', 'Các phố buôn bán cổ của Hải Khẩu được tô điểm bởi những dãy nhà \'kỵ lâu\' có hàng hiên vòm, do các thương nhân Hoa kiều trở về từ Đông Nam Á xây dựng. Tầng trệt của chúng tạo thành lối đi có mái che, chắn mưa nhiệt đới và nắng gắt, khiến việc mua sắm trở nên dễ chịu suốt khoảng một thế kỷ qua.'),
  'haikou/crater': ('Miệng núi lửa', 'Ngay ngoại ô Hải Khẩu, một vùng núi lửa cổ đã trở thành công viên địa chất xanh mướt với những miệng núi lửa đã tắt và các đường hầm dung nham. Đá bazan từ những đợt phun trào xa xưa vẫn được dùng để xây nhà và tường ruộng trong các ngôi làng quanh vùng; du khách còn có thể đi bộ xuống tận đáy một miệng núi lửa.'),
  'haikou/turtle': ('Biển nhiệt đới', 'Vùng biển ấm áp, trong xanh ngoài khơi Hải Nam nuôi dưỡng các rạn san hô và thảm cỏ biển tràn đầy sức sống. Rùa biển kiếm ăn và đẻ trứng dọc những bờ biển này; nhờ các dự án bảo tồn, cảnh rùa con lũn cũn chạy về phía sóng biển đã lại trở thành hình ảnh đầy hy vọng.'),
  'luoyang/grotto': ('Hang đá Long Môn', 'Được tạc vào vách đá hai bên bờ sông Y, hang đá Long Môn lưu giữ hàng chục nghìn tượng Phật và được UNESCO công nhận là Di sản Thế giới. Khởi công từ thời Bắc Ngụy và đạt đỉnh cao dưới triều Đường, quần thể điêu khắc lên tới tuyệt tác là pho tượng Đại Phật Lô Xá Na khổng lồ với nụ cười thanh thoát.'),
  'luoyang/peony': ('Thủ phủ hoa mẫu đơn', 'Từ thời nhà Đường, Lạc Dương đã gắn liền với hoa mẫu đơn; truyền thuyết kể rằng đây là loài hoa duy nhất dám kháng lệnh nở giữa mùa đông của Võ Tắc Thiên nên bị đày về đất này. Mỗi tháng Tư, thành phố bừng lên trong lễ hội mẫu đơn rực rỡ sắc màu, tôn vinh loài hoa được truyền thống phong là \'vua của các loài hoa\'.'),
  'luoyang/whitehorse': ('Chùa Bạch Mã', 'Được sáng lập năm 68 sau Công nguyên, chùa Bạch Mã được tôn vinh là ngôi chùa Phật giáo đầu tiên của Trung Quốc. Tên chùa gợi nhớ con ngựa trắng được cho là đã thồ kinh Phật từ Ấn Độ về. Là biểu tượng cho sự du nhập của Phật giáo vào Trung Hoa, đến nay chùa vẫn là nơi thờ tự và hành hương nhộn nhịp.'),
  'luoyang/capital': ('Cố đô', 'Lạc Dương từng là kinh đô của mười ba triều đại, trong đó có nhà Hán và nhà Đường, đứng ở trung tâm lịch sử Trung Hoa. Thành phố cổ kính bên lưu vực Hoàng Hà này còn là điểm dừng phía đông của Con đường Tơ lụa; các bảo tàng và di tích nơi đây gìn giữ ký ức đế chế trải dài hàng nghìn năm.'),
  'shantou/gongfutea': ('Trà đạo Triều Sán', 'Trà công phu của vùng Triều Sán là nghệ thuật pha trà mang tính nghi lễ: những chén trà nhỏ xíu được rót đầy, uống cạn rồi lại châm theo từng vòng tỉ mỉ. Mời trà ở đây là cách bày tỏ lòng kính trọng sâu sắc nhất; bộ ba chén và những động tác tay tinh tế được truyền cẩn thận từ thế hệ này sang thế hệ khác.'),
  'shantou/beefpot': ('Lẩu bò', 'Lẩu bò Triều Sán nổi tiếng vì sự tôn thờ độ tươi: thịt bò mổ trong ngày được phân loại theo từng phần và nhúng vào nồi nước dùng trong veo chỉ trong vài giây. Mỗi lát thịt có thời gian chần chính xác riêng, sau đó chấm vào sốt sa tế bùi béo để vị ngọt tự nhiên của thịt tỏa sáng.'),
  'shantou/opera': ('Kịch Triều Châu', 'Với lịch sử trải dài nhiều thế kỷ, hí kịch Triều Châu chinh phục khán giả bằng những giai điệu thanh nhã hát bằng phương ngữ Triều Châu và trang phục thêu lộng lẫy. Theo chân người Triều Sán di cư, loại hình sân khấu này lan tỏa khắp Đông Nam Á và vẫn gắn kết cộng đồng với cội nguồn qua bao thế hệ.'),
  'shantou/harbor': ('Thành phố cảng Sán Đầu', 'Mở cửa giao thương với nước ngoài từ thế kỷ mười chín, cảng Sán Đầu trở thành cánh cửa để vô số người Triều Sán ra đi lập nghiệp ở hải ngoại. Ngày nay nhiều gia đình gốc Hoa khắp Đông Nam Á có cội rễ từ nơi đây — mối liên kết được ghi dấu trong những lá thư \'kiều phê\' mà người di cư xưa gửi về quê nhà.'),
  'baoding/mansion': ('Phủ Tổng đốc Trực Lệ', 'Nha môn Tổng đốc Trực Lệ là công đường của các vị tổng đốc cai quản Trực Lệ — tỉnh bao quanh kinh đô — dưới thời nhà Thanh. Những nhân vật quyền thế như Lý Hồng Chương và Viên Thế Khải từng nhậm chức tại đây; với các sân trong và sảnh đường được bảo tồn tốt, dinh thự là chứng tích sống động của nền cai trị địa phương thời đế chế.'),
  'baoding/donkeyburger': ('Bánh kẹp thịt lừa', '\'Lürou huoshao\', bánh kẹp thịt lừa, được làm bằng cách nhồi thịt lừa om gia vị mềm nhừ vào chiếc bánh nướng giòn vừa ra lò. Được ngợi ca trong câu nói địa phương \'trên trời có thịt rồng, dưới đất có thịt lừa\', đây là món ăn đường phố nổi tiếng nhất và là niềm tự hào của Bảo Định.'),
  'baoding/balls': ('Bóng tập dưỡng sinh', 'Bi sức khỏe Bảo Định, được xoay tròn trong lòng bàn tay, là dụng cụ luyện tập tay truyền thống chế tác từ thời nhà Minh. Những lá âm thanh bên trong phát ra hai cung bậc — một cao, một trầm — khi bi xoay; người ta tin rằng luyện tập đều đặn nuôi dưỡng sự dẻo dai của ngón tay và tâm trí tĩnh lặng, tập trung.'),
  'baoding/reeds': ('Đầm lầy Bạch Dương Điến', 'Bạch Dương Điến, một trong những vùng đất ngập nước lớn nhất miền Bắc Trung Quốc, là mê cung của hàng trăm hồ đầm nối nhau bằng những con kênh viền lau sậy. Mùa hè hoa sen nở khắp mặt nước, rừng lau rộn tiếng chim; dân làng vẫn đánh cá và cắt lau trên những chiếc thuyền mảnh — nơi đây được gọi là \'Hòn ngọc phương Bắc\'.'),
  'jilin/rime': ('Băng giá Cát Lâm', 'Trong những đêm đông, hơi nước bốc lên từ dòng Tùng Hoa không đóng băng ngưng đọng thành lớp sương muối trắng như pha lê trên cành cây ven sông. Hiện tượng mang tên \'vụ tùng\' này được xếp vào bốn kỳ quan thiên nhiên lớn của Trung Quốc; dưới nắng ban mai, hàng cây phủ bạc lấp lánh như bước ra từ truyện cổ tích.'),
  'jilin/snowboard': ('Khu nghỉ dưỡng trượt tuyết', 'Với mùa đông dài và tuyết dày, Cát Lâm là một trong những vùng thể thao mùa đông hàng đầu Trung Quốc. Các khu nghỉ dưỡng hiện đại trên những dãy núi xung quanh thu hút người trượt tuyết và trượt ván với lớp tuyết bột khô mịn; vùng đất này đã đào tạo nên phần lớn các vận động viên thế vận hội mùa đông của đất nước.'),
  'jilin/meteorite': ('Bảo tàng Thiên thạch', 'Năm 1976, một thiên thạch vỡ tung trên bầu trời Cát Lâm, tạo nên một trong những trận mưa thiên thạch đá lớn nhất từng được ghi nhận. Khối chính khổng lồ nặng hơn một tấn hiện được trưng bày tại bảo tàng thiên thạch của thành phố, nơi du khách có thể đối diện với vị khách đến từ vũ trụ này.'),
  'jilin/skate': ('Sông Tùng Hoa đóng băng', 'Khi đông về, những khúc sông Tùng Hoa lặng nước đóng băng dày và trở thành sân trượt băng ngoài trời của người dân. Người trượt băng lướt qua, các cụ già quay con quay trên băng, trẻ em đua xe trượt tuyết — trong những tháng lạnh giá, bờ sông là nơi tụ họp vui nhộn nhất Cát Lâm.'),
  'ordos/khan': ('Lăng mộ Thành Cát Tư Hãn', 'Lăng Thành Cát Tư Hãn trên thảo nguyên Ordos là đền thờ tưởng niệm vị đại hãn, với ba mái vòm mô phỏng hình lều Mông Cổ. Suốt nhiều thế kỷ, các thủ hộ Darhad vẫn giữ ngọn lửa nghi lễ và dâng lễ vật tại đây, khiến lăng trở thành một trong những thánh địa thiêng liêng nhất của văn hóa Mông Cổ.'),
  'ordos/cashmere': ('Len Cashmere', 'Những đàn dê dạn dày trước mùa đông khắc nghiệt của thảo nguyên Ordos cho lớp lông tơ mịn tạo nên loại cashmere thuộc hàng tốt nhất thế giới. Thứ sợi được mệnh danh \'vàng mềm\' này đã đưa thành phố thành một trung tâm sản xuất cashmere toàn cầu, biến truyền thống chăn nuôi du mục thành ngành công nghiệp xa xỉ hiện đại.'),
  'ordos/sanddune': ('Cồn cát biết hát', 'Những cồn cát khổng lồ của sa mạc Kubuqi phát ra tiếng ù trầm vang khi bạn trượt xuống sườn cát — vì thế chúng được gọi là \'cát biết hát\'. Du khách vượt cồn cát bằng đoàn lạc đà hoặc lướt ván trên cát; khi hoàng hôn nhuộm cát thành sắc vàng óng, sa mạc hóa thành một bài thơ tĩnh lặng.'),
  'ordos/yurt': ('Lều Yurt Mông Cổ', 'Lều Mông Cổ tròn phủ nỉ trắng được thiết kế để đứng vững trước gió thảo nguyên nhưng vẫn dễ dàng tháo dỡ cho những cuộc thiên di. Cửa lều quay về hướng nam, bếp lửa ở trung tâm là trái tim của đời sống gia đình; nghỉ đêm trong một chiếc lều trên thảo nguyên Ordos là cách tuyệt vời nhất để nếm trải lòng hiếu khách du mục.'),
  'jining/confucius': ('Đền thờ Khổng Tử', 'Khúc Phụ, thuộc Tế Ninh, là nơi sinh của bậc đại hiền triết Khổng Tử. Khổng Miếu thờ ngài, Khổng Phủ nơi hậu duệ sinh sống và Khổng Lâm — khu mộ gia tộc rợp bóng cây — cùng được UNESCO công nhận là Di sản Thế giới; những sân bách cổ thụ và bia đá nghìn năm là chứng nhân lặng lẽ của hơn hai thiên niên kỷ tôn kính.'),
  'jining/barge': ('Đại Vận Hà', 'Là bến cảng sầm uất trên Đại Vận Hà nối Bắc Kinh với Hàng Châu, Tế Ninh thịnh vượng suốt nhiều thế kỷ nhờ thuyền chở lương thực và dòng thương nhân tấp nập. Giao thương đường thủy mang lại cho thành phố sự giàu có và văn hóa bến cảng sôi động; các đoạn phía nam của tuyến kênh vĩ đại này ngày nay vẫn chuyên chở hàng hóa.'),
  'jining/sword': ('Các anh hùng Lương Sơn', 'Trong tiểu thuyết kinh điển \'Thủy Hử\', 108 vị anh hùng bị quan lại tham nhũng hãm hại tụ nghĩa trên vùng đồi Lương Sơn được đầm lầy bao quanh. Dưới sự dẫn dắt của Tống Giang, những hảo hán này chiến đấu vì người nghèo chống lại cường quyền. Ngày nay Lương Sơn đón du khách với các điểm tham quan tái hiện những cảnh tượng huyền thoại của tiểu thuyết.'),
  'jining/fishnet': ('Hồ Vi Sơn', 'Hồ Vi Sơn, một trong những hồ nước ngọt lớn nhất miền Bắc Trung Quốc, mỗi mùa hè lại được phủ kín bởi những cánh đồng sen trải dài tới chân trời. Các gia đình ngư dân buông lưới theo phương pháp truyền qua bao thế hệ, sống theo nhịp điệu của hồ; ẩm thực địa phương tôn vinh cá tươi và ngó sen giòn ngọt.'),
  'langfang/culture': ('Trung tâm Văn hóa Con đường Tơ lụa', 'Nằm giữa Bắc Kinh và Thiên Tân, trung tâm văn hóa hiện đại đồ sộ của Lang Phường quy tụ các triển lãm chủ đề Con đường Tơ lụa, nghệ thuật biểu diễn và nghề thủ công dưới một mái nhà. Lấy cảm hứng từ thẩm mỹ của những tuyến lạc đà xưa, công trình tượng trưng cho vai trò cầu nối văn hóa của thành phố giữa hai đại đô thị.'),
  'langfang/furniture': ('Thành phố Nội thất', 'Huyện Hương Hà thuộc Lang Phường là một trong những trung tâm sản xuất và buôn bán đồ nội thất lớn nhất Trung Quốc. Các cửa hàng trưng bày và xưởng chế tác trải dài hàng cây số, cung cấp đủ mọi phong cách từ mộc gỗ hồng cổ điển đến thiết kế hiện đại — nhiều gia đình khắp miền Bắc Trung Quốc tìm về đây khi sắm sửa tổ ấm.'),
  'langfang/tunnel': ('Địa đạo Chiến tranh Cổ đại', 'Dọc vùng biên giới xưa giữa nhà Tống và nước Liêu phương bắc, những mạng lưới địa đạo phòng thủ bí mật đã được đào sâu trong lòng đất. Tồn tại khoảng một nghìn năm, các đường hầm xây gạch với lỗ thông hơi và phòng mai phục này là chứng nhân dưới lòng đất của những cuộc chiến biên ải cổ xưa.'),
  'langfang/themepark': ('Công viên \'Đệ nhất Thành\'', '\'Thiên Hạ Đệ Nhất Thành\' — \'thành trì số một dưới gầm trời\' — là công viên chủ đề khổng lồ tái hiện nguy nga những bức tường thành và cổng thành của Bắc Kinh xưa. Với hội chùa, các màn biểu diễn truyền thống và kiến trúc cổ điển, nơi đây đưa các gia đình vào chuyến du hành về quá khứ đế đô.'),
  'yancheng/salt': ('Diêm Thành', 'Tên gọi Diêm Thành có nghĩa là \'thành phố muối\': suốt nhiều thế kỷ, các ruộng muối ven biển nơi đây đã làm đầy ngân khố triều đình. Muối thu được từ việc phơi nước biển dưới nắng đã định hình vận mệnh thành phố, và di sản ấy vẫn sống trong các bảo tàng, địa danh và truyền thuyết địa phương ngày nay.'),
  'yancheng/crane': ('Sếu đầu đỏ', 'Vùng đất ngập nước ven biển Diêm Thành là bãi trú đông lớn nhất thế giới của sếu đầu đỏ hoang dã. Là biểu tượng của trường thọ và thanh cao trong văn hóa Trung Hoa, loài chim uy nghi này di cư từ phương bắc về đây mỗi mùa đông; dáng bay chậm rãi của chúng trên những cánh đồng lau khiến người yêu thiên nhiên mê đắm.'),
  'yancheng/elk': ('Hươu Père David', 'Hươu milu từng tuyệt chủng trong tự nhiên ở Trung Quốc, chỉ còn sống sót trong các công viên ở nước ngoài. Được đưa trở lại khu bảo tồn Đại Phong ở Diêm Thành, loài hươu này đã sinh sôi mạnh mẽ; ngày nay đàn milu lớn nhất thế giới tự do rong ruổi trên những đồng cỏ ngập nước ven biển — một kỳ tích của công tác bảo tồn.'),
  'yancheng/wetland': ('Đất ngập nước ven biển', 'Các bãi triều dọc bờ Hoàng Hải tạo thành trạm dừng chân khổng lồ cho chim di cư, được UNESCO ghi danh Di sản Thế giới. Hàng triệu con chim ven bờ trên tuyến di cư Đông Á - Úc châu nghỉ ngơi và kiếm ăn tại đây, khiến những bãi bùn rợp tiếng vỗ cánh mỗi mùa xuân và mùa thu.'),
  'huzhou/brush': ('Bút Hồ', 'Bút Hồ sản xuất tại Hồ Châu là loại bút lông danh giá nhất Trung Hoa, một trong \'văn phòng tứ bảo\' của thư pháp. Ngòi bút làm từ lông dê, thỏ và chồn phải trải qua hàng chục công đoạn tỉ mỉ để vừa nhọn vừa đàn hồi — với các nhà thư pháp, giá trị của chúng không gì sánh được.'),
  'huzhou/bamboo': ('Rừng trúc An Cát', 'Những cánh rừng trúc phủ kín đồi núi huyện An Cát đung đưa trong gió như một biển xanh bất tận. Từng là bối cảnh cho những thước phim khó quên trong \'Ngọa hổ tàng long\', rừng trúc nơi đây chào đón du khách với không khí mát lành, các lối mòn đi bộ và nền ẩm thực địa phương xoay quanh măng trúc non.'),
  'huzhou/silkworm': ('Tằm tơ', 'Bên bờ nam Thái Hồ, Hồ Châu là trái tim của nghề tơ tằm dâu suốt hàng nghìn năm. Hệ thống canh tác truyền thống kết hợp vườn dâu với ao cá nay được vinh danh là di sản nông nghiệp toàn cầu; lụa Hồ Châu trong lịch sử từng dệt nên xiêm y cho hoàng đế và cung đình.'),
  'huzhou/whitetea': ('Trà trắng An Cát', 'Trà trắng An Cát thực ra là một loại trà xanh, làm từ giống trà quý hiếm có lá non mùa xuân nhạt màu đến mức gần như trắng. Được yêu thích nhờ vị ngọt dịu, tươi mát và ít chát, mùa thu hái ngắn ngủi khiến nó trở thành một trong những loại trà được săn lùng nhất Trung Quốc.'),
  'quzhou/go': ('Cờ vây', 'Truyền thuyết kể về một tiều phu trên núi Lạn Kha mải mê xem hai vị tiên đánh cờ vây đến quên cả thời gian; khi sực tỉnh, cán rìu của ông đã mục nát tự bao giờ. Nhờ câu chuyện ấy, Cù Châu được tôn là thánh địa của cờ vây, và môn cờ chiến lược cổ xưa này được gìn giữ nồng nhiệt khắp thành phố.'),
  'quzhou/peaks': ('Núi Giang Lang', 'Ba cột đá khổng lồ của núi Giang Lang vươn thẳng lên trời từ giữa rừng xanh thẳm. Là mẫu mực nổi bật của địa mạo \'đan hà\' — sa thạch đỏ, ngọn núi được UNESCO ghi danh Di sản Thế giới; đi bộ trong khe hẹp giữa các cột đá là trải nghiệm choáng ngợp đến nghẹt thở.'),
  'quzhou/ponkan': ('Quýt đường Cù Châu', 'Quýt ponkan trồng trên những sườn đồi ôn hòa của Cù Châu nổi tiếng với vỏ dễ bóc và múi ngọt như mật. Cuối thu, các vườn quýt nhuộm sắc cam rực rỡ; mùa thu hoạch đưa các gia đình quây quần giữa vườn cây, và trái quýt trở thành niềm vui trên mâm cơm mùa đông khắp vùng.'),
  'quzhou/cake': ('Bánh nướng Cù Châu', 'Bánh nướng Cù Châu được làm bằng cách áp những miếng bột lên men vào thành trong nóng rực của lò nướng hình thùng. Bên dưới lớp vỏ giòn phủ vừng ẩn giấu phần nhân đậm đà; hàng người xếp trước lò bánh mỗi sáng cho thấy người dân yêu quý khởi đầu ngày mới này đến nhường nào.'),
  'huainan/tofu': ('Cái nôi của đậu phụ', 'Tương truyền đậu phụ ra đời thời nhà Hán, khi các nhà luyện đan của Hoài Nam vương Lưu An trên núi Bát Công lần đầu làm đông sữa đậu nành. Được phát minh tại đây khoảng hai nghìn năm trước, món ăn khiêm nhường này đã lan tỏa khắp ẩm thực thế giới; Hoài Nam tôn vinh di sản ấy bằng lễ hội đậu phụ tổ chức hằng năm.'),
  'huainan/coalmine': ('Thành phố than đá', 'Được xây dựng trên những vỉa than trù phú, Hoài Nam từ lâu là một trong những căn cứ năng lượng của miền Đông Trung Quốc. Các mỏ than và nhà máy điện cung cấp điện cho cả vùng, trong khi thành phố cũng đang biến những khu mỏ cũ thành hồ nước và công viên, hướng di sản công nghiệp về một tương lai xanh hơn.'),
  'huainan/oldtown': ('Cổ thành Thọ Huyện', 'Cổ thành Thọ Huyện là một trong những đô thị hiếm hoi ở Trung Quốc còn giữ nguyên vẹn tường thành từ thời nhà Tống. Những bức tường gạch dày và cổng vòm thậm chí từng che chở thành khỏi lũ lụt; các con phố xưa bên trong tường thành lưu giữ dấu tích của nước Sở cổ đại, vương quốc từng đặt kinh đô cuối cùng tại đây.'),
  'huainan/classic': ('Hoài Nam Tử', 'Hoài Nam Tử là bộ kinh điển triết học do các học giả quy tụ tại phủ của Lưu An, Hoài Nam vương thời nhà Hán, biên soạn. Hòa quyện tư tưởng Đạo gia, vũ trụ luận và thuật trị quốc, tác phẩm còn lưu truyền đến ngày nay những truyền thuyết được yêu mến như chuyện nữ thần Nữ Oa vá trời.'),
  'jingdezhen/porcelain': ('Thủ phủ gốm sứ', 'Cảnh Đức Trấn đã nung sứ hơn một nghìn năm; là trung tâm của các lò quan, nơi đây từng dâng những tác phẩm tinh xảo nhất lên triều đình. Cao lanh — nguyên liệu cốt lõi của đồ sứ — lấy tên từ làng Cao Lĩnh gần đó, và ngày nay thành phố vẫn thu hút các nghệ sĩ gốm sứ từ khắp thế giới.'),
  'jingdezhen/kiln': ('Lò gốm cổ', 'Tại khu di sản Cổ Diêu, các lò nung củi truyền thống và xưởng thủ công vẫn gìn giữ kỹ thuật xưa. Từ lò rồng trải dài trên sườn đồi đến lò hình quả trứng, du khách được chứng kiến hành trình thử lửa của đồ sứ, trong khi các nghệ nhân chuốt gốm, tráng men và vẽ hoa văn ngay trước mắt mọi người.'),
  'jingdezhen/bluewhite': ('Gốm sứ thanh hoa', '\'Thanh hoa\' — những họa tiết xanh cobalt vẽ dưới men trên nền sứ trắng tinh — là chữ ký lừng danh thế giới của Cảnh Đức Trấn. Đạt độ hoàn mỹ vào thời Nguyên và Minh, đồ sứ thanh hoa theo Con đường Tơ lụa và các tuyến hải thương lan khắp thế giới, trở thành niềm đam mê sưu tầm của các cung đình châu Âu.'),
  'jingdezhen/painting': ('Tranh vẽ trên gốm', 'Ở Cảnh Đức Trấn, đồ sứ không chỉ là vật dụng mà còn là tấm toan: các nghệ nhân dùng những cây cọ mảnh nhất vẽ nên phong cảnh, chim muông và cả những câu thơ. Các kỹ thuật như vẽ dưới men và tráng men màu được truyền qua nhiều thế hệ; tác phẩm có chữ ký của danh sư được sưu tầm trân trọng như tranh quý.'),
  'jian/jinggang': ('Núi Tỉnh Cương', 'Dãy Tỉnh Cương Sơn mờ sương là nơi căn cứ địa nông thôn đầu tiên của cách mạng Trung Quốc được thành lập năm 1927. Ngày nay là trái tim của \'du lịch đỏ\', dãy núi đón du khách với các di tích lịch sử bên cạnh thác nước, rừng trúc và biển mây cuồn cuộn dưới các đỉnh non.'),
  'jian/torch': ('Ngọn lửa cách mạng', 'Câu nói \'một đốm lửa nhỏ có thể thiêu cháy cả thảo nguyên\' khắc họa cách cách mạng lan từ vùng núi này ra khắp đất nước. Các đài tưởng niệm, bảo tàng và những sở chỉ huy được bảo tồn trong vùng Tỉnh Cương ghi lại cuộc đấu tranh gian khổ thuở ấy; người đi bộ đường dài men theo các lối mòn lịch sử giữa khung cảnh núi non hùng vĩ.'),
  'jian/academy': ('Học viện Bạch Lộ Châu', 'Được sáng lập thời nhà Tống trên một hòn đảo giữa sông Cám, thư viện Bạch Lộ Châu đã đào tạo học giả suốt nhiều thế kỷ — trong đó có người anh hùng dân tộc Văn Thiên Tường. Những khoảng sân yên tĩnh được dòng sông ôm trọn bốn bề vẫn là ký ức thanh nhã về truyền thống giáo dục cổ điển của Trung Hoa.'),
  'jian/pine': ('Thông Tỉnh Cương', 'Những cây tùng bám rễ trên các sườn dốc cheo leo của Tỉnh Cương Sơn vẫn hiên ngang giữa sương mù và gió núi. Lớn lên bằng cách bám vào đá trần, chúng trở thành biểu tượng của nghị lực và hy vọng; bóng tùng vươn lên từ biển mây lúc bình minh là cảnh tượng khó lòng quên được.'),
  'nanping/wuyi': ('Dãy núi Vũ Di', 'Núi Vũ Di, với vách đá đỏ thẫm, thung lũng xanh và dòng suối trong vắt uốn lượn giữa chúng, được UNESCO công nhận là di sản kép về cả thiên nhiên lẫn văn hóa. Những bài khắc trên vách đá cổ, các đồi chè bậc thang và dấu tích những thư viện của Chu Hi đưa dãy núi vào cả dòng chảy lịch sử tư tưởng Trung Hoa.'),
  'nanping/rocktea': ('Trà đá Vũ Di', 'Đại Hồng Bào, \'Chiếc áo bào đỏ lớn\', là vương miện của dòng \'trà đá vách\' — các loại oolong mọc trên nền đất giàu khoáng chất của vách núi Vũ Di. Lá hái từ những cây trà mẹ trăm tuổi trên vách đá từng được bán với giá huyền thoại; hương vị rang đậm, sâu lắng của trà được giới yêu trà kính trọng nhắc đến.'),
  'nanping/bambooraft': ('Bè tre Cửu Khúc', 'Suối Cửu Khúc len lỏi qua các vách đá đỏ của núi Vũ Di với chín khúc quanh ngoạn mục. Ngồi trên bè tre do người lái đò chống sào điều khiển, du khách trôi qua những cỗ quan tài hình thuyền bí ẩn được táng cao trên vách núi từ ngàn xưa và ngắm cảnh sắc đổi thay sau mỗi khúc quanh.'),
  'nanping/scholar': ('Chu Hy', 'Chu Hi, bậc đại sư của Tân Nho giáo, đã dành phần lớn cuộc đời quanh vùng núi Vũ Di, lập thư viện và đào tạo môn sinh tại đây. Học thuyết diễn giải lại tư tưởng Khổng Tử của ông đã định hình nền giáo dục và khoa cử của Trung Quốc cùng Đông Á suốt nhiều thế kỷ.'),
  'shenzhen/skyscraper': ('Tòa nhà chọc trời', 'Bốn mươi năm trước còn là làng chài, Thâm Quyến đã hóa thành rừng nhà chọc trời sau khi được chọn làm đặc khu kinh tế đầu tiên của Trung Quốc. Đường chân trời với tòa tháp Bình An vươn tới tận mây là biểu tượng cho nhịp độ của thời kỳ cải cách — người dân nói về "tốc độ Thâm Quyến", những tầng lầu mọc lên chỉ sau một đêm.'),
  'shenzhen/chip': ('Thành phố công nghệ', 'Trong chợ điện tử Hoa Cường Bắc, chip, bo mạch và linh kiện drone chảy từ quầy này sang quầy khác; những gã khổng lồ như Tencent, Huawei và DJI đều lớn lên từ thành phố này. Ở "Thung lũng Silicon của Trung Quốc", ý tưởng biến thành nguyên mẫu chỉ trong vài ngày — Thâm Quyến là thủ đô thế giới của các startup phần cứng.'),
  'shenzhen/miniature': ('Cửa sổ thế giới', 'Công viên chủ đề Cửa sổ Thế giới quy tụ mô hình thu nhỏ của những công trình nổi tiếng toàn cầu, từ tháp Eiffel đến kim tự tháp. Bạn có thể dạo bước qua các châu lục chỉ trong một buổi chiều; tòa "Eiffel" riêng của công viên thắp sáng mỗi đêm, gói trọn tinh thần vui tươi và đầy tham vọng của Thâm Quyến.'),
  'shenzhen/mangrove': ('Vịnh Thâm Quyến', 'Những cánh rừng ngập mặn của vịnh Thâm Quyến, trải dài dưới chân các tòa nhà chọc trời, là điểm dừng chân quan trọng của các loài chim trên đường di cư. Cò trắng và chim ven bờ kiếm ăn trên bãi bùn, trong khi lối đi dạo của công viên ven biển cho cư dân đô thị một khung cảnh hiếm có: thiên nhiên và đại đô thị sánh vai nhau.'),
  'xian/terracotta': ('Đội quân đất nung', 'Hàng nghìn binh sĩ đất nung canh giữ lăng mộ hoàng đế Tần Thủy Hoàng được những người nông dân đào giếng tình cờ phát hiện năm 1974. Gương mặt mỗi người lính đều khác nhau; xếp thành hàng ngũ lặng im, đội quân này phô bày quyền lực của một vị hoàng đế khao khát trường sinh, và thường được gọi là kỳ quan thứ tám của thế giới.'),
  'xian/citywall': ('Tường thành Tây An', 'Tường thành thời Minh của Tây An là bức tường thành được bảo tồn nguyên vẹn nhất Trung Quốc, thân tường đồ sộ ôm trọn khu phố cổ trong một hình chữ nhật liền mạch. Thuê xe đạp đạp một vòng trên mặt thành là trải nghiệm kinh điển của Tây An; từ các vọng lâu, thành phố hiện đại và kinh đô cổ xưa cùng hiện diện trong một khung hình.'),
  'xian/drumtower': ('Tháp Chuông', 'Tháp Chuông thời nhà Minh sừng sững ngay chính giữa thành phố đánh dấu trái tim của kinh đô cổ; tiếng chuông của nó xưa kia từng báo giờ trong ngày. Cùng với Tháp Trống kề bên và những con phố ẩm thực của khu phố người Hồi phía sau, nơi đây tạo nên quảng trường sôi động nhất trong những đêm Tây An.'),
  'xian/roujiamo': ('Nhục giáp mô', 'Thịt hầm nhiều giờ với gia vị, nhồi vào chiếc bánh mì nướng giòn — vì thế mà roujiamo được gọi là "hamburger Trung Hoa". Món ăn đường phố cổ xưa này của vùng Thiểm Tây hợp hoàn hảo với nhịp sống hối hả của kinh đô Con đường Tơ lụa: cầm gọn trong một tay, chỉ hai miếng cắn là bạn đã nối liền với truyền thống ẩm thực nghìn năm.'),
  'suzhou/garden': ('Viên lâm Tô Châu', 'Những khu vườn cổ điển của Tô Châu là tuyệt tác tái hiện thiên nhiên trong một không gian nhỏ bằng non bộ, ao nước và đình tạ; những khu vườn đẹp nhất đã được UNESCO công nhận là Di sản Thế giới. Mỗi ô cửa sổ được đóng khung như một bức tranh, và dạo bước trong vườn tựa như mở dần một cuộn tranh thay đổi theo từng bước chân.'),
  'suzhou/watertown': ('Thị trấn nước', 'Với những con kênh, cầu đá cong và những ngôi nhà quét vôi trắng, Tô Châu được mệnh danh là "Venice của phương Đông". Dọc các con phố cổ như đường Bình Giang, dòng nước chảy ngay trước thềm nhà; ngồi thuyền lướt đi, bạn nghe tiếng đàn tỳ bà và những khúc hát dân gian vẳng ra từ các quán trà.'),
  'suzhou/embroidery': ('Tô Tú', 'Thêu Tô Châu là nghề thủ công nghìn năm tuổi, thực hiện trên lụa bằng những sợi chỉ mảnh hơn cả sợi tóc; các bậc thầy tài hoa nhất có thể thêu hai họa tiết khác nhau trên hai mặt của cùng một tấm vải. Nắm bắt được độ óng của lông mèo hay lớp vảy cá chỉ bằng cây kim, nghệ thuật này là hiện thân cho sự kiên nhẫn và tinh tế của thành phố.'),
  'suzhou/kunqu': ('Côn khúc', 'Côn khúc, được tôn vinh là mẹ của mọi loại hình hí kịch Trung Hoa, ra đời quanh vùng Tô Châu; nó nổi tiếng với những giai điệu mượt mà như nước chảy và những động tác tay thanh thoát đầy tính ước lệ. Được ghi vào danh sách di sản văn hóa phi vật thể của UNESCO, nghệ thuật này ngày nay vẫn được trình diễn trong các đình viện vườn cổ và những sân khấu nhỏ ấm cúng.'),
  'kunming/stoneforest': ('Thạch Lâm', 'Những cột đá vôi khổng lồ được nước bào mòn qua hàng triệu năm tạo nên mê cung mang tên Thạch Lâm — Rừng Đá gần Côn Minh. Người Tát Ni bản địa kể về những khối đá này qua truyền thuyết A Thi Mã: cô gái xinh đẹp hóa đá, đến nay vẫn chào đón du khách trong hình hài một cột đá nổi tiếng.'),
  'kunming/springcity': ('Thành phố mùa xuân', 'Trên cao nguyên Vân Nam, mùa đông êm dịu và mùa hè mát mẻ, vì thế Côn Minh được gọi là "Thành phố Mùa Xuân", nơi hoa không bao giờ tàn. Thành phố sở hữu một trong những chợ hoa lớn nhất châu Á, và những bó hoa tươi được bày bán ở cả các góc phố.'),
  'kunming/seagull': ('Mòng biển đầu đen', 'Mỗi mùa đông, hàng nghìn con mòng biển mỏ đỏ từ Siberia bay về, nhuộm trắng bờ hồ và công viên của Côn Minh. Cho chim ăn trên tay là nghi thức mùa lạnh được người dân yêu thích, và sự trở về của đàn mòng biển được chào đón gần như tin vui báo hiệu một mùa mới ở Côn Minh.'),
  'kunming/ricenoodle': ('Bún qua cầu', 'Bún qua cầu là món ăn đặc trưng của Vân Nam: bát nước dùng nóng bỏng được bưng ra bàn, rồi bún gạo mảnh và các nguyên liệu được thả vào ngay trước mắt bạn. Tương truyền, một người vợ mang cơm qua cây cầu trên đảo cho chồng đang dùi mài kinh sử đã nghĩ ra cách giữ nóng bát canh như thế.'),
  'jinan/spring': ('Thành phố suối', 'Ở Tế Nam, mạch nước ngầm phun trào lên mặt đất ngay giữa lòng thành phố; nổi tiếng nhất trong 72 con suối trứ danh là suối Báo Đột cuộn trào không ngớt. Tại "Thành phố Suối nguồn", nước trong vắt chảy qua cả những con ngõ của khu phố cổ, và người dân vẫn tự hào pha trà bằng nước suối.'),
  'jinan/daminglake': ('Hồ Đại Minh', 'Được nuôi dưỡng bởi những dòng suối của thành phố, hồ Đại Minh là ốc đảo đô thị viền quanh bởi liễu rủ và hoa sen. Mùa hè, thuyền nhẹ trôi giữa những thảm sen nở rộ, còn các đình tạ và quán trà ven hồ tiếp nối nhịp sống chậm rãi, thanh nhã mà Tế Nam vốn nổi danh trong văn chương Trung Hoa.'),
  'jinan/buddhamountain': ('Núi Thiên Phật', 'Hàng trăm tượng Phật đã được tạc vào sườn núi Thiên Phật qua nhiều thế kỷ, những bức phù điêu cổ nhất có từ thời nhà Tùy. Leo theo các lối mòn, du khách vừa chiêm ngưỡng những pho tượng trong hốc đá, vừa từ đỉnh núi phóng tầm mắt bao quát toàn cảnh Tế Nam, thành phố của những dòng suối.'),
  'jinan/poet': ('Nữ sĩ Lý Thanh Chiếu', 'Lý Thanh Chiếu, người được tôn vinh là nữ thi sĩ vĩ đại nhất Trung Quốc, sinh ra tại thành phố suối nguồn này vào thời nhà Tống. Những bài từ man mác buồn của bà nói về tình yêu, kiếp lưu lạc và mất mát; nhà tưởng niệm bên suối Báo Đột lưu giữ đến hôm nay thế giới róc rách tiếng nước đã sinh ra những vần thơ ấy.'),
  'ningbo/library': ('Thiên Nhất Các', 'Được xây dựng vào thời nhà Minh, Thiên Nhất Các là thư viện tư nhân cổ nhất còn tồn tại ở châu Á, do một vị quan say mê sách vở lập nên. Để bảo vệ những bản thảo quý hiếm khỏi ẩm mốc và hỏa hoạn, nơi đây được thiết kế gần như một ngôi đền của sách, với khu vườn, hồ nước và những quy tắc gia tộc nghiêm ngặt về việc ai được bước vào.'),
  'ningbo/port': ('Cảng Ninh Ba - Chu Sơn', 'Cảng Ninh Ba - Chu San là cảng nhộn nhịp nhất thế giới tính theo khối lượng hàng hóa, bờ biển của nó là rừng tàu container và những cần cẩu khổng lồ. Truyền thống hàng hải của thành phố có gốc rễ sâu xa — Ninh Ba từng là một trong những cửa ngõ xuất phát của Con đường Tơ lụa trên biển thời cổ đại.'),
  'ningbo/tangyuan': ('Thang viên', 'Bánh trôi tàu kiểu Ninh Ba là những viên bột nếp mịn màng nhân mè đen ngọt ngào; cắn một miếng, phần nhân ấm nóng tan chảy ra như một bất ngờ nhỏ. Là món ngọt biểu tượng của Tết Nguyên tiêu, hình dáng tròn trịa của nó tượng trưng cho sự sum vầy và đoàn tụ gia đình.'),
  'ningbo/seafood': ('Hải sản', 'Hướng ra biển Hoa Đông, mâm cơm Ninh Ba được dọn lên từ biển cả: cá đù vàng, cua và các loài giáp xác là nền tảng của ẩm thực nơi đây. Khẩu vị địa phương tôn thờ sự cân bằng "mặn mà - tươi ngon" — cách hấp đơn giản và ướp muối nhẹ nhàng không bao giờ lấn át hương vị tự nhiên của cá chính là dấu ấn riêng của nền ẩm thực này.'),
  'shijiazhuang/bridge': ('Cầu Triệu Châu', 'Được kiến trúc sư bậc thầy Lý Xuân xây dựng vào thời nhà Tùy, cầu Triệu Châu là cây cầu vòm đá có vai rỗng cổ nhất thế giới. Đứng vững trước lũ lụt và động đất suốt khoảng 1.400 năm, nhịp vòm thanh thoát này được giảng dạy trong sách giáo khoa như một kiệt tác kinh điển của kỹ thuật xây dựng Trung Hoa.'),
  'shijiazhuang/clifftemple': ('Núi Thương Nham', 'Trên núi Thương Nham, ngôi chùa tọa lạc trên cây cầu đá vắt giữa hai vách núi tạo nên một trong những khung cảnh ngoạn mục nhất Trung Quốc. Muốn lên đến nơi phải leo những bậc thang đá dựng đứng từ thung lũng xanh; công trình này từng là bối cảnh cho cảnh kết của bộ phim "Ngọa hổ tàng long".'),
  'shijiazhuang/redbase': ('Khu di tích Tây Bách Pha', 'Làng Tây Bách Pha gần Thạch Gia Trang từng là tổng hành dinh cách mạng trong giai đoạn cuối của cuộc nội chiến; kế hoạch kiến lập Trung Quốc mới được vạch ra ngay trong những khoảnh sân đất này. Ngày nay là một điểm dừng thiêng liêng của "du lịch đỏ", những ngôi nhà làng mộc mạc nơi đây là chứng nhân cho các quyết định lớn của lịch sử.'),
  'shijiazhuang/pharma': ('Thành phố Dược phẩm', 'Thạch Gia Trang là một trong những trung tâm sản xuất dược phẩm lớn nhất Trung Quốc, được mệnh danh là "thành phố thuốc" đặc biệt nhờ kháng sinh và nguyên liệu dược. Là một thủ phủ tỉnh trẻ lớn lên từ đầu mối đường sắt, thành phố hòa quyện bản sắc công nghiệp của mình với ngành dược và sản xuất hiện đại.'),
  'taiyuan/jincitemple': ('Chùa Tấn Từ', 'Đền Tấn Từ bên rìa Thái Nguyên là khu vườn đền thanh nhã nhất miền bắc Trung Quốc, với những dòng suối thiêng, hàng bách cổ thụ và các pho tượng thị nữ thời nhà Tống. Trong điện Thánh Mẫu bằng gỗ, mỗi bức tượng mang một nét mặt khác nhau — như thể họ đã thì thầm trò chuyện suốt nghìn năm.'),
  'taiyuan/coalcart': ('Thủ phủ Than đá', 'Núi non Sơn Tây đan dày những vỉa than, và phần lớn năng lượng của Trung Quốc được khai thác từ đây; Thái Nguyên là thủ phủ của nguồn tài nguyên ấy. Nghề mỏ đã mang lại cho thành phố nền công nghiệp, đường sắt và văn hóa cơ khí nặng; ngày nay đô thị này đang nỗ lực cân bằng di sản than đá với năng lượng sạch hơn.'),
  'taiyuan/vinegar': ('Giấm lão trần', 'Giấm lâu năm của Sơn Tây được làm bằng cách lên men chậm cao lương và ngũ cốc, quý ở màu sẫm và vị chua khói đặc trưng. Người dân địa phương rưới giấm lên mọi món ăn, từ mì sợi đến sủi cảo — ở đây giấm không phải một thứ gia vị, mà gần như là một bản sắc.'),
  'taiyuan/twinpagoda': ('Song Tháp', 'Hai ngọn tháp bát giác thời nhà Minh đứng song song ở phía đông nam thành phố đã là biểu tượng bất biến của Thái Nguyên qua nhiều thế kỷ. Những tòa tháp xây gạch phô diễn sự tinh xảo của nghề nề truyền thống, và vào mùa xuân, hoa mận nở quanh chân tháp mang đến khoảnh khắc đáng chụp ảnh nhất của chuyến thăm.'),
  'hohhot/lamatemple': ('Chùa Đại Chiêu', 'Được xây dựng vào thời nhà Minh, chùa Đại Chiêu là trái tim tâm linh của Hohhot, với báu vật lớn nhất là pho tượng Phật bằng bạc. Trung tâm Phật giáo Tây Tạng giữa thảo nguyên này mở ra một thế giới tách biệt hẳn khỏi sự ồn ào của phố thị, bao bọc trong khói hương, những bánh xe cầu nguyện và tiếng tụng kinh trầm thấp.'),
  'hohhot/dairy': ('Thủ phủ Sữa', 'Những thương hiệu sữa lớn nhất Trung Quốc đều ra đời ở Hohhot, nơi truyền thống sữa của thảo nguyên đã vươn mình thành một ngành công nghiệp hiện đại — thành phố được gọi là "thủ đô sữa". Trên bàn ăn, những món ngon Mông Cổ như trà sữa, sữa khô đóng bánh và kem sữa đặc vẫn sống hòa thuận bên các sản phẩm nhà máy.'),
  'hohhot/wrestling': ('Đấu vật Mông Cổ', 'Đấu vật Mông Cổ, gọi là bökh, là cuộc thi được yêu thích nhất của lễ hội Naadam; các đô vật bước ra sân đấu trong áo gi-lê thêu, trình diễn điệu múa đại bàng. Người chiến thắng được tán thưởng vì sự uyển chuyển không kém gì sức mạnh — trên thảo nguyên, đấu vật cùng cưỡi ngựa và bắn cung hợp thành "ba tài nghệ của đấng nam nhi".'),
  'hohhot/prairie': ('Thảo nguyên', 'Ngay bên ngoài Hohhot, thảo nguyên Mông Cổ trải dài đến tận chân trời; những đồng cỏ mùa hè gợn sóng như biển xanh, nơi đàn ngựa và bầy cừu thong dong gặm cỏ. Du khách nghỉ đêm trong lều Mông Cổ được đón tiếp bằng trà sữa và tiệc thịt cừu, và khi màn đêm buông xuống, bầu trời ngập tràn những vì sao đã bị lãng quên nơi phố thị.'),
  'sanya/resortbeach': ('Bãi biển nhiệt đới', 'Nằm ở mũi phía nam đảo Hải Nam, Tam Á là thủ đô nghỉ dưỡng nhiệt đới của Trung Quốc; bãi cát mịn như phấn và làn nước xanh ngọc của vịnh Á Long đem về cho nó danh xưng "Hawaii của Trung Quốc". Trên những bờ biển rợp bóng dừa, mùa hè kéo dài quanh năm — đây là một trong số ít bờ biển Trung Quốc có thể tắm được cả trong mùa đông.'),
  'sanya/guanyin': ('Tượng Quan Âm', 'Vươn cao 108 mét trên mặt biển ở Nam Sơn, tượng Quan Âm nằm trong số những pho tượng nữ thần cao nhất thế giới. Ba mặt tượng hướng về đất liền, biển cả và khơi xa; con đường dẫn ra chân tượng vị Bồ Tát từ bi thu hút cả những người hành hương lẫn du khách hiếu kỳ.'),
  'sanya/diving': ('Lặn biển', 'Với làn nước ấm áp trong vắt, Tam Á là thiên đường lặn biển của Trung Quốc; những rạn san hô quanh đảo Ngô Chi Châu đầy ắp cá đủ sắc màu. Người mới bắt đầu có thể lặn ở rạn nông cùng huấn luyện viên, và chỉ với chiếc ống thở, bạn cũng đã có thể ngắm nhìn khu vườn nhiệt đới dưới mặt nước.'),
  'sanya/coconutdrink': ('Dừa', 'Ở Tam Á, dừa là một phần của đời sống thường nhật: dọc các bãi biển, người bán hàng bổ quả dừa tươi bằng dao rựa rồi trao cho khách kèm chiếc ống hút. Nước dừa mát lành là liều thuốc tự nhiên nhất cho cái nóng nhiệt đới, còn nước cốt dừa nêm hương cho các món gà và món ngọt địa phương, vỏ dừa thì biến thành đồ thủ công mỹ nghệ.'),
  'yangzhou/slenderlake': ('Sấu Tây Hồ', 'Sấu Tây Hồ mang tên mình như một lời gợi nhắc duyên dáng đến hồ nổi tiếng của Hàng Châu; dải nước dài và hẹp được tô điểm bởi hàng liễu, những cây cầu trắng cong cong và các đình tạ. Từng khiến các hoàng đế nhà Thanh say đắm trong những chuyến tuần du phương nam, cảnh sắc nơi đây đến nay vẫn thanh tao như một bức tranh thủy mặc.'),
  'yangzhou/friedrice': ('Cơm chiên Dương Châu', 'Cơm chiên Dương Châu là món kinh điển vàng óng với tôm, trứng và hành lá, được đảo cho đến khi từng hạt cơm tơi rời; tên tuổi của nó sống mãi trong các nhà hàng Trung Hoa khắp thế giới. Bí quyết nằm ở sự giản dị — mỗi hạt cơm được áo một lớp trứng, nguyên liệu tươi ngon và không bao giờ tham lam chất đống.'),
  'yangzhou/morningtea': ('Trà sáng', 'Ở Dương Châu, ngày mới bắt đầu bằng nghi thức "trà sáng": trà đậm được dọn cùng bánh bao hấp, các món bánh sợi củ cải thái mỏng như giấy và sủi cảo nhân súp. Trong những quán trà cổ, bữa sáng này kéo dài hàng giờ liền — vội vàng khi thưởng thức gần như là một điều thất lễ.'),
  'yangzhou/gegarden': ('Cá Viên', 'Được một thương nhân buôn muối giàu có xây dựng, Cá Viên mang tên mình từ hình dáng của lá tre. Nét tài tình nổi tiếng nhất của khu vườn là bộ non bộ gợi tả bốn mùa bằng những loại đá khác nhau — chỉ vài bước chân, bạn đi từ mùa xuân sang mùa đông, xuyên qua đỉnh cao của nghệ thuật vườn cảnh cổ điển.'),
  'weihai/navalisland': ('Đảo Lưu Công', 'Đảo Lưu Công ngoài khơi Uy Hải từng là căn cứ của hạm đội Bắc Dương, lực lượng hải quân hiện đại của nhà Thanh, đã thất trận ngay tại đây trong cuộc chiến với hải quân Nhật Bản. Với những bảo tàng và công sự cũ, hòn đảo ngày nay kể lại một trang sử đau thương nhưng đầy bài học trong lịch sử hải quân Trung Quốc.'),
  'weihai/swan': ('Hồ Thiên Nga', 'Mỗi mùa đông, hàng trăm con thiên nga kèn từ Siberia bay về trú ngụ tại đầm phá ven biển gần Uy Hải. Những cánh chim trắng lướt qua màn sương sớm thu hút các nhiếp ảnh gia và người yêu thiên nhiên, còn dân làng chăm sóc và cho thiên nga ăn như những người hàng xóm thân thiết.'),
  'weihai/seacucumber': ('Hải sâm', 'Hải sâm nuôi trong làn nước lạnh và sạch của Uy Hải nằm trong số những sơn hào hải vị quý giá nhất của bàn ăn Trung Hoa. Được xem là rất bổ dưỡng, hải sâm được dọn trong các dịp trọng đại và là món quà biếu trang trọng; những trang trại dọc bờ biển là nguồn sinh kế quan trọng của thành phố.'),
  'weihai/cape': ('Mũi đất Trung Quốc', 'Thành Sơn Đầu, mũi đất phía đông Uy Hải, là một trong những điểm cực đông nơi đất liền Trung Quốc gặp biển — mặt trời chào đất nước này nơi đây trước tiên. Tương truyền, Tần Thủy Hoàng, vị hoàng đế đầu tiên, đã đi đến tận chốn này để tìm xứ sở trường sinh bên kia sóng nước; mũi đất còn được gọi là "nơi tận cùng của bầu trời".'),
  'handan/taichi': ('Thái Cực Quyền', 'Trấn cổ có tường thành Quảng Phủ gần Hàm Đan là nơi khai sinh hai phái Dương và Võ của thái cực quyền; bậc thầy huyền thoại Dương Lộ Thiền đã rèn luyện tại đây. Mỗi sáng, những học trò tập các bài quyền chậm rãi, uyển chuyển dưới chân tường thành và trong các sân nhà vẫn gìn giữ di sản sống động của môn võ "nhu" này.'),
  'handan/congtai': ('Đài Tùng Đài', 'Đài Tùng Đài còn lại từ nước Triệu hùng mạnh thời Chiến Quốc; đài cao nơi các vị vua xưa ngự xem lễ nghi và duyệt binh nay đứng giữa lòng một công viên. Bước lên đài, bạn phóng tầm mắt nhìn xuống hơn hai nghìn năm lịch sử của Hàm Đan trong vai trò một kinh đô cổ.'),
  'handan/idiom': ('Thành phố Thành ngữ', 'Hàm Đan là "thành phố của thành ngữ": hơn 1.500 thành ngữ Trung Hoa bắt nguồn từ những sự kiện và câu chuyện trên mảnh đất này. Nổi tiếng nhất là "Hàm Đan học bộ" — kể về kẻ bắt chước dáng đi của người khác đến mức quên mất cách đi của chính mình — thành ngữ đã khắc tên thành phố vào ngôn ngữ mãi mãi.'),
  'handan/ciporcelain': ('Gốm Từ Châu', 'Gốm Từ Châu (Cizhou) nổi tiếng với những họa tiết đen táo bạo vẽ phóng khoáng trên lớp men lót trắng — hoa lá, cá và những câu thơ được đưa lên gốm bằng nét chân chất của nghệ thuật dân gian. Sống động từ thời nhà Tống, dòng gốm này là đồ gốm của đời thường, đứng đối trọng với đồ sứ của cung đình.'),
  'daqing/oilpump': ('Mỏ dầu', 'Việc phát hiện mỏ dầu Đại Khánh đã giải phóng nước Cộng hòa Nhân dân non trẻ khỏi sự phụ thuộc vào dầu nhập khẩu; thành phố gần như mọc lên ngay trên những giếng dầu. Những chiếc máy bơm dầu vẫn chậm rãi gật gù trên đồng bằng, và Đại Khánh đi vào lịch sử với tư cách mỏ dầu lớn nhất Trung Quốc.'),
  'daqing/oilworker': ('Người sắt', 'Công nhân dầu khí Vương Tiến Hỉ được đặt biệt danh "Người Sắt" nhờ ý chí kiên cường khoan giếng trong giá rét cắt da; chuyện kể rằng ông từng nhảy xuống hố bùn, dùng chính thân mình để trộn dung dịch khoan. Bảo tàng mang tên ông cùng "tinh thần Người Sắt" vẫn giữ cho huyền thoại lập nghiệp của Đại Khánh sống mãi.'),
  'daqing/reedlake': ('Đất ngập nước', 'Giữa những giếng dầu ẩn giấu một miền hoang dã đáng kinh ngạc: các hồ lau sậy và vùng đất ngập nước mênh mông của Đại Khánh là nơi trú ngụ của sếu, thiên nga và các loài chim nước di cư. Vào mùa thu, khi những rặng lau vàng óng đung đưa trong gió, thành phố công nghiệp hóa thành một thiên đường chim chóc.'),
  'daqing/hotspring': ('Suối nước nóng', 'Quanh Đại Khánh, những dòng nước khoáng nóng trào lên từ lòng đất sâu mang đến chốn nghỉ dưỡng chữa lành trong mùa đông giá lạnh của vùng đông bắc. Huyện Lâm Điện đã nổi danh là thị trấn suối nước nóng, và ngâm mình trong những bể nước nghi ngút hơi là câu trả lời dịu dàng cho khí hậu khắc nghiệt của thành phố dầu mỏ.'),
  'zibo/bbq': ('Đồ nướng Truy Bác', 'Thịt nướng Truy Bác nổi tiếng với bộ ba: chiếc lò than nhỏ, những xiên thịt mảnh và bánh tráng mềm mỏng. Bạn tự nướng nốt xiên thịt của mình, rồi cuộn vào bánh cùng hành tươi và nước sốt — một nghi thức thân tình đã làm mưa làm gió trên mạng xã hội Trung Quốc và đưa thành phố thành hiện tượng cả nước chỉ sau một đêm.'),
  'zibo/cuju': ('Xúc cúc', 'Xúc cúc, hình thức bóng đá cổ xưa nhất thế giới, từng được chơi ở Lâm Tri, kinh đô của nước Tề cổ đại — di sản mà FIFA công nhận là cội nguồn của môn bóng đá. Trò chơi giữ quả bóng da trên không bằng chân này từng có đời sống phong phú, trải dài từ thú tiêu khiển chốn cung đình đến bài luyện tập của binh sĩ.'),
  'zibo/ceramic': ('Gốm sứ Truy Bác', 'Những lò gốm của Truy Bác đã đỏ lửa hơn một nghìn năm, đưa thành phố thành một trong những trung tâm gốm sứ lâu đời nhất miền bắc Trung Quốc. Truyền thống sản xuất trải từ đồ dùng hằng ngày đến sứ nghệ thuật vẫn sống trong các bảo tàng và xưởng gốm, còn những hội chợ gốm sứ thu hút nghệ nhân từ khắp cả nước về đây.'),
  'zibo/glass': ('Lưu ly', 'Lưu ly, được tạo hình thủ công từ thủy tinh nóng chảy đủ sắc màu, là nghề chơi đùa với ánh sáng của Truy Bác; quận Bác Sơn nổi danh là trung tâm lịch sử của nghệ thuật này. Các nghệ nhân dùng kẹp kéo và uốn khối thủy tinh rực đỏ; những hạt chuỗi, chim muông và bình hoa ra đời lấp lánh dưới nắng như tranh kính màu.'),
  'taian/mounttai': ('Núi Thái Sơn', 'Thái Sơn, đứng đầu Ngũ Nhạc, là ngọn núi linh thiêng nhất Trung Quốc; suốt nhiều thế kỷ, các hoàng đế đã cử hành nghi lễ tế tự tại đây để cáo với trời đất về vương triều của mình. Trên các vách đá của di sản UNESCO này khắc đầy bút tích của thi nhân và nhà thư pháp — mỗi phiến đá là một trang sử.'),
  'taian/sunrise': ('Ngắm bình minh trên đỉnh núi', 'Phần thưởng lớn nhất khi chinh phục Thái Sơn là ngắm mặt trời mọc trên biển mây từ đỉnh núi. Hàng nghìn người leo núi xuyên đêm để đón bình minh trên đỉnh Ngọc Hoàng; khi chân trời rực đỏ, tiếng reo hò vang lên từ đám đông cuốn phăng mọi mệt nhọc trong khoảnh khắc.'),
  'taian/stonesteps': ('Đường bậc thang đá', 'Khoảng 7.000 bậc đá dẫn lên đỉnh núi là một thử thách thể lực mà những người hành hương đã từng bước chinh phục qua nhiều thế kỷ. Đoạn dốc nhất mang tên "Thập Bát Bàn" — mười tám khúc quanh lên trời; những người phu gánh hàng lên xuống các bậc thang này mỗi ngày chính là những anh hùng thầm lặng của ngọn núi.'),
  'taian/daitemple': ('Đại Miếu', 'Đại Miếu dưới chân núi là quần thể nguy nga nơi các hoàng đế nghỉ lại và trai giới trước khi cử hành nghi lễ trên Thái Sơn. Chính điện mang kiến trúc cung đình nổi tiếng với bức bích họa khổng lồ khắc họa hành trình của thần núi Thái Sơn, còn những cây bách cổ thụ trong sân là chứng nhân của lịch sử.'),
  'lianyungang/monkey': ('Hoa Quả Sơn', 'Hoa Quả Sơn — ngọn núi Hoa Trái, quê nhà của Mỹ Hầu Vương Tôn Ngộ Không trong danh tác "Tây Du Ký" — sừng sững tại nơi đây. Muốn vào Thủy Liêm Động phải đi xuyên qua sau thác nước, và những chú khỉ macaque thật sự leo trèo trên vách đá làm nhòa đi ranh giới giữa truyền thuyết và cảnh sắc.'),
  'lianyungang/seaport': ('Cảng biển Liên Vân Cảng', 'Liên Vân Cảng là đầu mút Thái Bình Dương của cây cầu đường sắt xuyên lục địa Á - Âu; những đoàn tàu bốc hàng từ đây chạy qua Trung Á hướng về châu Âu. Được xem là cửa biển phía đông của Con đường Tơ lụa, hải cảng này tựa như sự tiếp nối hiện đại của những tuyến thương mại cổ xưa.'),
  'lianyungang/mountain': ('Núi Vân Đài', 'Những đỉnh núi hiểm trở của Vân Đài Sơn nắm giữ điểm cao nhất tỉnh Giang Tô — một ngoại lệ đáng kinh ngạc giữa vùng đất vốn nổi tiếng bởi những đồng bằng thấp. Với sườn núi phủ rừng, những ngôi chùa và các dãy núi hướng tầm nhìn ra biển, dãy núi này là chốn trốn về với thiên nhiên của thành phố.'),
  'lianyungang/crystal': ('Thủ phủ pha lê', 'Huyện Đông Hải thuộc Liên Vân Cảng là nơi họp một trong những chợ pha lê thạch anh lớn nhất thế giới. Những tinh thể trong suốt khai thác từ lòng đất nơi đây phục vụ đủ mọi lĩnh vực, từ trang sức đến nguyên liệu công nghiệp, và các sạp hàng trong chợ của thị trấn lấp lánh những viên đá rực rỡ.'),
  'maanshan/libai': ('Thi tiên Lý Bạch', 'Lý Bạch, người được tôn vinh là nhà thơ vĩ đại nhất Trung Quốc, đã sống những năm cuối đời quanh thị trấn ven sông này; mộ của ông nằm ở Đương Đồ gần đó. Công viên tưởng niệm lưu giữ dấu chân của bậc thi hào đã đưa rượu, trăng và tự do vào thơ, và Mã An Sơn tự hào gọi mình là "thành phố thi ca".'),
  'maanshan/steel': ('Thành phố thép', 'Khu liên hợp gang thép Mã Cương đã đưa Mã An Sơn thành một trong những căn cứ gang thép trọng yếu của Trung Quốc, những lò cao của nó nhả khói bên bờ Trường Giang suốt hàng chục năm. Thành phố cân bằng bản sắc công nghiệp nặng ấy với quá khứ thi vị của mình — một bên là thép nóng chảy, một bên là những vần thơ Lý Bạch.'),
  'maanshan/rivercliff': ('Thái Thạch Cơ', 'Ghềnh đá Thái Thạch, với mũi đá dựng đứng lao thẳng xuống Trường Giang, mang đến một trong những cảnh quan nên thơ nhất của dòng sông. Tương truyền, Lý Bạch đã ngã xuống nước tại đây khi vươn tay ôm lấy bóng trăng in trên mặt sông, để rồi bước vào cõi bất tử; những đình tạ và lối mòn trên ghềnh đá vẫn thì thầm kể lại câu chuyện ấy.'),
  'maanshan/moonwine': ('Trăng và Rượu', 'Trăng và rượu, hai hình tượng lớn trong thơ Lý Bạch, đến nay vẫn được tôn vinh ở Mã An Sơn, nơi tổ chức những lễ hội thơ để tưởng nhớ ông. Nâng chén bên bờ sông ngắm trăng là cách giản dị nhất để chia sẻ cùng một cảm xúc với thi nhân của nghìn năm trước.'),
  'longyan/tulou': ('Thổ lâu Vĩnh Định', 'Những tòa thổ lâu tròn khổng lồ rải rác giữa núi non Vĩnh Định là nhà pháo đài mà người Khách Gia dựng nên từ đất và gỗ, nay đã là Di sản Thế giới UNESCO. Sau lớp tường đất dày, hàng chục gia đình sống quây quần bên nhau; khói bếp bay lên từ khoảng sân chung mang theo hơi thở của hàng thế kỷ đời sống cộng đồng.'),
  'longyan/redmeeting': ('Hội nghị Cổ Điền', 'Năm 1929, Hội nghị Cổ Điền lịch sử — nơi xác lập các nguyên tắc và đường hướng của Hồng quân — đã diễn ra tại ngôi làng miền núi này thuộc Long Nham. Hội trường quét vôi trắng vẫn được bảo tồn đến ngày nay, và ngôi làng thu hút những du khách muốn tận mắt thấy một trong các bước ngoặt của lịch sử cách mạng.'),
  'longyan/hakka': ('Văn hóa Khách Gia', 'Người Khách Gia, mang cái tên có nghĩa là "những gia đình khách", có được danh xưng ấy từ hành trình di cư từ miền bắc Trung Quốc xuống phương nam để tránh chiến loạn. Giữa núi non Long Nham, họ đã gìn giữ suốt nhiều thế kỷ thứ tiếng nói riêng biệt, những món ăn như gà nướng muối và mối gắn kết gia tộc bền chặt của mình.'),
  'longyan/mountain': ('Núi Quan Trại', 'Núi Quan Trại nổi tiếng với đỉnh đá đỏ được cho là giống chiếc mũ quan tòa thời xưa; những vách đá đỏ thắm thuộc địa mạo đan hà này nằm giữa các hồ nước trong veo và những hẻm núi dựng đứng. Với bậc thang tạc vào vách đá và những chuyến thuyền trên hồ, ngọn núi được xem là viên ngọc thiên nhiên của miền nam Phúc Kiến.'),
  'sanming/danxia': ('Đan Hà Thái Ninh', 'Thái Ninh ở tây bắc Phúc Kiến là công viên địa chất UNESCO với những vách đá sa thạch đỏ, hẻm núi hẹp và hang động. Nước đã khoét nên mê cung đá này qua hàng triệu năm; ngày nay bạn có thể ngồi thuyền len lỏi qua đó, ngắm dòng suối xanh lướt giữa những bức tường đỏ thắm.'),
  'sanming/shaxian': ('Đồ ăn vặt Sa Huyện', 'Ẩm thực dân dã của Sa Huyện đã trở thành hiện tượng toàn quốc nhờ những món ăn rẻ mà no bụng. Hoành thánh vỏ mỏng như giấy, mì trộn sốt lạc và các món canh hầm được phục vụ với cùng một sự ấm áp tại những quán ăn vặt Sa Huyện có mặt trên hầu như mọi con phố ở Trung Quốc.'),
  'sanming/forest': ('Thủ phủ Xanh', 'Tam Minh là một trong những thành phố có độ che phủ rừng cao nhất Trung Quốc, núi non xanh mướt từ đỉnh đến thung lũng. Từ một thị trấn khai thác gỗ, thành phố đã chuyển hướng sang du lịch sinh thái, tự hào mang danh hiệu "thủ đô xanh" với không khí trong lành và những lối mòn xuyên rừng.'),
  'sanming/goldenlake': ('Hồ Kim', 'Kim Hồ là hồ chứa nước rộng lớn uốn lượn giữa những vách đá Đan Hà đỏ rực của Thái Ninh. Các chuyến thuyền đưa bạn qua những hẻm nước hẹp, ngang qua vách đá dựng đứng và chùa Cam Lộ xây trong hang — một cảnh quan hiếm có nơi nước gặp gỡ đá.'),
  'ningde/mudflat': ('Bãi bùn Hà Phố', 'Mỗi ngày khi thủy triều rút ở Hà Phố (Xiapu), những bãi bồi mênh mông hiện ra, lấp lánh trong ánh sáng luôn biến đổi. Ruộng rong biển, hàng hàng cọc tre và ngư dân cần mẫn nơi nước cạn đã biến bờ biển này thành điểm hẹn nổi tiếng thế giới của giới nhiếp ảnh.'),
  'ningde/whitetea': ('Bạch trà Phúc Đỉnh', 'Phúc Đỉnh là quê hương của bạch trà Trung Quốc: những búp trà phủ lông tơ ánh bạc chỉ được làm héo rồi sấy khô, không bao giờ sao. Câu nói địa phương "một năm là trà, ba năm là thuốc, bảy năm là báu vật" cho thấy loại trà thanh nhã này càng để lâu càng quý giá.'),
  'ningde/taimu': ('Núi Thái Mỗ', 'Núi Thái Mẫu vươn lên bên bờ biển với những tháp đá granit tròn trịa, khe đá hẹp và lối đi xuyên hang. Được người xưa gọi là "tiên cảnh trên biển", các lối mòn của núi len lỏi giữa những tảng đá, dẫn bạn tới điểm ngắm cảnh nơi sương mù gặp gỡ đại dương.'),
  'ningde/croaker': ('Cá đù vàng', 'Những vịnh biển kín gió Tam Đô Áo khiến Ninh Đức trở thành trung tâm nuôi cá đù vàng lớn nhất Trung Quốc. Các trại lồng bè nổi hợp thành cả một ngôi làng trên mặt nước; thịt cá trắng mềm chỉ cần hấp đơn giản đã thành món quý trên mâm cơm Phúc Kiến.'),
  'shaoguan/redcliff': ('Núi Đan Hà', 'Núi Đan Hà là khối núi sa thạch đỏ đã đặt tên cho dạng địa hình "danxia" trên toàn thế giới và được UNESCO công nhận là Di sản Thế giới. Những tháp và cột đá do gió và nước tạc nên rực lên như than hồng lúc hoàng hôn; các lối mòn quanh co cùng những chuyến du thuyền trên sông mở lối khám phá mê cung đỏ này.'),
  'shaoguan/chantemple': ('Chùa Nam Hoa', 'Chùa Nam Hoa gần Thiều Quan là nơi Huệ Năng, vị Lục Tổ của Thiền tông, truyền bá giáo pháp. Với lịch sử gần mười lăm thế kỷ, đây vẫn là trái tim thiêng liêng của Thiền phái phương Nam, nơi khách hành hương ngày nay vẫn lần theo dấu chân vị tổ sư giữa làn khói hương.'),
  'shaoguan/ancestor': ('Ngõ Châu Cơ', 'Ngõ Chu Cơ ở Nam Hùng là trạm dừng chân của các gia đình di cư từ phương Bắc thời Tống trước khi xuống định cư phương Nam. Ngày nay hàng triệu người Quảng Đông truy nguyên gia phả về con ngõ đá hẹp này, năm nào cũng có người trở về tìm tên tổ tiên mình.'),
  'shaoguan/yaodance': ('Người Dao', 'Người Dao ở các huyện miền núi Thiều Quan nổi tiếng với trang phục thêu rực rỡ và điệu múa trống dài. Trong lễ hội mùa gặt, tiếng trống vang vọng khắp thung lũng, còn những hoa văn thêu truyền lại lịch sử dòng tộc như một thứ ngôn ngữ không chữ viết.'),
  'zhanjiang/oyster': ('Hàu Trạm Giang', 'Hàu nuôi trong vùng nước phương Nam ấm áp, trong sạch của Trạm Giang lớn nhanh, béo mọng trắng như sữa. Buổi tối, hàu xèo xèo trên bếp than với tỏi và dầu tại các quầy hàng vỉa hè — một nghi thức đậm vị biển nằm giữa trái tim đời sống về đêm của thành phố.'),
  'zhanjiang/navy': ('Cảng Hải quân', 'Với cảng tự nhiên sâu và kín gió, Trạm Giang là nơi đóng quân của Hạm đội Nam Hải thuộc hải quân Trung Quốc. Từng bị cho Pháp thuê với tên gọi Quảng Châu Loan, thành phố cảng này ngày nay là cửa ngõ chiến lược của Trung Quốc hướng ra Biển Đông.'),
  'zhanjiang/mangrove': ('Rừng ngập mặn', 'Rừng ngập mặn dọc bờ biển Trạm Giang là khu bảo tồn rừng ngập mặn lớn nhất Trung Quốc. Ngập rồi cạn theo con nước thủy triều, khu rừng nước mặn này là mái nhà của cò trắng, cá thòi lòi và cua, trong khi bộ rễ chằng chịt vừa chắn bão cho bờ biển vừa làm vườn ươm tự nhiên cho cá con.'),
  'zhanjiang/donghai': ('Đảo Đông Hải', 'Đảo Đông Hải ngoài khơi Trạm Giang nổi tiếng với bãi biển trải dài liên tục nhiều cây số. Gió biển ổn định thu hút người chơi lướt sóng; hòn đảo còn được biết đến với điệu "múa rồng người" truyền thống, trong đó hàng chục người kề vai nhau hóa thành một con rồng duy nhất.'),
  'maoming/lychee': ('Thủ phủ vải thiều', 'Mậu Danh là một trong những vùng trồng vải lớn nhất thế giới; đầu hè, đồi núi nơi đây đỏ rực màu quả chín. Thời xưa, vải vùng này từng được hỏa tốc đưa về cung đình làm cống phẩm, và những cây vải cổ thụ hàng trăm năm tuổi trong vườn đến nay vẫn ra quả.'),
  'maoming/refinery': ('Cơ sở hóa dầu', 'Mậu Danh phát triển thành thành phố công nghiệp từ thập niên 1950 nhờ chế biến đá phiến dầu, và ngày nay sở hữu một trong những tổ hợp hóa dầu lớn nhất miền Nam Trung Quốc. Các nhà máy lọc dầu và sản xuất etylen tạo nên xương sống kinh tế vững chắc cho vùng đất vốn xanh tươi, giàu nông nghiệp này.'),
  'maoming/ladyxian': ('Phu nhân Tiển', 'Tiển phu nhân, nữ thủ lĩnh hiền minh sống ở thế kỷ thứ sáu, đã đoàn kết các dân tộc vùng cực Nam trong hòa bình. Hàng trăm đền miếu quanh Mậu Danh được dựng để thờ bà, và các lễ tưởng niệm hằng năm là minh chứng cho lòng tôn kính bền bỉ suốt khoảng mười lăm thế kỷ.'),
  'maoming/seaside': ('Bãi biển', 'Bờ biển Mậu Danh, được quảng bá là "Bãi biển số một Trung Quốc", trải dài hàng cây số cát vàng óng. Rừng phi lao trồng dọc bờ tạo thành tấm màn xanh chắn gió, còn các gia đình tắm biển suốt ngày rồi khép lại chuyến đi trong những nhà hàng hải sản.'),
  'zhaoqing/sevenstar': ('Thất Tinh Nham', 'Bảy ngọn núi đá vôi vươn lên từ hồ Tinh Hồ với thế sắp xếp được ví như chòm sao Bắc Đẩu. Trong lòng núi ẩn giấu những hang động phủ đầy bút tích khắc qua nhiều thế kỷ, và dạo bước trên các con đê ven hồ, bạn sẽ hiểu vì sao nơi đây được gọi là "Quế Lâm của Quảng Đông".'),
  'zhaoqing/inkstone': ('Nghiên mực Đoan Khê', 'Trong "văn phòng tứ bảo", nghiên mực nổi tiếng nhất chính là nghiên đá Đoan của Triệu Khánh. Được khai thác tại đây từ thời Đường, khối đá tím hóa thành tác phẩm nghệ thuật dưới bàn tay nghệ nhân; một nghiên Đoan hảo hạng giữ mực lâu khô và nâng niu ngọn bút lông.'),
  'zhaoqing/dinghu': ('Núi Đỉnh Hồ', 'Núi Đỉnh Hồ trở thành khu bảo tồn thiên nhiên đầu tiên của Trung Quốc vào năm 1956. Với rừng mưa cận nhiệt đới nguyên sinh, thác nước và chùa Khánh Vân, ngọn núi là chốn nghỉ mát mà người thành phố trìu mến gọi là "quầy bar oxy" của thiên nhiên.'),
  'zhaoqing/songwall': ('Tường thành thời Tống', 'Tường thành Triệu Khánh được đắp từ thời Tống và còn tồn tại gần như nguyên vẹn cả vòng thành. Các lớp gạch ghi dấu những lần tu sửa qua từng triều đại, và đi dạo trên mặt thành chẳng khác nào một vòng du hành qua gần một nghìn năm lịch sử đô thị.'),
  'huizhou/westlake': ('Tây Hồ Huệ Châu', 'Tây Hồ Huệ Châu là bức tranh cổ điển thanh nhã với những con đê rợp bóng liễu, cầu đá và đảo nhỏ. Đại thi hào Tô Đông Pha, khi bị biếm trích đến đây, đã đưa hồ vào những vần thơ bất hủ, và một con đê ven hồ đến nay vẫn mang tên ông.'),
  'huizhou/luofu': ('Núi La Phù', 'Núi La Phù là một trong những ngọn núi Đạo giáo linh thiêng nhất miền Nam Trung Quốc, bao thế kỷ thu hút ẩn sĩ và các nhà luyện đan tìm về. Những cánh rừng nổi tiếng nhiều dược liệu của núi ẩn chứa đền chùa, suối nguồn và các lối mòn leo lên tận tầng mây.'),
  'huizhou/alchemy': ('Lò luyện đan của Cát Hồng', 'Cát Hồng, nhà luyện đan kiêm thầy thuốc thời Tấn, đã lui về núi La Phù luyện thuốc và viết nên các trước tác y học của mình. Ghi chú của ông về cây thanh hao trong một cuốn sách cổ, nhiều thế kỷ sau, đã gợi cảm hứng cho việc tìm ra một loại thuốc chống sốt rét hiện đại.'),
  'huizhou/xunliao': ('Vịnh Huân Liêu', 'Vịnh Xunliao quyến rũ với làn nước xanh ngọc nông và dải cát sáng màu trải dài, trở thành khu nghỉ dưỡng được yêu thích trên bờ biển Quảng Đông. Những ngôi làng chài xưa nay phục vụ hải sản tươi rói, và mặt biển êm đềm rất hợp với các gia đình có trẻ nhỏ.'),
  'meizhou/weilongwu': ('Nhà围龙屋 (Vi Long Ốc)', 'Mai Châu được coi là thủ phủ tinh thần của người Khách Gia (Hakka) tản mát khắp thế giới. Những ngôi nhà vi long ốc hình móng ngựa tựa lưng vào đồi, quy tụ cả dòng họ lớn dưới một mái nhà, và sân nhà đến nay vẫn rộn ràng trong những dịp lễ họ tộc.'),
  'meizhou/saltchicken': ('Gà hấp muối', 'Gà ủ muối là món kinh điển nổi tiếng nhất của ẩm thực Khách Gia: cả con gà bọc giấy được vùi trong muối hạt nóng để chín từ từ. Muối không làm khô thịt mà ngược lại khóa trọn nước ngọt bên trong, cho ra thớ thịt mượt như lụa thoang thoảng hương gừng.'),
  'meizhou/football': ('Cái nôi bóng đá', 'Mai Châu là một trong những nơi bóng đá hiện đại bén rễ sớm nhất ở Trung Quốc, được mệnh danh là "cái nôi của bóng đá Trung Quốc". Tiền đạo huyền thoại Lý Huệ Đường sinh ra trên mảnh đất này, và niềm đam mê ấy vẫn chảy từ sân bóng làng đến các câu lạc bộ chuyên nghiệp.'),
  'meizhou/plum': ('Hoa mai', 'Tên Mai Châu bắt nguồn từ chữ "mai" — hoa mơ, và dòng Mai Giang, tức sông Mơ, tưới mát thành phố. Nở giữa giá lạnh mùa đông, hoa mai tượng trưng cho tinh thần kiên cường, chịu thương chịu khó của người Khách Gia và xuất hiện như một họa tiết trang trí khắp phố phường.'),
  'jiangmen/diaolou': ('Nhà chòi Khai Bình', 'Những tòa tháp điêu lâu vươn lên giữa ruộng lúa Khai Bình do những người Hoa hồi hương từ nước ngoài xây vào đầu thế kỷ hai mươi. Được thiết kế như pháo đài chống cướp và lũ lụt, chúng pha trộn hàng cột phương Tây với mái nhà Trung Hoa, và nay là Di sản Thế giới UNESCO.'),
  'jiangmen/qiaoxiang': ('Quê hương của người Hoa hải ngoại', 'Giang Môn và vùng Ngũ Ấp xung quanh là quê tổ của hàng triệu Hoa kiều trên khắp thế giới. Cộng đồng kiều bào trải từ châu Mỹ đến Đông Nam Á đã gửi tiền về xây trường học, đường sá và dinh thự, tạo cho thành phố một diện mạo hòa quyện Đông – Tây.'),
  'jiangmen/chenpi': ('Trần bì', 'Trần bì của Tân Hội là vỏ quýt được phơi nắng rồi ủ nhiều năm trước khi đem dùng. Nó mang lại hương thơm sâu lắng cho các món ăn Quảng Đông và rất được quý trọng trong y học cổ truyền; vỏ quýt ủ lâu năm được nâng niu chẳng khác gì một chai rượu vang hảo hạng.'),
  'jiangmen/birds': ('Thiên đường chim', '"Thiên đường của chim" ở Tân Hội là một cây đa khổng lồ duy nhất, cành buông rễ bén đất phủ kín cả một hòn đảo nhỏ. Hàng nghìn con cò và chim nước về đây trú ngụ, và bài tùy bút nổi tiếng của nhà văn Ba Kim đã khiến cả Trung Quốc đem lòng yêu mến hòn đảo xanh này.'),
  'yangjiang/knife': ('Thủ phủ dao kéo', 'Dương Giang là thủ phủ dao kéo của Trung Quốc; phần lớn dao bếp cả nước xuất xưởng từ các lò rèn và nhà máy nơi đây. Nghề rèn hàng trăm năm tuổi đã kết hợp với công nghệ thép hiện đại, đưa các thương hiệu địa phương đến gian bếp khắp thế giới.'),
  'yangjiang/shipwreck': ('Tàu Nam Hải số 1', 'Nam Hải 1 là thương thuyền thời Tống chìm trên Con đường Tơ lụa trên biển và ngủ yên dưới đáy đại dương suốt nhiều thế kỷ. Được trục vớt nguyên vẹn, con tàu nay yên nghỉ trong bảo tàng bể kính trên đảo Hải Lăng, nơi hàng chục nghìn món đồ sứ đã lộ diện từ khoang tàu.'),
  'yangjiang/hailing': ('Đảo Hải Lăng', 'Đảo Hải Lăng, với vịnh Đại Giác hình trăng lưỡi liềm và những bãi cát mềm mịn, là một trong những hòn đảo nghỉ mát được yêu thích nhất Quảng Đông. Ban ngày đùa mình trong sóng biển, buổi tối thưởng thức hải sản tươi từ bến cá — và đảo còn là nơi đặt bảo tàng xác tàu Nam Hải 1.'),
  'yangjiang/kite': ('Thành phố diều', 'Dương Giang cùng với Duy Phường ở phương Bắc được coi là hai thủ phủ diều của Trung Quốc. Những cánh diều truyền thống khung tre được làm thủ công qua bao thế hệ, và mỗi độ thu về, vào tết Trùng Cửu, bầu trời lại rợp những cánh diều rực rỡ sắc màu.'),
  'qingyuan/rafting': ('Thủ phủ chèo thuyền vượt thác', 'Với những dòng nước cuồn cuộn đổ xuống từ núi cao, Thanh Viễn được mệnh danh là "quê hương của chèo bè vượt thác" ở Trung Quốc. Mùa hè, hàng nghìn du khách cưỡi bè trên các đoạn sông tung bọt trắng, trong khi những thung lũng với rừng cây mát rượi và hồ đá là chốn trốn cái nóng phố thị.'),
  'qingyuan/chicken': ('Gà Thanh Viễn', 'Giống gà bản địa lông đốm của Thanh Viễn, xương nhỏ thịt đậm đà, là loại gà được săn đón nhất trong ẩm thực Quảng Đông. Được nuôi thả tự nhiên, gà thường chỉ luộc đơn giản rồi chấm sốt gừng hành — chính sự giản dị ấy là minh chứng cho chất lượng.'),
  'qingyuan/hotspring': ('Suối nước nóng', 'Nguồn nước nóng giàu khoáng chất trào lên từ các thung lũng núi đã biến Thanh Viễn thành thủ phủ suối khoáng nóng của Quảng Đông. Hơi nước cuộn lên từ những bể tắm lộ thiên giữa rừng tre xào xạc, và du khách từ Quảng Châu đổ về mỗi cuối tuần để ngâm mình xua tan mệt mỏi.'),
  'qingyuan/yaoterrace': ('Ruộng bậc thang người Dao', 'Ở các bản làng người Dao vùng Liên Nam, ruộng bậc thang leo dần lên sườn núi từng bậc một. Được đắp bằng tay qua nhiều thế kỷ, chúng hóa thành những tấm gương nước vào mùa xuân và bậc thang vàng óng vào mùa thu, trong khi các bản Dao cổ kính vẫn sinh sống giữa những thửa ruộng ấy.'),
  'chaozhou/guangjibridge': ('Cầu Quảng Tế', 'Cầu Quảng Tế bắc qua sông Hàn Giang, khởi dựng từ thời Tống, độc đáo với nhịp giữa ghép từ những con thuyền buộc sát cạnh nhau. Đoạn cầu phao mở ra mỗi ngày để nhường lối cho tàu thuyền, đưa cây cầu vào hàng bốn cây cầu cổ nổi tiếng của Trung Quốc.'),
  'chaozhou/woodcarving': ('Điêu khắc gỗ dát vàng', 'Nghệ thuật chạm gỗ thếp vàng của Triều Châu là nghề thủ công trứ danh, xếp cảnh này chồng lên cảnh khác trong cùng một bức phù điêu. Mọi chi tiết, từ tấm lưới ngư dân đến các anh hùng tuồng cổ, đều được đục đẽo tinh xảo, và những tác phẩm dát vàng ấy khiến đền chùa, dinh thự lấp lánh ánh vàng.'),
  'chaozhou/chaoxiu': ('Thêu Triều Châu', 'Thêu Triều Châu là nhánh lộng lẫy nhất của nghề thêu Quảng Đông: chỉ vàng chỉ bạc được thêu trên lớp đệm để tạo hiệu ứng phù điêu nổi. Rồng và phượng như chực bay ra khỏi mặt vải, tô điểm cho áo cưới lẫn phục trang sân khấu tuồng cổ.'),
  'chaozhou/kaiyuan': ('Chùa Khai Nguyên', 'Được sáng lập năm 738 dưới niên hiệu Khai Nguyên đời Đường, ngôi chùa mang tên niên hiệu ấy đến tận ngày nay. Hơn một nghìn năm hương khói chưa từng gián đoạn trong các sân chùa, những lư hương khổng lồ nghi ngút dưới các điện thờ được trang hoàng bằng nghệ thuật chạm gỗ tinh xảo nhất của Triều Châu.'),
  'jieyang/citygate': ('Cổng Tấn Hiền', 'Cổng Tiến Hiền — "cổng đón người hiền tài" — là biểu tượng thanh nhã còn sót lại của Yết Dương cổ. Tòa lầu gỗ mái chồng lớp soi bóng xuống hào thành, và cái tên gửi gắm ước nguyện của thành phố: rộng cửa đón những con người hiền đức, tài năng.'),
  'jieyang/jade': ('Thủ phủ ngọc bích', 'Dương Mỹ, một thị trấn thuộc Yết Dương, là một trong những trung tâm chế tác và buôn bán ngọc lớn nhất Trung Quốc. Ngọc bích thô từ Myanmar được cắt, chạm và đánh bóng tại đây, và trong các ngõ chợ, những bậc thầy "đọc" màu xanh ẩn trong từng khối đá như đánh một canh bạc.'),
  'jieyang/jieyanglou': ('Tháp Yết Dương', 'Lầu Yết Dương là công trình hiện đại làm sống lại kiến trúc cổ với những mái hiên truyền thống cong vút và dáng vẻ uy nghi. Bên trong là các triển lãm văn hóa, và tòa lầu đứng đó như niềm tự hào về cội nguồn của người Triều Sán được tạc vào đá và gỗ.'),
  'jieyang/beefbroth': ('Lẩu bò Triều Sán', 'Canh bò và lẩu bò Triều Sán là nền ẩm thực tôn thờ độ tươi: mỗi phần thịt của con bò có tên gọi riêng và chỉ được chần đúng vài giây trong nồi nước dùng trong veo. Ăn kèm nước chấm sa tế, sự điêu luyện ẩn trong giản dị ấy chính là niềm tự hào của cả vùng.'),
  'yunfu/marble': ('Vương quốc đá', 'Vân Phù được biết đến là thủ phủ nghề đá của Trung Quốc, nơi đá cẩm thạch và hoa cương được cắt gọt, đánh bóng qua bao thế hệ. Hàng nghìn xưởng đá nối nhau dọc quốc lộ xuất đi khắp thế giới mặt bàn, tượng và đá ốp lát; đá chính là kế sinh nhai hằng ngày của thành phố.'),
  'yunfu/patriarch': ('Lục tổ Huệ Năng', 'Huệ Năng, vị Lục Tổ của Thiền tông, sinh ra ở Tân Hưng thuộc Vân Phù và trải qua những ngày cuối đời tại đây. Chùa Quốc Ân dựng lên để tôn vinh ngài là chốn thanh tịnh thu hút khách hành hương — nơi khởi đầu câu chuyện của ngài, từ cậu bé đốn củi trở thành bậc thầy giác ngộ.'),
  'yunfu/tianlu': ('Núi Thiên Lộ', 'Núi Thiên Lộ là vương miện xanh của Vân Phù, những dãy sống núi vươn vào tầng mây và sườn núi phủ kín vườn chè. Buổi sớm, biển mây thường tràn ngập các thung lũng, ban thưởng cho những người leo núi đón bình minh cảnh tượng các đỉnh núi nhô lên từ màn sương.'),
  'yunfu/xijiang': ('Tây Giang', 'Tây Giang là nhánh chính của hệ thống sông Châu Giang và là một trong những tuyến đường thủy nhộn nhịp nhất miền Nam Trung Quốc. Sà lan chở hàng qua lại trước Vân Phù suốt ngày đêm, và dòng sông vẫn là mạch sống chuyên chở đá và nông sản xuôi về Quảng Châu rồi tỏa ra thế giới.'),
  'liuzhou/luosifen': ('Bún ốc Liễu Châu', 'Bún ốc Liễu Châu, tức luosifen, nổi danh nhờ nước dùng ninh từ ốc sông và vị chua nồng đặc trưng của măng muối. Mùi hương của nó gây tranh cãi từ xa, nhưng nếm thử một lần thường là mê luôn; ở dạng gói ăn liền, món đặc sản này đã chinh phục cả Trung Quốc và vươn ra thế giới.'),
  'liuzhou/autocity': ('Thành phố ô tô', 'Liễu Châu là trái tim công nghiệp của Quảng Tây và một trong những căn cứ sản xuất ô tô lớn của Trung Quốc. Những chiếc ô tô điện nhỏ gọn, giá phải chăng sản xuất tại đây đã trở thành biểu tượng của đường phố, được người dân yêu thích vì lách vừa cả những chỗ đỗ xe chật hẹp nhất.'),
  'liuzhou/karst': ('Địa hình karst sông Liễu', 'Dòng Liễu Giang uốn quanh thành phố như một dải thắt lưng, bốn bề là những ngọn núi đá vôi vươn cao. Khúc uốn lớn ấy khiến Liễu Châu được ví như "thành phố ấm trà", và ngay giữa lòng một đô thị công nghiệp, các công viên ven sông cùng những đỉnh karst đem lại vẻ đẹp thiên nhiên đầy bất ngờ.'),
  'liuzhou/liuhou': ('Thi hào Liễu Tông Nguyên', 'Liễu Tông Nguyên, đại văn hào đời Đường, làm quan cai quản chính nơi ông bị biếm trích là Liễu Châu, cho đào giếng và chăm lo dân nghèo. Đền thờ ông tọa lạc trong công viên Liễu Hầu giữa trung tâm, và nhà thơ mãi gắn liền với thành phố của những năm tháng cuối đời mình.'),
  'wuzhou/gemstone': ('Thủ phủ đá quý', 'Ngô Châu là thủ phủ đá quý nhân tạo của thế giới: phần lớn zircon tổng hợp toàn cầu được cắt và đánh bóng trong các xưởng bên sông nơi đây. Những đôi tay lành nghề mài giũa từng giác cắt trên các viên đá tí hon, để rồi từ đây chúng tỏa đi các chợ trang sức khắp địa cầu.'),
  'wuzhou/liubaotea': ('Trà đen Lục Bảo', 'Trà Lục Bảo của Ngô Châu là loại trà lên men sẫm màu, càng ủ lâu năm càng đằm dịu. Xưa kia trà theo thuyền sông đến tay thợ mỏ ở Đông Nam Á, những người tin rằng nó giúp điều hòa cơ thể trong khí hậu ẩm ướt; những sọt trà ủ lâu năm nay được giới sưu tầm săn lùng.'),
  'wuzhou/turtlejelly': ('Quy linh cao', 'Ngô Châu được xem là quê hương của quy linh cao, món thạch đen chế biến từ các vị thảo dược. Thạch hơi đăng đắng, thường được rưới mật ong và dùng lạnh — một truyền thống giải nhiệt được tin là giúp rút bớt "nhiệt trong người" giữa mùa hè ẩm nóng phương Nam.'),
  'wuzhou/dragonmother': ('Đền Long Mẫu', 'Miếu Long Mẫu bên bờ Tây Giang thờ vị nữ thần được coi là đấng bảo hộ của cư dân sông nước. Truyền thuyết kể rằng bà đã nuôi năm con rồng như con đẻ và che chở dân lành khỏi lũ lụt; vào những ngày hội, ngôi miếu ngập trong khói hương và các dải lụa ước nguyện.'),
  'beihai/silverbeach': ('Bãi biển Ngân Than', 'Bãi Bạc của Bắc Hải lấp lánh đúng như tên gọi: cát trắng giàu thạch anh ánh lên sắc bạc dưới nắng. Được ca tụng là "bãi biển số một thiên hạ", bờ cát trải dài hàng cây số, và vùng biển nông, ấm áp mở ra không gian bơi lội, dạo bước như vô tận.'),
  'beihai/pearl': ('Thành phố ngọc trai', 'Hợp Phố thuộc Bắc Hải nổi tiếng về ngọc trai từ thời Hán; "ngọc phương Nam" nơi đây từng thuộc hàng cống phẩm quý giá nhất dâng lên triều đình. Thành ngữ "châu về Hợp Phố" ra đời trên chính bờ biển này, và các trại nuôi ngọc trai cùng chợ trang sức vẫn giữ cho truyền thống sống mãi.'),
  'beihai/weizhou': ('Đảo Vi Châu', 'Vi Châu ngoài khơi Bắc Hải được biết đến là hòn đảo núi lửa trẻ nhất Trung Quốc. Vách đá nham thạch đen, rạn san hô và những vườn chuối bao quanh đảo, còn nhà thờ Công giáo bằng đá do các nhà truyền giáo xây vào thế kỷ mười chín là cảnh tượng gây ngạc nhiên nhất trên đảo.'),
  'beihai/oldstreet': ('Phố cổ', 'Phố Cổ Bắc Hải san sát những dãy nhà kỵ lâu (qilou) có hàng hiên vòm, mọc lên khi thương cảng mở cửa giao thương với nước ngoài vào cuối thế kỷ mười chín. Những mặt tiền cuốn vòm phảng phất hơi thở Đông Nam Á và châu Âu, và ngày nay con phố vẫn lưu giữ quá khứ giữa các quầy trứng chiên hàu và dấu tích những tòa lãnh sự xưa.'),
  'qinzhou/nixingpottery': ('Gốm Nê Hưng', 'Gốm Nê Hưng của Khâm Châu, dù nung hoàn toàn không tráng men, vẫn tự khoác lên các sắc đồng, đỏ thẫm và tím ngay trong lò. Được chế tác từ đất sét pha trộn lấy ở hai bờ sông, nghề gốm này thuộc hàng bốn dòng gốm danh tiếng của Trung Quốc.'),
  'qinzhou/dolphin': ('Cá heo trắng', 'Vịnh Tam Nương ở Khâm Châu là một trong những mái nhà nổi tiếng nhất của loài cá heo trắng Trung Hoa quý hiếm. Những sinh vật duyên dáng này chuyển dần sang màu hồng khi về già và thường nổi lên bên cạnh thuyền du lịch; người dân địa phương tự hào bảo vệ loài vật mà họ gọi là "gấu trúc của biển cả".'),
  'qinzhou/oysterfarm': ('Trại hàu', 'Biển Mao Vĩ nông và giàu dinh dưỡng ở Khâm Châu là một trong những vườn ươm hàu giống lớn nhất Trung Quốc. Mặt nước phủ kín những dãy bè nổi nối tiếp nhau, và vụ hàu béo mọng đưa thành phố thành thủ phủ hàu của phương Nam, những lò nướng mùa lễ hội chẳng bao giờ nguội lửa.'),
  'qinzhou/general': ('Tướng quân Phùng Tử Tài', 'Danh tướng nhà Thanh Phùng Tử Tài, dù tuổi đã cao, vẫn tái xuất cầm quân và giành chiến thắng lịch sử chống quân xâm lược tại ải Trấn Nam trên biên giới Việt Nam. Tại quê hương Khâm Châu, dinh thự cũ của ông được gìn giữ làm bảo tàng, và tên tuổi ông sống mãi như biểu tượng của tinh thần bảo vệ quê hương.'),
  'guigang/lotus': ('Thành phố hoa sen', 'Quý Cảng được cả Trung Quốc biết đến với tên gọi "Thành phố Sen": mùa hè, ao đầm và đồng ruộng quanh thành phố phủ kín sắc hoa hồng phấn và trắng. Ngó sen và hạt sen là nguyên liệu quen thuộc của gian bếp địa phương, và lễ hội sen thường niên khiến cả thành phố tưng bừng lễ hội.'),
  'guigang/uprising': ('Khởi nghĩa Kim Điền', 'Năm 1851, tại làng Kim Điền thuộc Quế Bình, Hồng Tú Toàn phất cờ khởi nghĩa Thái Bình Thiên Quốc. Một trong những phong trào quần chúng lớn nhất thế kỷ mười chín đã từ đây lan rộng, làm rung chuyển nửa nước Trung Hoa, và khu tưởng niệm trong làng ngày nay kể lại câu chuyện ấy.'),
  'guigang/nanshan': ('Chùa Nam Sơn', 'Chùa Nam Sơn ở Quý Cảng là chốn thiêng nghìn năm tuổi nép mình trong những hang động tự nhiên của một ngọn đồi đá vôi. Vách hang phủ kín bút tích và thi phú khắc qua bao triều đại, trong khi các pho tượng Phật lặng lẽ an tọa trong những gian đá mát lạnh.'),
  'guigang/sugarcane': ('Mía đường', 'Quảng Tây là nguồn cung đường lớn nhất Trung Quốc, và đồng bằng ven sông màu mỡ của Quý Cảng góp phần quan trọng vào vụ mùa ngọt ngào ấy. Vào thu, mía đã cao vượt đầu người, và đến mùa thu hoạch, đường sá đầy ắp những chuyến xe tải chở mía về nhà máy.'),
  'yulin/medicine': ('Chợ dược liệu', 'Chợ dược liệu Ngọc Lâm thuộc hàng đầu mối buôn bán thuốc y học cổ truyền lớn nhất miền Nam Trung Quốc. Các dãy hàng quyện hương rễ, vỏ cây và hoa phơi khô, và các thương nhân — những người thừa kế kho tri thức hàng thế kỷ — thuộc lòng tính vị của từng vị thuốc.'),
  'yulin/goldenpalace': ('Vân Thiên Cung', 'Vân Thiên Cung là công trình văn hóa đồ sộ tái hiện kiến trúc cung điện truyền thống ở quy mô khổng lồ. Các tầng lầu trưng bày phù điêu tinh xảo, tượng đồng và những tích truyện thần thoại, còn các tòa tháp dát vàng là điểm nhấn ấn tượng nhất trên đường chân trời thành phố.'),
  'yulin/lychee': ('Vườn vải', 'Đồi núi và thung lũng ấm áp của Ngọc Lâm phủ kín những vườn vải và nhãn. Đầu hè, cành cây trĩu nặng từng chùm quả đỏ, sạp chợ ngập tràn thứ trái thơm ngọt của mùa thu hoạch, và các gia đình coi ngày hái quả như một ngày hội.'),
  'yulin/beef': ('Thịt bò Ngọc Lâm', 'Niuba, món ăn vặt trứ danh của Ngọc Lâm, được làm bằng cách sấy và om chậm những lát thịt bò thái mỏng trong nước sốt gia vị. Miếng thịt sẫm màu, ngòn ngọt và đậm đà hết mực, ăn cùng cơm hoặc nhâm nhi bên tách trà; công thức được các gia đình truyền từ đời này sang đời khác.'),
  'baise/redbase': ('Khởi nghĩa Bách Sắc', 'Năm 1929, cuộc khởi nghĩa Bách Sắc do Đặng Tiểu Bình thời trẻ lãnh đạo đã lập nên căn cứ cách mạng bên dòng sông Hữu Giang. Vì thế thành phố là điểm dừng quan trọng trên các tuyến du lịch "ký ức đỏ" của Trung Quốc, với nhà tưởng niệm và các tòa nhà tổng hành dinh xưa đưa cả một thời kỳ về với hiện tại.'),
  'baise/sinkhole': ('Hố sụt Lạc Nghiệp', 'Những hố sụt khổng lồ, gọi là thiên khanh, ở huyện Lạc Nghiệp hợp thành một trong những cụm hố sụt dày đặc nhất Trái Đất. Dưới đáy vực sâu hàng trăm mét là những cánh rừng nguyên sinh chưa ai chạm tới, còn sông ngầm và hệ thống hang động khiến nơi đây thành điểm đến ưa thích của các nhà địa chất và dân thám hiểm hang.'),
  'baise/mango': ('Thủ phủ xoài', 'Những thung lũng nóng ấm, chan hòa nắng của Bách Sắc thuộc hàng vùng trồng xoài quan trọng nhất Trung Quốc. Giữa hè, các sườn đồi ngả sắc vàng, xe tải chở trái ngọt tỏa đi khắp cả nước, và cây xoài đã trở thành vừa kế sinh nhai vừa niềm kiêu hãnh của các huyện miền núi này.'),
  'baise/aluminum': ('Thành phố nhôm', 'Núi non Bách Sắc giàu quặng bô-xít, thứ quặng đã đưa thành phố trở thành căn cứ phía Nam của ngành công nghiệp nhôm Trung Quốc. Các mỏ và nhà máy luyện kim là xương sống kinh tế của vùng, và thứ kim loại "bạc" ẩn dưới lớp đất đỏ ấy đem lại việc làm cho hàng nghìn gia đình.'),
  'hechi/longevity': ('Ba Mã trường thọ', 'Ba Mã thuộc Hà Trì là "miền trường thọ" nổi tiếng thế giới, nơi tỷ lệ cư dân sống quá trăm tuổi cao đến kinh ngạc. Không khí trong lành, bữa ăn đạm bạc và nhịp sống thong dong được coi là bí quyết, và mỗi năm hàng nghìn du khách tìm về những thung lũng này để kiếm tìm sức khỏe.'),
  'hechi/folksong': ('Lưu Tam Tỷ', 'Nghi Châu thuộc Hà Trì được tôn vinh là quê hương của Lưu Tam Tỷ, nàng ca sĩ dân gian huyền thoại của người Choang. Trong truyện kể, nàng "tiên ca" đã dùng những màn hát đối ứng khẩu để hạ gục bọn địa chủ — truyền thống ấy đến nay vẫn sống động rộn ràng tại các hội hát.'),
  'hechi/bronzedrum': ('Trống đồng', 'Trống đồng là một trong những vật thiêng nhất của các dân tộc phương Nam như người Choang và người Dao, và Hà Trì được coi là trái tim của văn hóa trống đồng còn sống động. Những chiếc trống chạm nổi vang lên trong lễ hội để cầu phúc lành và sự chở che, và nhiều bản làng gìn giữ trống cổ trăm năm như báu vật gia truyền.'),
  'hechi/geopark': ('Công viên địa chất Karst', 'Vùng karst Hà Trì là một phòng thí nghiệm của thiên nhiên với hố sụt, những vòm hang khổng lồ và sông ngầm. Cầu đá tự nhiên và các "cửa sổ trời" của hang động quanh Phượng Sơn là ngôi sao của công viên địa chất; nơi ánh sáng rót xuống qua giếng trời, những thế giới ẩn giấu dần hiện ra bên dưới.'),
  'laibin/sugarcity': ('Thủ phủ đường', 'Đồng bằng Lai Tân phủ kín mía ngút tầm mắt, mang về cho thành phố danh xưng "thủ phủ đường của Trung Quốc". Khi vụ thu hoạch mùa đông bắt đầu, ống khói các nhà máy lại nghi ngút, biến cây mía thành đường, mật rỉ và giấy, còn hương thơm ngọt dịu lan tỏa khắp các thị trấn.'),
  'laibin/yao': ('Người Dao Đại Dao', 'Dãy núi Đại Dao ở Kim Tú thuộc Lai Tân là quê hương của năm nhánh người Dao khác biệt, mỗi nhánh có trang phục, thổ ngữ và nghi lễ riêng. Trang sức bạc và mũ đội thêu hoa lấp lánh trong các lễ hội bản làng, biến Kim Tú thành một bảo tàng văn hóa sống.'),
  'laibin/hongshui': ('Sông Hồng Thủy', 'Sông Hồng Thủy, mang tên lớp phù sa đỏ mà nó chuyên chở, là dòng sông hùng vĩ xẻ dọc núi non Quảng Tây. Các đập thủy điện dọc thung lũng đưa điện tỏa khắp miền Nam, trong khi những ngôi làng ven sông tận hưởng cảnh sắc mà dòng nước khắc nên giữa các đỉnh karst.'),
  'laibin/shengtang': ('Núi Thánh Đường', 'Núi Thánh Đường là đỉnh cao nhất của dãy Đại Dao và thuộc hàng những "nóc nhà" của Quảng Tây. Mùa xuân, sườn núi rực đỏ hoa đỗ quyên, còn trên đỉnh, biển mây, bình minh và màn sương cuốn theo gió là phần thưởng dành cho những ai chinh phục.'),
  'chongzuo/waterfall': ('Thác Bản Giốc', 'Thác Đức Thiên — phía Việt Nam gọi là thác Bản Giốc — đổ xuống thành từng bậc rộng trên dòng sông biên giới Trung–Việt và được xem là thác nước xuyên quốc gia lớn nhất châu Á. Bè tre đưa bạn vào làn hơi nước mát lạnh của màn thác, trong khi những đỉnh karst bốn bề biến khung cảnh thành một bức tranh thủy mặc.'),
  'chongzuo/langur': ('Voọc đầu trắng', 'Voọc đầu trắng chỉ sinh sống giữa những ngọn đồi đá vôi của Sùng Tả và thuộc hàng linh trưởng quý hiếm nhất thế giới. Ban đêm chúng ngủ trong khe vách đá, ban ngày chuyền nhảy trên vách núi cheo leo, và nhờ các khu bảo tồn, số lượng của loài đang dần hồi phục.'),
  'chongzuo/rockart': ('Tranh đá Hoa Sơn', 'Được người Lạc Việt vẽ lên vách đá sông Tả Giang khoảng hai nghìn năm trước, những hình vẽ màu đỏ khắc họa hàng nghìn người nhảy múa trong tư thế ếch. Làm thế nào họ vẽ được trên những vách đá hiểm trở đến vậy vẫn còn là điều tranh cãi, và nghệ thuật vách đá này đã được UNESCO ghi danh Di sản Thế giới.'),
  'chongzuo/borderpass': ('Ải Nam Quan', 'Hữu Nghị Quan là cửa khẩu lịch sử nối Trung Quốc với Việt Nam và thuộc hàng những cửa ải nổi tiếng của Trung Quốc. Tòa lầu cổng vòm giữa núi non xanh thẳm đã đón đưa binh đoàn, đoàn thương buôn và sứ thần suốt bao thế kỷ, và ngày nay vẫn là cánh cổng giao thương biên giới nhộn nhịp.'),
  'beijing/great-wall': ('Vạn Lý Trường Thành', 'Công trình phòng thủ dài nhất thế giới — hơn 20.000 km được xây dựng qua nhiều thế kỷ để bảo vệ biên cương phía bắc Trung Quốc. Đoạn Bát Đạt Lĩnh gần Bắc Kinh, với những bậc đá, tường thành và các tháp canh trải dài trên sống núi, là khúc trường thành được tham quan nhiều nhất.'),
  'beijing/temple': ('Thiên Đàn', 'Quần thể đền thiêng nơi các hoàng đế nhà Minh và nhà Thanh hằng năm cầu trời cho mùa màng bội thu. Mái tròn ba tầng màu xanh lam của Thiên Đàn — được dựng không dùng một chiếc đinh nào — là một trong những biểu tượng dễ nhận biết nhất của kiến trúc Trung Hoa.'),
  'beijing/pagoda': ('Chùa Thiên Ninh', 'Ngọn tháp gạch 13 tầng cao khoảng 57 mét có từ thời nhà Liêu. Với những phù điêu chạm khắc và thân tháp bát giác, đây là một trong những công trình cổ nhất còn tồn tại ở Bắc Kinh — chứng nhân cho lịch sử nghìn năm của thành phố.'),
  'beijing/opera': ('Kinh kịch', 'Nghệ thuật sân khấu truyền thống Trung Hoa 200 năm tuổi, hòa quyện ca hát, thoại kịch, võ thuật và nhào lộn. Lớp hóa trang mặt nạ nhiều màu (kiểm phổ) của diễn viên hé lộ tính cách từng nhân vật: màu đỏ tượng trưng cho lòng trung nghĩa, màu trắng cho sự gian xảo.'),
  'zunyi/huiyi': ('Hội nghị Tuân Nghĩa', 'Trong những ngày đen tối nhất của cuộc Vạn lý Trường chinh, các lãnh đạo Đảng Cộng sản đã họp tại tòa nhà đá xám này năm 1935, vẽ lại hướng đi của cách mạng và mở đường cho Mao Trạch Đông vươn lên vị trí lãnh đạo. Ngày nay ngôi nhà trở thành bảo tàng, đưa Tuân Nghĩa vào vị trí trung tâm trên bản đồ \'du lịch đỏ\' của Trung Quốc.'),
  'zunyi/moutai': ('Thị trấn Mao Đài', 'Thị trấn nhỏ Mao Đài bên bờ sông Xích Thủy là quê hương của loại rượu bạch tửu huyền thoại được tôn vinh là quốc tửu Trung Hoa. Được chưng cất từ cao lương và ủ nhiều năm, thứ rượu nồng nàn này trở thành món không thể thiếu trong các quốc yến; ngay cả không khí thị trấn cũng phảng phất hương men.'),
  'zunyi/loushan': ('Đèo Lâu Sơn', 'Đèo Lâu Sơn hiểm trở xẻ đôi núi non là nơi diễn ra trận thắng lịch sử của Hồng quân trong cuộc Vạn lý Trường chinh. Mao Trạch Đông đã bất tử hóa con đèo bằng bài thơ nổi tiếng viết tại đây; ngày nay du khách leo lên những vách đá mù sương và đọc những vần thơ ấy được khắc vào đá.'),
  'zunyi/chishui': ('Thác Xích Thủy', 'Thác nước đổ xuống từ những vách đá Đan Hà đỏ rực của Xích Thủy vào thung lũng rừng tre và những cây dương xỉ thân gỗ khổng lồ còn sót lại từ thời khủng long. Tên vùng đất có nghĩa là \'nước đỏ\', bắt nguồn từ dòng sông chuyển màu đỏ thẫm sau mưa, và cảnh quan nơi đây thuộc di sản thiên nhiên Đan Hà Trung Quốc của UNESCO.'),
  'liupanshui/coolcity': ('Thành phố Mát mẻ', 'Nằm trên cao nguyên nơi mùa hè luôn mát mẻ dễ chịu, Lục Bàn Thủy tự hào mang danh hiệu \'thủ đô mát lạnh của Trung Quốc\'. Mỗi mùa hè, du khách từ Tứ Xuyên và Trùng Khánh oi bức đổ về đây tránh nóng, và thành phố đã khéo léo biến bầu không khí trong lành ấy thành các lễ hội và du lịch vùng cao.'),
  'liupanshui/coal': ('Biển than Tây Nam', 'Được xây dựng trên những vỉa than giàu có, Lục Bàn Thủy từ lâu là lò năng lượng của miền tây nam Trung Quốc. Thành phố lớn lên quanh các mỏ than và nhà máy thép trong cuộc đại công nghiệp hóa thế kỷ XX; ngày nay nơi đây đang cân bằng bản sắc thợ mỏ của mình với năng lượng xanh và du lịch.'),
  'liupanshui/grassland': ('Đồng cỏ Ô Mông', 'Những thảo nguyên bát ngát của cao nguyên Ô Mông, láng giềng của mây trời, điểm xuyết đàn ngựa và những hàng tuabin gió nơi chân trời. Người Di và người Miêu chăn thả gia súc suốt mùa hè mát mẻ, và sương mù cao nguyên có thể buông xuống trong chớp mắt, biến cả khung cảnh thành xứ sở cổ tích.'),
  'liupanshui/kiwi': ('Kiwi ruột đỏ', 'Kiwi ruột đỏ sinh trưởng trên các cao nguyên mát mẻ, mù sương quanh Lục Bàn Thủy và trở thành kho báu xanh ngọt ngào của thành phố. Với phần ruột đỏ hồng như ngọc, loại quả này ngọt hơn kiwi thường; đến mùa thu hoạch, các bản làng miền núi rộn ràng với từng thùng quả đầy ắp.'),
  'anshun/huangguoshu': ('Thác Hoàng Quả Thụ', 'Hoàng Quả Thụ, thác nước lớn nhất Trung Quốc, đổ ầm ầm từ độ cao 77 mét và rải cầu vồng qua màn sương nước. Một lối đi xuyên qua động Thủy Liêm phía sau thác cho phép bạn ngắm nhìn từ sau bức màn nước — nhiều cảnh trong bộ phim truyền hình kinh điển Tây Du Ký được quay tại đây.'),
  'anshun/dixi': ('Kịch Địa hí', 'Được trình diễn trên sân làng với mặt nạ chiến binh gỗ chạm khắc và tiếng chiêng vang dội, kịch Địa hí được gọi là \'hóa thạch sống của hí kịch Trung Hoa\'. Theo chân binh lính đồn trú nhà Minh đến Quý Châu, loại hình sân khấu nghi lễ này đã kể lại các thiên anh hùng ca chiến trận cổ xưa với cùng một nhiệt huyết suốt khoảng sáu thế kỷ.'),
  'anshun/batik': ('Nghệ thuật nhuộm sáp', 'Phụ nữ Bố Y và Miêu dùng sáp ong nóng chảy vẽ chim muông, hoa lá và hoa văn xoáy lên vải, rồi nhúng tấm vải vào thuốc nhuộm chàm. Màu nhuộm thấm vào những vết nứt li ti của sáp khiến mỗi tấm vải trở nên độc nhất vô nhị, vì thế vải batik An Thuận được xem là nghề thủ công không có bản sao.'),
  'anshun/tunpu': ('Làng Đồn Phố', 'Trong những ngôi làng đồn trú bằng đá do quân đội nhà Minh lập nên khoảng 600 năm trước, người Đồn Bảo (Tunpu) vẫn mặc trang phục kiểu Nam Kinh xưa của tổ tiên và nói một phương ngữ cổ. Dạo bước trên những con ngõ tường đá nơi đây tựa như bước vào một thị trấn nhà Minh đông cứng trong thời gian.'),
  'bijie/azalea': ('Rừng đỗ quyên Bách Lý', 'Mỗi độ xuân về, các sườn núi Tất Tiết rực cháy sắc đỏ thắm, hồng và tím của hoa đỗ quyên, và \'Vành đai Đỗ quyên Trăm dặm\' được xem là rừng đỗ quyên tự nhiên lớn nhất thế giới. Trong các lễ hội tháng Tư, dân làng Di và Miêu đón chào mùa xuân bằng lời ca giữa biển hoa.'),
  'bijie/zhijin': ('Động Chức Kim', 'Hang Chức Kim, nơi những cột măng đá khổng lồ vươn cao như rừng đá, được mệnh danh là \'cung điện dưới lòng đất\' và xếp vào hàng những hang động ngoạn mục nhất Trung Quốc. Trong những khoang hang rộng như thánh đường, các khối thạch nhũ tinh xảo như \'Cây Mưa Bạc\' khiến du khách sững sờ mê đắm.'),
  'bijie/caohai': ('Sếu Thảo Hải', 'Thảo Hải, hồ nước nông đầy cỏ trên cao nguyên Uy Ninh, mỗi mùa đông lại trở thành nơi trú ngụ của loài sếu cổ đen quý hiếm. Khi sương sớm tan dần, tiếng gọi của hàng nghìn con chim tràn ngập mặt nước, trong lúc những người chèo thuyền lặng lẽ đưa du khách len lỏi giữa các bãi lau sậy.'),
  'bijie/potato': ('Thủ phủ khoai tây', 'Khoai tây trồng trên các cao nguyên mát mẻ, chan hòa nắng khiến Tất Tiết trở thành một trong những vựa khoai tây lớn của Trung Quốc, và khoai Uy Ninh nổi danh khắp cả nước. Được nướng trên than hồng, chiên giòn và trộn ớt cay tại các quầy hàng rong, củ khoai tây bình dị chính là vương miện của ẩm thực cao nguyên.'),
  'qujing/rapeseed': ('Biển hoa cải La Bình', 'Cuối đông, bình nguyên La Bình chìm trong sắc hoa cải dầu vàng rực, với những chóp núi đá vôi nhô lên giữa cánh đồng như những hòn đảo trong biển vàng. Mùa hoa thu hút người nuôi ong, nhiếp ảnh gia và người mê mật ong từ khắp bốn phương, và cả không khí cũng trở nên ngọt ngào.'),
  'qujing/ham': ('Giăm bông Tuyên Uy', 'Được ướp muối và hong khô trong khí hậu núi cao suốt hàng thế kỷ, giăm bông Tuyên Uy là niềm tự hào của ẩm thực Vân Nam. Thớ thịt đỏ hồng và hương vị đậm đà đưa nó vào hàng những loại giăm bông nổi tiếng nhất Trung Quốc, góp mặt trong đủ món từ canh súp đến bánh trung thu ngày lễ.'),
  'qujing/jiulong': ('Thác Cửu Long', 'Gần La Bình, dòng sông \'Cửu Long\' đổ xuống thành một chuỗi thác bậc thang, mỗi tầng thác mang chiều rộng và cá tính riêng. Vào mùa nước lớn, khung cảnh được viền quanh bởi những cánh đồng cải dầu vàng óng được xem là một trong những chuỗi thác đẹp nhất Trung Quốc.'),
  'qujing/sandforest': ('Rừng cát ngũ sắc', 'Tại Rừng Cát Màu ở Lục Lương, những cột cát được gió mưa gọt giũa ánh lên đủ sắc từ vàng, đỏ nâu đến trắng và tím. Màu sắc biến đổi theo ánh sáng, biến khu vườn điêu khắc tự nhiên này thành phim trường yêu thích của các đoàn làm phim và nhiếp ảnh gia.'),
  'yuxi/fuxian': ('Hồ Phủ Tiên', 'Phủ Tiên, một trong những hồ sâu nhất Trung Quốc, nằm lọt giữa cao nguyên Vân Nam như tấm gương núi bằng nước trong vắt như pha lê. Truyền thuyết kể về một thành cổ chìm dưới đáy hồ, và ngư dân các làng ven bờ vẫn giăng lưới bắt loài cá kanglang nhỏ bé nổi tiếng của hồ.'),
  'yuxi/nieer': ('Nhạc sĩ Nhiếp Nhĩ', 'Nhiếp Nhĩ, người soạn quốc ca Trung Quốc, xuất thân từ một gia đình gốc Ngọc Khê, và thành phố tự hào nhận ông là người con quê hương. Với công viên âm nhạc, đài tưởng niệm và các lễ hội mang tên ông, Ngọc Khê truyền lại giai điệu của nhà soạn nhạc yểu mệnh từ thế hệ này sang thế hệ khác.'),
  'yuxi/chengjiang': ('Hóa thạch Trừng Giang', 'Các tầng hóa thạch kỷ Cambri 530 triệu năm tuổi ở Trừng Giang là Di sản Thế giới UNESCO, hé lộ buổi bình minh của sự sống động vật với độ chi tiết kinh ngạc. Ngay cả các mô mềm cũng in hằn vào đá, khiến những sinh vật này trở thành các nhân chứng phong phú bậc nhất của \'vụ bùng nổ kỷ Cambri\'.'),
  'yuxi/kiln': ('Lò gốm Ngọc Khê', 'Lò gốm cổ Ngọc Khê, có từ thời nhà Nguyên, được xem là nơi khai sinh dòng gốm sứ hoa lam của Vân Nam. Làm nghề ở nơi cách xa Cảnh Đức Trấn danh tiếng, các nghệ nhân địa phương đã phát triển phong cách riêng, ghi dấu ấn lên truyền thống gốm sứ miền tây nam bằng những sản phẩm vẽ men lam cobalt.'),
  'dali/threepagodas': ('Sùng Thánh Tự Tam Tháp', 'Vươn cao dưới chân dãy Thương Sơn suốt nghìn năm, ba ngọn tháp thanh nhã là biểu tượng của các vương quốc cổ Nam Chiếu và Đại Lý. Trụ vững qua bao thế kỷ động đất, những ngọn tháp tạo nên khung cảnh bưu thiếp được yêu thích nhất của Đại Lý, với đỉnh núi tuyết phía sau và hồ nước phản chiếu phía trước.'),
  'dali/erhai': ('Hồ Nhĩ Hải', 'Mang tên gọi từ hình dáng vành tai, Nhĩ Hải là hồ cao nguyên trải dài giữa dãy Thương Sơn và bình nguyên Đại Lý. Những ngôi làng người Bạch tường trắng tô điểm ven bờ, và đạp xe quanh hồ hay ngắm thuyền cá lúc bình minh là những thú vui kinh điển của Đại Lý.'),
  'dali/cangshan': ('Núi Thương Sơn', 'Với mười chín đỉnh núi và mười tám dòng suối len lỏi giữa chúng, Thương Sơn vươn lên như tấm rèm xanh sau lưng Đại Lý. Trong tiếng Trung, đá cẩm thạch được gọi hẳn là \'đá Đại Lý\': loại đá vân hoa khai thác từ những mạch núi này đã tô điểm cung điện và đền chùa suốt hàng thế kỷ.'),
  'dali/wind': ('Phong Hoa Tuyết Nguyệt', 'Gió Hạ Quan, hoa Thượng Quan, tuyết Thương Sơn và trăng Nhĩ Hải — bốn vẻ đẹp của Đại Lý được ngâm nga như một bài thơ duy nhất. Ngay cả khăn đội đầu của phụ nữ Bạch cũng dệt bốn biểu tượng ấy, một công thức thanh nhã mà thành phố dùng để tự khắc họa thiên nhiên của mình.'),
  'lijiang/oldtown': ('Phố cổ Lệ Giang', 'Được dệt nên từ kênh nước, ngõ đá cuội và những ngôi nhà gỗ mái ngói, phố cổ Lệ Giang là trái tim sống động của văn hóa Nạp Tây. Đô thị UNESCO nổi tiếng vì được xây không tường thành này từng đón các đoàn thương buôn trên Trà Mã Cổ Đạo, và tiếng nước chảy róc rách vẫn theo chân bạn xuống từng con ngõ.'),
  'lijiang/snowmountain': ('Núi tuyết Ngọc Long', 'Với đỉnh băng tuyết cao 5.596 mét, núi tuyết Ngọc Long lấp lánh trên bầu trời Lệ Giang như con rồng đang say ngủ. Người Nạp Tây tôn núi là chốn linh thiêng; cáp treo đưa du khách lên công viên sông băng, trong khi thung lũng Lam Nguyệt dưới chân núi mê hoặc lòng người bằng những hồ nước xanh ngọc lam.'),
  'lijiang/dongba': ('Chữ tượng hình Đông Ba', 'Đông Ba, chữ tượng hình của các thầy tế Nạp Tây, được xem là hệ chữ tượng hình cuối cùng trên thế giới còn được sử dụng. Hàng nghìn bản thảo ghi lại các nghi lễ thờ thần linh thiên nhiên và vũ trụ quan của người Nạp Tây — một kho lưu trữ đã được ghi danh vào Chương trình Ký ức Thế giới của UNESCO.'),
  'lijiang/tigerleaping': ('Hẻm núi Hổ Nhảy', 'Truyền thuyết kể rằng một con hổ đã vượt qua khúc hẹp nhất của sông Kim Sa chỉ bằng một cú nhảy, đặt tên cho hẻm núi Hổ Khiêu. Lao sâu giữa hai ngọn núi tuyết Ngọc Long và Cáp Ba, đây là một trong những hẻm núi sâu nhất địa cầu, và con đường mòn trên cao men theo sườn núi là giấc mơ của dân trekking.'),
  'lincang/dianhong': ('Trà đen Điền Hồng', 'Điền Hồng, loại hồng trà búp vàng của Phượng Khánh, tuy chỉ mới ra đời trong thế kỷ trước nhưng đã nhanh chóng đưa tên tuổi Vân Nam ra thế giới. Được quý chuộng nhờ nước trà thoảng hương mật ong và caramel, nó xếp vào hàng những loại hồng trà danh giá nhất Trung Quốc, càng thêm sâu lắng nhờ lá hái từ những cây trà cổ thụ.'),
  'lincang/wadrum': ('Trống gỗ người Ngõa', 'Người Ngõa xem trống gỗ là vật linh thiêng, tin rằng tiếng trống bắc cầu nối giữa trời và người. Ở các bản làng miền núi Thương Nguyên, điệu múa trống tung tóc — nơi các cô gái quăng mái tóc dài theo nhịp trống — làm rung chuyển cả thung lũng trong những ngày mùa gặt và lễ hội.'),
  'lincang/teatrees': ('Cây trà cổ thụ', 'Những dãy núi mù sương của Lâm Thương che chở các cây trà hoang dã và cổ thụ có tuổi đời tính bằng thế kỷ, thậm chí thiên niên kỷ, gìn giữ những cánh rừng nơi cây trà khai sinh. Vào vụ xuân, dân làng bắc thang leo lên những cây trà khổng lồ, và từ những lá trà già ấy ra đời các loại trà Phổ Nhĩ được săn lùng bậc nhất thế giới.'),
  'lincang/lancang': ('Sông Lan Thương', 'Lan Thương, thượng nguồn của sông Mekong, đổ xuống từ Tây Tạng và xẻ qua những thung lũng sâu của Lâm Thương trên hành trình về phương nam tới Đông Nam Á. Chuỗi đập thủy điện dọc dòng sông thắp sáng cả vùng, trong khi những đồi trà và vườn cây ăn quả nhiệt đới leo dần lên các triền dốc bên bờ.'),
  'puer/tea': ('Trà Phổ Nhĩ', 'Trà Phổ Nhĩ ép bánh, mang tên chính thành phố miền núi này, là báu vật sống càng ủ lâu năm càng đằm vị và tăng giá trị. Lá trà được nén thành bánh có thể cất giữ hàng chục năm, và xưa kia các đoàn la thồ từng chở những bánh trà ấy vượt núi non đến Tây Tạng và triều đình.'),
  'puer/coffee': ('Thủ phủ cà phê Trung Quốc', 'Phần lớn cà phê Trung Quốc mọc lên trong các vườn arabica trên những sườn đồi mù sương của Phổ Nhĩ, nên thủ phủ của trà nay lại thoang thoảng mùi latte đầy bất ngờ. Các nông trại mở tour nếm thử giữa những chùm quả cà phê, và các barista trẻ đang quyết tâm đưa hạt cà phê quê nhà ra sân khấu thế giới.'),
  'puer/teahorse': ('Trà Mã Cổ Đạo', 'Trà Mã Cổ Đạo — con đường cổ nơi các đoàn la thồ chở bánh trà sang Tây Tạng và dắt ngựa về Trung Nguyên — khởi đầu từ Phổ Nhĩ rồi leo lên những con đèo mây phủ. Dấu tích các lối mòn lát đá và những trấn dịch trạm xưa vẫn lưu giữ ký ức về nghề buôn gian truân ấy.'),
  'puer/peafowl': ('Công xanh', 'Những cánh rừng nhiệt đới quanh Phổ Nhĩ là một trong các chốn nương náu cuối cùng của công lục, loài chim quý hiếm bậc nhất Trung Quốc. Các khu bảo tồn nơi đây không chỉ che chở loài chim lộng lẫy này mà cả voi rừng và vượn; thành phố tự hào về rừng của mình chẳng kém gì trà.'),
  'baoshan/volcano': ('Núi lửa Đằng Xung', 'Chín mươi bảy chóp núi lửa đã tắt xếp hàng trên bình nguyên Đằng Xung, khoác lên cảnh quan dáng vẻ của bề mặt Mặt Trăng. Du khách leo lên miệng núi lửa hoặc lượn trên các chóp núi bằng khinh khí cầu, và đá dung nham đen được xây hẳn vào tường nhà của thị trấn.'),
  'baoshan/rehai': ('Nhiệt Hải', 'Trong thung lũng \'Biển Nóng\' của Đằng Xung, mạch nước phun tỏa khói và các hồ nước sôi sùng sục, nổi tiếng nhất là \'Nồi Sôi Lớn\' khổng lồ. Du khách nhấm nháp trứng chín bằng hơi nước suối nóng, rồi ngâm mình trong bồn khoáng, tìm hơi ấm chữa lành của vùng đất núi lửa này.'),
  'baoshan/heshun': ('Trấn Hòa Thuận', 'Hòa Thuận, thị trấn đá của những thương nhân bao đời buôn bán sang Miến Điện và xa hơn nữa, chứng kiến những người con gửi cơ nghiệp về quê thành các dinh thự và trường học thanh nhã. Sở hữu một trong những thư viện làng cổ nhất Trung Quốc, thị trấn tỏa hơi thở bình yên với những ao sen và cầu đá.'),
  'baoshan/gaoligong': ('Dãy núi Cao Lê Cống', 'Trải dài dọc biên giới Myanmar, dãy núi Cao Lê Cống là kho báu của sự sống với những thung lũng bươm bướm, rừng ấm áp và hàng nghìn loài thực vật. Vươn từ thung lũng nhiệt đới lên các rặng núi tuyết, dãy núi che chở vô số loài quý hiếm, từ vượn đến những loài chim hiếm gặp.'),
  'deyang/sanxingdui': ('Di chỉ Tam Tinh Đôi', 'Những chiếc mặt nạ đồng khổng lồ với đôi mắt lồi, được khai quật từ các hố tế lễ phát hiện năm 1986, đã đưa nền văn minh Thục bí ẩn 3.000 năm tuổi ra ánh sáng. Với những cây trượng vàng và cây đồng thiêng, Tam Tinh Đôi được xem là một trong những bất ngờ lớn nhất của khảo cổ học Trung Quốc.'),
  'deyang/jiannanchun': ('Rượu Kiếm Nam Xuân', 'Kiếm Nam Xuân, chưng cất tại Miên Trúc, là loại bạch tửu lâu đời từng có tên trong danh sách mỹ tửu dâng lên triều đình nhà Đường. Với những hố lên men cổ vẫn dùng liên tục và hương thơm thoảng vị hoa, nó đứng trong hàng những cái tên danh giá nhất của truyền thống rượu Tứ Xuyên.'),
  'deyang/nianhua': ('Tranh Tết Miên Trúc', 'Tranh Tết khắc gỗ vẽ tay của Miên Trúc treo phúc lộc lên khung cửa: các vị thần hộ mệnh, những em bé bụ bẫm và biểu tượng sung túc. Được xếp vào hàng những dòng tranh Tết lớn của Trung Quốc, nghề này biến mỗi bản in thành một tác phẩm riêng biệt nhờ nét bút hoàn thiện sống động của các nghệ nhân.'),
  'deyang/turbine': ('Thủ phủ công nghiệp nặng', 'Một phần lớn các tuabin khổng lồ, máy phát điện và thiết bị nhà máy điện của cả nước được rèn đúc trong những xưởng máy mênh mông của Đức Dương. Được xem là thủ phủ của ngành cơ khí nặng, thành phố là một trong những bắp thịt thép thầm lặng chống đỡ hạ tầng năng lượng Trung Quốc.'),
  'mianyang/libai': ('Quê hương Lý Bạch', 'Lý Bạch, thi tiên bất tử, đã trải qua thời niên thiếu giữa núi non Giang Du, nơi những vần thơ dâng hiến cho ánh trăng và men rượu của ông lần đầu bén rễ. Khu tưởng niệm và bảo tàng mang tên ông mỗi năm quy tụ những người yêu thơ tìm về theo dấu chân bậc thầy huyền thoại của thi ca đời Đường.'),
  'mianyang/sciencecity': ('Thành phố Khoa học', 'Miên Dương, thành phố duy nhất mang danh hiệu chính thức \'Thành phố Khoa học và Công nghệ\' của Trung Quốc, xây dựng tương lai bằng các viện nghiên cứu và nhà máy điện tử. Là quê hương của tivi Changhong, đây là gương mặt khoác áo blouse, thông minh bậc nhất của Tứ Xuyên.'),
  'mianyang/qiang': ('Tháp đá người Khương', 'Ở các bản làng miền núi Bắc Xuyên, những tháp canh bằng đá của người Khương đã đứng vững qua hàng thế kỷ, được xây cất tài tình vừa để phòng thủ vừa làm biểu tượng thanh thế. Gìn giữ tín ngưỡng đá trắng và nghề thêu len, các làng Khương duy trì một nền văn hóa miền núi cổ xưa.'),
  'mianyang/mifen': ('Bún gạo Miên Dương', 'Những sợi bún gạo mảnh nghi ngút khói trong nước dùng gà, bò hay lòng đánh thức Miên Dương mỗi sớm mai. Sợi bún mỏng manh chín chỉ trong vài giây, và đám đông cúi đầu bên tô bún nơi quầy hàng chính là nghi thức buổi sáng chung thủy nhất của thành phố.'),
  'nanchong/langzhong': ('Cổ trấn Lãng Trung', 'Lãng Trung, một trong những cổ thành được quy hoạch theo phong thủy còn nguyên vẹn nhất, ngủ yên trong vòng ôm của khúc uốn sông Gia Lăng. Là quê hương của nhà thiên văn đời Hán Lạc Hạ Hoành, nơi đây được tôn vinh là cái nôi của phong tục Tết Nguyên đán Trung Hoa, và những con ngõ thoảng mùi giấm vẫn giữ nguyên nếp phố thời Minh–Thanh.'),
  'nanchong/silk': ('Thủ phủ tơ lụa', 'Với hơn hai nghìn năm trồng dâu dệt lụa, Nam Sung mang danh hiệu thủ phủ tơ lụa miền tây Trung Quốc. Từng cung cấp vải vóc cho Con đường Tơ lụa, thành phố ngày nay vẫn sống cùng các nhà máy ươm tơ và bảo tàng tơ lụa, những tấm lụa óng ánh của nó vẫn tỏa đi các thị trường khắp thế giới.'),
  'nanchong/zhangfei': ('Thịt bò Trương Phi', 'Trương Phi, người hùng thời Tam Quốc, từng trấn giữ Lãng Trung nhiều năm, và đền thờ ông vẫn đứng đó đến hôm nay. Món thịt bò khô tẩm gia vị mang tên ông — đen nhánh bên ngoài, đỏ hồng bên trong — là lời gợi nhắc dí dỏm đến hình tượng \'mặt đen\' nổi tiếng của vị hào kiệt.'),
  'nanchong/zhude': ('Quê hương Chu Đức', 'Nguyên soái Chu Đức, một trong những vị tướng sáng lập Quân Giải phóng Nhân dân, sinh ra trong một nông trại nghèo ở Nghi Lũng. Ngôi nhà quê mộc mạc và nhà tưởng niệm bên cạnh là điểm hành hương của lịch sử Trung Quốc hiện đại, nơi du khách cảm nhận sức mạnh của những khởi đầu khiêm nhường.'),
  'yibin/wuliangye': ('Rượu Ngũ Lương Dịch', 'Được chưng cất từ cao lương, gạo tẻ, gạo nếp, lúa mì và ngô, Ngũ Lương Dịch lấy tên từ \'năm loại ngũ cốc\' này và xếp vào hàng những thương hiệu bạch tửu quý giá nhất Trung Quốc. Khí hậu ẩm ướt của Nghi Tân cùng các hố lên men trăm năm tuổi ban cho loại rượu này hương thơm nhiều tầng đặc trưng.'),
  'yibin/firstcity': ('Thành phố đầu nguồn sông Dương Tử', 'Nơi sông Mân và sông Kim Sa hội ngộ, dòng sông mang tên Trường Giang — vì thế Nghi Tân được gọi là \'thành phố đầu tiên trên Trường Giang\'. Mũi đất nơi hai dòng nước khác màu hòa vào nhau, nay là công viên ven sông, chính là biểu tượng đáng tự hào nhất của thành phố.'),
  'yibin/bamboosea': ('Thục Nam Trúc Hải', 'Biển Trúc Thục Nam, phủ kín hơn một trăm ngọn đồi, dập dờn trong gió như một đại dương xanh vô tận. Những lối mòn rừng mát rượi, thác nước ẩn mình và nền ẩm thực xây trên măng trúc ôm trọn du khách, và các đoàn làm phim cứ trở lại mãi với vùng xanh bát ngát này.'),
  'yibin/ranmian': ('Mì đốt (Ranmian)', 'Được nhào gần như không nước và trộn trong dầu thơm, mì \'nhiên miến\' mang tên \'mì bốc cháy\' vì khô đến mức dầu trên sợi mì có thể bén lửa. Đậm đà vị ớt, hoa tiêu Tứ Xuyên và lạc rang, đây là ngôi sao đánh thức mọi giác quan của bữa sáng Nghi Tân.'),
  'luzhou/laojiao': ('Hầm rượu Lão Giao', 'Những hố lên men bằng bùn được dùng liên tục từ năm 1573 là trái tim của truyền thống bạch tửu \'nồng hương\' Lô Châu. Quần thể vi sinh sống trong các hố được truyền từ đời này sang đời khác, và các bậc thầy chưng cất tin rằng những hố cổ nhất ban cho rượu hương thơm sâu lắng nhất.'),
  'luzhou/port': ('Cảng sông Dương Tử', 'Được dựng lên nơi sông Đà Giang (Tuo) gặp Trường Giang, Lô Châu là cánh cổng đường thủy của Tứ Xuyên hướng ra biển. Suốt hàng thế kỷ, bến cảng nơi đây bốc xếp muối, rượu và ngũ cốc; ngày nay cảng container của thành phố vẫn nối các tỉnh nội địa với hạ lưu Trường Giang và thế giới.'),
  'luzhou/longan': ('Vườn nhãn', 'Long nhãn, thứ quả nhỏ ngọt như mật mang tên \'mắt rồng\', mọc trên những triền dốc ấm áp của các thung lũng sông ở Lô Châu. Thành phố sở hữu một số vườn nhãn lớn ở cực bắc Trung Quốc, và loại quả chín muộn này chất đầy các sạp chợ mỗi độ thu về.'),
  'luzhou/umbrella': ('Ô giấy dầu', 'Những chiếc ô giấy dầu thủ công của các nghệ nhân Phân Thủy, với nan tre và hoa văn vẽ tay, là nghề thủ công thanh nhã đã bốn thế kỷ tuổi. Mỗi chiếc ô trải qua hàng chục công đoạn và mở ra đón may mắn chẳng kém gì đón mưa — dáng tròn của nó tượng trưng cho sự viên mãn và hạnh phúc.'),
  'leshan/giantbuddha': ('Lạc Sơn Đại Phật', 'Được tạc vào vách đá, tượng Phật ngồi cao 71 mét đã điềm tĩnh dõi nhìn ngã ba cuồn cuộn của ba dòng sông suốt mười hai thế kỷ. Khởi công bởi nhà sư Hải Thông đời Đường để che chở thuyền bè qua lại, công trình vĩ đại này nay là di sản UNESCO — chỉ riêng các ngón chân tượng đã đủ chỗ cho hàng chục người đứng.'),
  'leshan/emei': ('Núi Nga Mi', 'Nga Mi, một trong bốn ngọn núi thiêng của Phật giáo, vẫy gọi khách hành hương và người leo núi bằng Kim Đỉnh rực rỡ trên biển mây. Những lối mòn men qua các tự viện cổ kính, và vào ngày may mắn, trên đỉnh núi hiện ra vầng cầu vồng tròn được gọi là \'Phật quang\'.'),
  'leshan/monkeys': ('Khỉ Nga Mi', 'Lũ khỉ macaque tinh nghịch sống dọc các lối mòn Nga Mi nổi tiếng vì dạn dĩ lục túi khách hành hương. Người dân địa phương gọi chúng là \'chủ nhà của núi\'; vắt vẻo trên lan can và tạo dáng chụp ảnh, đàn khỉ để lại cho du khách những kỷ niệm vui nhộn nhất — và cũng nghịch ngợm nhất — của chuyến leo núi.'),
  'leshan/qiaojiao': ('Canh bò Kiều Cước', '\'Kiều cước\' — món canh bò ninh nhiều giờ với thảo mộc và gia vị — lấy tên từ những thực khách xưa kia gác chân lên băng ghế cao trước quầy trong lúc húp canh. Là món kinh điển của đường phố Lạc Sơn suốt khoảng một thế kỷ, tô canh nghi ngút khói này biến cả lòng bò dân dã thành đại tiệc.'),
  'zigong/saltwell': ('Giếng muối sâu nghìn mét', 'Tự Cống đã sống nhờ những giếng muối suốt khoảng hai nghìn năm, và tài nghệ khoan giếng bằng dây cáp tre đạt đỉnh cao với giếng Shenhai — lỗ khoan đầu tiên trên trái đất vượt độ sâu nghìn mét. Những tháp khoan gỗ và bảo tàng muối vẫn kể câu chuyện về \'thủ phủ muối\' tài hoa này.'),
  'zigong/lantern': ('Lễ hội đèn lồng Tự Cống', 'Mỗi dịp năm mới, Tự Cống hóa thành xứ sở thần tiên với những vườn đèn lồng khổng lồ rực sáng. Rồng bay, cung điện và các nhân vật cổ tích vươn lên từ lụa và thép, và các nghệ nhân đèn lồng của thành phố nay còn dựng những lễ hội ánh sáng ấy ở các đô thị khắp thế giới.'),
  'zigong/dinosaur': ('Bảo tàng Khủng long', 'Hàng nghìn hóa thạch trồi lên từ các tầng địa chất kỷ Jura ở Dashanpu đưa Tự Cống thành thủ phủ khủng long của Trung Quốc. Bảo tàng dựng ngay trên khu khai quật trưng bày các tầng xương đúng nguyên trạng lúc tìm thấy, và những bộ xương sauropod sừng sững đưa du khách chìm sâu vào kỷ Jura.'),
  'zigong/rabbit': ('Thỏ lạnh', '\'Lengtu\' — thịt thỏ ăn nguội trong dầu ớt cùng hoa tiêu Tứ Xuyên và lạc rang — là một trong những món khai vị táo bạo nhất của Tứ Xuyên, và Tự Cống chính là quê hương của nó. Sinh ra từ những bữa cơm no đủ của thợ muối, ẩm thực thành phố vẫn giữ truyền thống hào phóng gia vị ấy đến tận hôm nay.'),
  'panzhihua/steel': ('Thủ phủ Vanadi-Titan', 'Nép mình trong thung lũng núi non của sông Kim Sa, Phan Chi Hoa là thành phố thép khổng lồ khai thác những mỏ vanadi–titan giàu nhất thế giới. Vươn lên từ con số không trong cuộc đại công nghiệp hóa thế kỷ XX, thành phố mang tên loài hoa đỏ rực như lửa của cây gạo bản địa.'),
  'panzhihua/fruitvalley': ('Thung lũng trái cây ngập nắng', 'Xoài, lựu và chuối của thung lũng Kim Sa khô nóng chín mọng trong vùng tiểu khí hậu chan hòa nắng này, thậm chí kéo dài đến tận mùa đông. Xoài chín muộn là niềm tự hào của thành phố, và những vườn cây trái mang đến cho đô thị thép một hương vị nhiệt đới đầy bất ngờ.'),
  'panzhihua/sunshine': ('Thành phố nắng mùa đông', 'Với khoảng 2.700 giờ nắng mỗi năm, Phan Chi Hoa là điểm dừng chân dưỡng sức cho những ai tìm kiếm mùa đông ôn hòa, tràn ánh sáng. Người về hưu trốn cái rét phương bắc đến đây trú đông, và thành phố tôn vinh nắng trời của mình bằng các trại thể thao và khu nghỉ dưỡng suối nước nóng.'),
  'panzhihua/jinsha': ('Sông Kim Sa', 'Kim Sa — \'dòng sông cát vàng\' — là thượng nguồn của Trường Giang, khoét những thung lũng sâu khi cuộn chảy qua trái tim Phan Chi Hoa. Các đập thủy điện dọc dòng sông cấp điện cho cả vùng, trong khi những cây cầu và lối dạo ven sông thổi sức sống vào đôi bờ.'),
  'dazhou/gas': ('Thủ phủ khí đốt', 'Bên dưới Đạt Châu là Phổ Quang, một trong những mỏ khí thiên nhiên lớn nhất Trung Quốc, đưa thành phố thành căn cứ năng lượng quốc gia. Các đường ống từ đây vươn tới những đô thị công nghiệp miền đông, và nền kinh tế khí đốt đã mở ra kỷ nguyên mới cho góc núi non này của Tứ Xuyên.'),
  'dazhou/ba': ('Di sản nước Ba', 'Đây từng là đất của các chiến binh Ba cổ đại, lừng danh với những thanh kiếm hình lá liễu, mà các món đồ đồng khắc hình hổ vẫn lên tiếng qua di chỉ Luojiaba. Nền văn hóa bí ẩn của tộc người chiến binh sống ven thung lũng sông này là một trong những tầng cổ xưa nhất của lịch sử Tứ Xuyên.'),
  'dazhou/dengying': ('Thịt bò Đăng Ảnh', 'Thịt bò \'đăng ảnh\', thái mỏng đến mức ánh đèn có thể xuyên qua, lấy tên từ trò rối bóng chiếu bên ngọn đèn thuở xưa. Những lát thịt giòn tan mỏng như giấy được phủ lớp gia vị vừa ngọt vừa cay, và món quà vặt thanh lịch này của Đạt Châu đã tô điểm bàn ăn hơn một thế kỷ.'),
  'dazhou/hanque': ('Khuyết đá thời Hán', 'Những tháp cổng \'khuyết\' bằng đá hai nghìn năm tuổi đứng giữa đồng ruộng Cừ Huyện là vẻ thanh nhã hiếm hoi còn sót lại của kiến trúc đời Hán. Xưa kia trấn giữ lối vào các lăng mộ, những tháp cổng chạm khắc này in hằn thế giới nhà Hán vào đá qua các linh thú thần thoại và cảnh sinh hoạt đời thường.'),
  'guangyuan/jianmen': ('Kiếm Môn Quan', 'Kiếm Môn Quan, nơi \'một người trấn giữ, vạn người khó qua\', là chiếc khóa của con đường Thục đạo cổ xưa, với những vách đá dựng đứng như lưỡi kiếm. Là yết hầu của các đạo quân từ thời Tam Quốc, con đèo gợi nhớ câu thơ Lý Bạch rằng đường vào đất Thục \'khó hơn lên trời xanh\'.'),
  'guangyuan/wuzetian': ('Quê hương Võ Tắc Thiên', 'Võ Tắc Thiên, nữ hoàng đế duy nhất trong lịch sử Trung Hoa, được tin là sinh ra tại Quảng Nguyên, và chùa Hoàng Trạch đã tưởng nhớ bà suốt nghìn năm. Thành phố tôn vinh vị nữ vương quyền uy bằng lễ hội phụ nữ thường niên, trong khi tượng bà ngồi trầm mặc trong ngôi chùa bên sông.'),
  'guangyuan/plankroad': ('Sạn đạo cổ', 'Những con đường ván gỗ đặt trên dầm đóng vào vách đá dựng đứng là tượng đài của lòng quả cảm, biến con đường Thục \'khó hơn lên trời\' thành lối đi được. Dấu tích sạn đạo cổ vẫn còn ở hẻm Minh Nguyệt, nơi du khách bước trên những tấm ván phục dựng và cảm nhận nhịp tim hồi hộp của các đoàn thương buôn thuở trước.'),
  'guangyuan/cypress': ('Hành lang bách Thúy Vân', 'Hàng vạn cây bách cổ thụ xếp dọc con đường cổ, biến hành lang Thúy Vân thành đường hầm xanh mướt. Truyền thuyết cho rằng một phần rừng cây được trồng theo lệnh của Trương Phi, người hùng thời Tam Quốc, và con đường rợp bóng này thuộc hàng những hàng cây ven đường cổ nhất còn tồn tại trên thế giới.'),
  'yaan/panda': ('Cái nôi của gấu trúc', 'Gấu trúc lớn lần đầu được khoa học mô tả tại Bảo Hưng năm 1869, khi bản báo cáo của nhà tự nhiên học người Pháp Armand David giới thiệu loài vật đáng yêu này với thế giới. Trung tâm gấu trúc Bích Phong Hiệp tiếp nối di sản ấy, và những cánh rừng trúc mù sương của Nhã An vẫn là chiếc nôi của gấu trúc.'),
  'yaan/rain': ('Thành phố mưa', '\'Mưa Nhã\' gột rửa mái nhà gần như mỗi đêm, và mỗi sớm mai thành phố lại ánh lên nghìn sắc xanh vừa được tắm gội. Người dân đếm ba nét duyên — mưa Nhã, cá Nhã và thiếu nữ Nhã — bộ ba gói trọn tâm hồn dịu dàng, trù phú của thành phố mưa.'),
  'yaan/mengding': ('Trà núi Mông Đỉnh', 'Tương truyền cây trà lần đầu được bàn tay con người vun trồng trên núi Mông Đỉnh khoảng hai nghìn năm trước, đưa ngọn núi thành cái nôi của văn hóa trà. Lá trà từ những vườn cổ trên đỉnh núi từng được tiến cống các hoàng đế suốt bao thế kỷ, và trà lễ vẫn được cử hành trên những sườn núi mù sương đến hôm nay.'),
  'yaan/yayu': ('Cá Nhã', 'Cá Nhã huyền thoại của những dòng suối tuyết tan được dọn lên bàn trong nồi lẩu sôi sục và được xếp vào ba nét duyên của thành phố. Nổi tiếng với thớ thịt trắng săn chắc, loài cá này giấu trong đầu một mẩu xương nhỏ hình thanh kiếm, quanh \'thanh kiếm\' ấy các truyền thuyết địa phương đã dệt nên bao câu chuyện.'),
  'xianyang/qincapital': ('Kinh đô nhà Tần', 'Nơi đây từng là kinh đô của nhà Tần, triều đại đầu tiên thống nhất Trung Hoa; Tần Thủy Hoàng đã đi con đường tới đế nghiệp từ Hàm Dương. Các cung điện xưa nay là những di chỉ khảo cổ, nơi đồ đồng và nền móng cung thất thì thầm về một quyền lực hơn hai nghìn năm tuổi.'),
  'xianyang/qianling': ('Càn Lăng', 'Càn Lăng, lăng mộ chung tạc vào núi của Võ Tắc Thiên và chồng bà là Đường Cao Tông, là một trong số hiếm hoi các lăng tẩm đời Đường đến với chúng ta mà chưa từng bị đào trộm. Tượng thần hộ vệ bằng đá và tượng sứ thần ngoại quốc xếp dọc thần đạo, trong khi tấm bia không chữ nổi tiếng do Võ Tắc Thiên dựng lên phó mặc lời phán xét về bà cho hậu thế.'),
  'xianyang/zhengguo': ('Kênh Trịnh Quốc', 'Được đào vào cuối thời Chiến Quốc, kênh Trịnh Quốc tưới tắm bình nguyên Quan Trung, biến nơi đây thành vựa lúa của nước Tần và đặt nền móng kinh tế cho công cuộc thống nhất. Nuôi dưỡng cả vùng suốt hơn hai thiên niên kỷ, công trình này là một kiệt tác thiên tài của kỹ thuật cổ đại.'),
  'xianyang/guokui': ('Bánh quách khôi', '\'Quả khôi\' — chiếc bánh nướng giòn to và dày như nắp nồi — được xếp vào \'mười điều kỳ lạ\' nổi tiếng của Thiểm Tây. Nướng chậm rãi trên lửa củi, bánh giữ được nhiều ngày, và tương truyền nguồn gốc của nó bắt nguồn từ những cuộc chinh chiến xa xưa, khi binh lính được cho là đã nướng bánh trong mũ trận của mình.'),
  'baoji/bronze': ('Thủ phủ đồ đồng', 'Từ lòng đất Bảo Kê, vùng đất trung tâm của nhà Chu, hàng nghìn chiếc đỉnh vạc đồng khắc minh văn đã lộ diện — trong đó có chiếc tôn He zun mang dòng chữ cổ nhất được biết đến của tên gọi \'Trung Quốc\' (Zhongguo). Bảo tàng đồ đồng của thành phố trưng bày tài nghệ ba nghìn năm tuổi ấy trong một trong những bộ sưu tập phong phú nhất thế giới.'),
  'baoji/famen': ('Chùa Pháp Môn', 'Chùa Pháp Môn, nơi gìn giữ xá lợi xương ngón tay Đức Phật, từng là kho báu linh thiêng của các hoàng đế nhà Đường. Khi mật thất dưới chân tháp được mở ra năm 1987, cả một kho tàng đời Đường lộng lẫy bằng vàng, bạc và tơ lụa hiện ra dưới ánh sáng; ngày nay một quần thể đồ sộ tôn thờ xá lợi ấy.'),
  'baoji/taibai': ('Núi Thái Bạch', 'Thái Bạch, nóc nhà 3.771 mét của dãy Tần Lĩnh, nuôi dưỡng huyền thoại bằng lớp tuyết còn vương đến tận mùa hè — \'tuyết tháng Sáu trên Thái Bạch\' từng là một trong những kỳ quan lừng danh của đất Quan Trung xưa. Những lối mòn leo lên các hồ băng hà đưa bạn đi trên chính ranh giới tự nhiên giữa miền bắc và miền nam Trung Quốc.'),
  'baoji/saozi': ('Mì sao tử', 'Mì \'tao tử\' Kỳ Sơn trong nước sốt thịt chua cay được xem là hương vị sống của ẩm thực thời nhà Chu, với sợi mì mảnh, dài và dai giòn. Giấm và ớt phi quyện điệu cùng cà rốt, trứng và mộc nhĩ, và tục lệ mời khách hết bát này đến bát khác trong đám cưới đã có từ hàng thế kỷ.'),
};
